{
  "name": "Smart Inventory Pro",
  "description": "A high-efficiency local inventory counting system optimized for USB barcode scanners, featuring real-time tracking, audio feedback, and CSV/Excel data handling.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface InventoryItem {
  barcode: string;      // 條碼編號
  productCode: string;  // 產品代號
  name: string;         // 品名
  bookQty: number;      // 期末數量 (ERP)
  actualQty: number;    // 盤點數量
  diff: number;         // 差異數
}

export interface ScanResult {
  success: boolean;
  message: string;
  item?: InventoryItem;
}

class AudioService {
  private audioCtx: AudioContext | null = null;

  private init() {
    if (!this.audioCtx) {
      this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
  }

  playSuccess() {
    this.init();
    if (!this.audioCtx) return;
    const osc = this.audioCtx.createOscillator();
    const gain = this.audioCtx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(880, this.audioCtx.currentTime); // A5
    gain.gain.setValueAtTime(0.1, this.audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.audioCtx.currentTime + 0.1);

    osc.connect(gain);
    gain.connect(this.audioCtx.destination);

    osc.start();
    osc.stop(this.audioCtx.currentTime + 0.1);
  }

  playError() {
    this.init();
    if (!this.audioCtx) return;
    const osc = this.audioCtx.createOscillator();
    const gain = this.audioCtx.createGain();

    osc.type = 'square';
    osc.frequency.setValueAtTime(110, this.audioCtx.currentTime); // A2
    gain.gain.setValueAtTime(0.1, this.audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.01, this.audioCtx.currentTime + 0.3);

    osc.connect(gain);
    gain.connect(this.audioCtx.destination);

    osc.start();
    osc.stop(this.audioCtx.currentTime + 0.3);
  }
}

export const audioService = new AudioService();

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileUp, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  RefreshCw,
  Package,
  History
} from 'lucide-react';
import { InventoryItem, ScanResult } from './types';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-focus logic
  const focusInput = useCallback(() => {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }, []);

  useEffect(() => {
    focusInput();
    const handleGlobalClick = () => focusInput();
    window.addEventListener('click', handleGlobalClick);
    return () => window.removeEventListener('click', handleGlobalClick);
  }, [focusInput]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsLoading(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        // Basic CSV Parsing (handling potential UTF-8/Big5 issues would be handled by browser encoding detection)
        const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
        if (lines.length < 1) throw new Error("File is empty");

        const headers = lines[0].split(',').map(h => h.trim());
        const mappedData: InventoryItem[] = lines.slice(1).map(line => {
          const values = line.split(',').map(v => v.trim());
          const item: any = {};
          headers.forEach((h, i) => {
            if (h === '條碼編號') item.barcode = values[i];
            if (h === '產品代號') item.productCode = values[i];
            if (h === '品名') item.name = values[i];
            if (h === '期末數量') item.bookQty = parseFloat(values[i]) || 0;
          });
          return {
            ...item,
            actualQty: 0,
            diff: -(item.bookQty || 0)
          };
        });

        setData(mappedData);
        setError(null);
        audioService.playSuccess();
      } catch (err) {
        setError("CSV 格式錯誤，請檢查欄位是否包含：條碼編號, 產品代號, 品名, 期末數量");
        audioService.playError();
      } finally {
        setIsLoading(false);
      }
    };
    reader.readAsText(file);
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code) return;

    const index = data.findIndex(item => item.barcode === code || item.productCode === code);

    if (index !== -1) {
      const updatedData = [...data];
      const item = { ...updatedData[index] };
      item.actualQty += 1;
      item.diff = item.actualQty - item.bookQty;
      updatedData[index] = item;

      setData(updatedData);
      setLastScanned(item);
      setError(null);
      audioService.playSuccess();
    } else {
      setLastScanned(null);
      setError(`找不到條碼或代號: ${code}`);
      audioService.playError();
    }

    setInputValue('');
  };

  const handleExport = () => {
    if (data.length === 0) return;

    const headers = ['條碼編號', '產品代號', '品名', '期末數量(ERP)', '盤點數量', '差異數'];
    const csvContent = [
      headers.join(','),
      ...data.map(item => [
        item.barcode,
        item.productCode,
        item.name,
        item.bookQty,
        item.actualQty,
        item.diff
      ].join(','))
    ].join('\n');

    const blob = new Blob(["\uFEFF" + csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `inventory_result_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-8 space-y-6 max-w-5xl mx-auto">
      {/* Header Section */}
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-4 mb-4">
        <div className="flex items-center space-x-3">
          <div className="bg-blue-600 p-2 rounded-lg shadow-lg">
            <Package className="text-white w-8 h-8" />
          </div>
          <h1 className="text-3xl font-extrabold text-slate-800 tracking-tight">Smart Inventory Pro</h1>
        </div>

        <div className="flex items-center space-x-2">
          {data.length === 0 ? (
            <label className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-full cursor-pointer transition-all shadow-md active:scale-95 font-semibold">
              <FileUp size={20} />
              <span>匯入 CSV 庫存檔</span>
              <input type="file" accept=".csv" onChange={handleFileUpload} className="hidden" />
            </label>
          ) : (
            <div className="flex space-x-2">
              <button 
                onClick={() => { if(confirm('確定要清除所有盤點數據並重新匯入？')) setData([]); }}
                className="flex items-center space-x-2 bg-slate-200 hover:bg-slate-300 text-slate-700 px-5 py-2.5 rounded-full transition-all font-semibold"
              >
                <RefreshCw size={18} />
                <span>重新開始</span>
              </button>
              <button 
                onClick={handleExport}
                className="flex items-center space-x-2 bg-emerald-600 hover:bg-emerald-700 text-white px-5 py-2.5 rounded-full transition-all shadow-md active:scale-95 font-semibold"
              >
                <FileDown size={18} />
                <span>匯出盤點結果</span>
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Main Scanner Section */}
      <main className="w-full space-y-6">
        {/* Scanning Box */}
        <div className={`bg-white rounded-3xl p-6 shadow-xl border-2 transition-all duration-300 ${error ? 'border-red-400' : 'border-blue-400'}`}>
          <form onSubmit={handleScan} className="relative">
            <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">
              <Search size={32} />
            </div>
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder="請掃描條碼或輸入產品代號..."
              className="w-full pl-16 pr-4 py-6 text-3xl font-bold bg-slate-50 border-none rounded-2xl scan-focus outline-none placeholder:text-slate-300 transition-all"
              autoComplete="off"
            />
            <div className="absolute right-4 top-1/2 -translate-y-1/2 bg-blue-100 p-2 rounded-xl">
              <Scan size={32} className="text-blue-600 animate-pulse" />
            </div>
          </form>
          {error && (
            <div className="mt-4 flex items-center text-red-600 space-x-2 animate-bounce">
              <AlertCircle size={20} />
              <span className="font-bold text-xl">{error}</span>
            </div>
          )}
        </div>

        {/* Display Card */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white rounded-3xl p-8 shadow-xl min-h-[300px] flex flex-col justify-center border border-slate-100">
             {lastScanned ? (
               <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                 <div className="flex items-center space-x-2 text-blue-600 font-bold uppercase tracking-wider text-sm">
                   <CheckCircle2 size={16} />
                   <span>掃描成功</span>
                 </div>
                 <h2 className="text-4xl font-black text-slate-800 leading-tight">
                   {lastScanned.name}
                 </h2>
                 <div className="flex gap-4 text-slate-500 font-mono text-lg">
                   <span className="bg-slate-100 px-3 py-1 rounded-md">SN: {lastScanned.barcode}</span>
                   <span className="bg-slate-100 px-3 py-1 rounded-md">ID: {lastScanned.productCode}</span>
                 </div>
               </div>
             ) : (
               <div className="text-center space-y-4 text-slate-300">
                 <Scan size={64} className="mx-auto opacity-20" />
                 <p className="text-xl font-medium">等待掃描中...</p>
               </div>
             )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-white rounded-3xl p-6 shadow-lg border border-slate-100 flex flex-col justify-center items-center text-center">
              <span className="text-slate-500 font-bold mb-1">盤點數量</span>
              <span className="text-6xl font-black text-blue-600">{lastScanned ? lastScanned.actualQty : '-'}</span>
            </div>
            <div className="bg-white rounded-3xl p-6 shadow-lg border border-slate-100 flex flex-col justify-center items-center text-center">
              <span className="text-slate-500 font-bold mb-1">ERP 帳面</span>
              <span className="text-6xl font-black text-slate-400">{lastScanned ? lastScanned.bookQty : '-'}</span>
            </div>
            <div className={`col-span-2 rounded-3xl p-6 shadow-xl flex flex-col justify-center items-center text-center transition-colors duration-300 ${
              !lastScanned ? 'bg-white' : lastScanned.diff === 0 ? 'bg-emerald-50 text-emerald-600 border-2 border-emerald-400' : 'bg-red-50 text-red-600 border-2 border-red-400'
            }`}>
              <span className="font-bold mb-1 opacity-80 uppercase tracking-widest">差異狀況 (Diff)</span>
              <span className="text-7xl font-black">
                {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '-'}
              </span>
              {lastScanned && lastScanned.diff === 0 && <span className="mt-2 font-bold text-lg">庫存完全符合</span>}
              {lastScanned && lastScanned.diff !== 0 && <span className="mt-2 font-bold text-lg">庫存不一致</span>}
            </div>
          </div>
        </div>
      </main>

      {/* Summary Footer */}
      <footer className="w-full bg-slate-800 text-white rounded-3xl p-6 shadow-2xl">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 items-center">
          <div className="flex flex-col">
            <span className="text-slate-400 text-xs font-bold uppercase mb-1">總項目數</span>
            <span className="text-2xl font-black">{data.length}</span>
          </div>
          <div className="flex flex-col">
            <span className="text-slate-400 text-xs font-bold uppercase mb-1">已盤點項目</span>
            <span className="text-2xl font-black text-emerald-400">
              {data.filter(i => i.actualQty > 0).length}
            </span>
          </div>
          <div className="flex flex-col">
            <span className="text-slate-400 text-xs font-bold uppercase mb-1">異常項目</span>
            <span className="text-2xl font-black text-red-400">
              {data.filter(i => i.diff !== 0 && i.actualQty > 0).length}
            </span>
          </div>
          <div className="flex flex-col items-end">
             <div className="flex items-center space-x-2 text-slate-400 text-sm font-semibold">
               <History size={16} />
               <span>掃描狀態：運作中</span>
             </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import os
import pandas as pd
from flask import Flask, render_template_string, request, jsonify, send_file
import io

app = Flask(__name__)

# Global variable to store inventory data
# In a real production environment, you'd use a database. 
# For a portable script, we'll keep it in memory.
inventory_df = None
CSV_FILENAME = 'inventory.csv'

def load_data():
    global inventory_df
    try:
        # Try different encodings
        for encoding in ['utf-8', 'cp950', 'gbk']:
            try:
                df = pd.read_csv(CSV_FILENAME, encoding=encoding)
                # Clean column names
                df.columns = df.columns.str.strip()
                # Clean string values in key columns
                for col in ['條碼編號', '產品代號', '品名']:
                    if col in df.columns:
                        df[col] = df[col].astype(str).str.strip()

                # Initialize Inventory Count if not exists
                if '盤點數量' not in df.columns:
                    df['盤點數量'] = 0

                # Ensure book quantity is numeric
                df['期末數量'] = pd.to_numeric(df['期末數量'], errors='coerce').fillna(0)

                inventory_df = df
                print(f"Loaded {len(df)} items with {encoding} encoding.")
                return True
            except (UnicodeDecodeError, pd.errors.ParserError):
                continue
        return False
    except Exception as e:
        print(f"Error loading CSV: {e}")
        return False

@app.route('/')
def index():
    if inventory_df is None:
        if not load_data():
            return "<h1>找不到 inventory.csv 或格式不正確。</h1><p>請確保檔案存在且包含：條碼編號, 產品代號, 品名, 期末數量</p>"

    html = """
    <!DOCTYPE html>
    <html lang="zh-TW">
    <head>
        <meta charset="UTF-8">
        <title>極簡盤點系統</title>
        <script src="https://cdn.tailwindcss.com"></script>
        <style>
            body { background-color: #f1f5f9; font-family: sans-serif; }
            .card { background: white; border-radius: 1rem; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.1); }
            input:focus { outline: none; box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.5); }
        </style>
    </head>
    <body class="p-8">
        <div class="max-w-4xl mx-auto space-y-8">
            <div class="flex justify-between items-center">
                <h1 class="text-3xl font-bold text-slate-800">📦 單機盤點系統</h1>
                <a href="/export" class="bg-emerald-600 hover:bg-emerald-700 text-white px-6 py-2 rounded-full font-bold transition shadow-lg">匯出 Excel</a>
            </div>

            <div class="card p-6 border-4 border-blue-500">
                <input type="text" id="scanner" placeholder="請掃描條碼..." 
                    class="w-full text-5xl p-6 font-bold bg-slate-50 rounded-lg text-center" autocomplete="off">
                <p id="msg" class="mt-4 text-center text-xl font-bold min-h-[1.5rem]"></p>
            </div>

            <div id="result-card" class="card p-10 hidden text-center space-y-6">
                <h2 id="res-name" class="text-6xl font-black text-slate-800"></h2>
                <div class="grid grid-cols-3 gap-8 pt-6">
                    <div>
                        <p class="text-slate-500 font-bold uppercase tracking-widest">目前盤點數</p>
                        <p id="res-actual" class="text-8xl font-black text-blue-600">-</p>
                    </div>
                    <div>
                        <p class="text-slate-500 font-bold uppercase tracking-widest">ERP 帳面</p>
                        <p id="res-book" class="text-8xl font-black text-slate-300">-</p>
                    </div>
                    <div>
                        <p class="text-slate-500 font-bold uppercase tracking-widest">差異數</p>
                        <p id="res-diff" class="text-8xl font-black">-</p>
                    </div>
                </div>
            </div>
        </div>

        <script>
            const scanner = document.getElementById('scanner');
            const msg = document.getElementById('msg');
            const resultCard = document.getElementById('result-card');

            const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

            function playSound(freq, duration, type='sine') {
                const osc = audioCtx.createOscillator();
                const gain = audioCtx.createGain();
                osc.type = type;
                osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
                gain.gain.setValueAtTime(0.1, audioCtx.currentTime);
                gain.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + duration);
                osc.connect(gain);
                gain.connect(audioCtx.destination);
                osc.start();
                osc.stop(audioCtx.currentTime + duration);
            }

            scanner.focus();
            window.addEventListener('click', () => scanner.focus());
            scanner.addEventListener('blur', () => setTimeout(() => scanner.focus(), 10));

            scanner.addEventListener('keypress', async (e) => {
                if (e.key === 'Enter') {
                    const code = scanner.value.trim();
                    scanner.value = '';
                    if (!code) return;

                    try {
                        const res = await fetch('/scan', {
                            method: 'POST',
                            headers: {'Content-Type': 'application/json'},
                            body: JSON.stringify({code})
                        });
                        const data = await res.json();

                        if (data.success) {
                            msg.innerText = "✅ 掃描成功";
                            msg.className = "mt-4 text-center text-xl font-bold text-emerald-600";
                            playSound(880, 0.1);

                            resultCard.classList.remove('hidden');
                            document.getElementById('res-name').innerText = data.item.品名;
                            document.getElementById('res-actual').innerText = data.item.盤點數量;
                            document.getElementById('res-book').innerText = data.item.期末數量;

                            const diff = data.item.盤點數量 - data.item.期末數量;
                            const diffEl = document.getElementById('res-diff');
                            diffEl.innerText = diff > 0 ? '+' + diff : diff;
                            diffEl.className = diff === 0 ? "text-8xl font-black text-emerald-500" : "text-8xl font-black text-red-500";
                        } else {
                            msg.innerText = "❌ " + data.message;
                            msg.className = "mt-4 text-center text-xl font-bold text-red-600 animate-pulse";
                            playSound(110, 0.3, 'square');
                            resultCard.classList.add('hidden');
                        }
                    } catch (err) {
                        console.error(err);
                    }
                }
            });
        </script>
    </body>
    </html>
    """
    return render_template_string(html)

@app.route('/scan', methods=['POST'])
def scan():
    global inventory_df
    code = request.json.get('code', '').strip()

    # Priority search: Barcode -> Product Code
    mask = (inventory_df['條碼編號'] == code) | (inventory_df['產品代號'] == code)
    if not mask.any():
        return jsonify(success=False, message=f"找不到條碼或代號: {code}")

    idx = inventory_df[mask].index[0]
    inventory_df.at[idx, '盤點數量'] += 1

    item = inventory_df.iloc[idx].to_dict()
    return jsonify(success=True, item=item)

@app.route('/export')
def export():
    global inventory_df
    if inventory_df is None: return "無資料"

    # Calculate diff for export
    export_df = inventory_df.copy()
    export_df['差異數'] = export_df['盤點數量'] - export_df['期末數量']

    output = io.BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        export_df.to_excel(writer, index=False, sheet_name='盤點結果')
    output.seek(0)

    return send_file(output, 
                     download_name=f"inventory_report.xlsx", 
                     as_attachment=True, 
                     mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet')

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)

{
