              <FileUp size={24} />
              <span>匯入庫存 CSV</span>
              <input type="file" accept=".csv" onChange={handleFileUpload} className="hidden" />
            </label>
          ) : (
            <div className="flex gap-3">
              <button 
                onClick={clearAll}
                className="flex items-center space-x-2 bg-slate-100 hover:bg-red-50 hover:text-red-600 text-slate-600 px-6 py-3.5 rounded-2xl transition-all font-bold border border-slate-200"
              >
                <Trash2 size={20} />
                <span>清空重置</span>
              </button>
              <button 
                onClick={handleExport}
                className="flex items-center space-x-2 bg-emerald-600 hover:bg-emerald-700 text-white px-8 py-3.5 rounded-2xl transition-all shadow-lg shadow-emerald-100 active:scale-95 font-bold text-lg"
              >
                <FileDown size={24} />
                <span>匯出結果</span>
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Main Scanner Section */}
      <main className="w-full space-y-8">
        {/* Scanning Box */}
        <div className={`bg-white rounded-[2rem] p-8 shadow-2xl border-4 transition-all duration-300 ${
          isSuccess ? 'border-emerald-400 scale-[1.01]' : error ? 'border-red-400 shake' : 'border-blue-500 shadow-blue-50'
        }`}>
          <form onSubmit={handleScan} className="relative">
            <div className={`absolute left-6 top-1/2 -translate-y-1/2 transition-colors ${error ? 'text-red-400' : 'text-blue-500'}`}>
              <Search size={40} strokeWidth={3} />
            </div>
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描條碼或輸入編號..." : "請先匯入 CSV 庫存檔"}
              disabled={data.length === 0}
              className="w-full pl-20 pr-8 py-8 text-4xl font-black bg-slate-50 border-none rounded-2xl scan-focus outline-none placeholder:text-slate-300 transition-all text-slate-800"
              autoComplete="off"
            />
            <div className="absolute right-6 top-1/2 -translate-y-1/2 bg-white/80 backdrop-blur p-3 rounded-2xl border border-slate-200">
              <Scan size={40} className={`text-blue-600 ${data.length > 0 ? 'animate-pulse' : 'opacity-20'}`} />
            </div>
          </form>
          {error && (
            <div className="mt-6 flex items-center justify-center text-red-600 space-x-3 bg-red-50 p-4 rounded-xl animate-in slide-in-from-top-2">
              <AlertCircle size={28} strokeWidth={3} />
              <span className="font-black text-2xl">{error}</span>
            </div>
          )}
        </div>

        {/* Display Card */}
        <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
          {/* Product Info Card */}
          <div className="lg:col-span-3 bg-white rounded-[2.5rem] p-10 shadow-xl min-h-[400px] flex flex-col justify-center border border-slate-100 relative overflow-hidden">
             <div className="absolute top-0 right-0 p-8 opacity-5">
                <Package size={200} />
             </div>

             {lastScanned ? (
               <div className="space-y-6 animate-in fade-in slide-in-from-bottom-8 duration-500 relative z-10">
                 <div className="flex items-center space-x-3 bg-emerald-50 text-emerald-600 px-4 py-2 rounded-full w-fit font-bold text-lg">
                   <CheckCircle2 size={24} />
                   <span>掃描比對成功</span>
                 </div>
                 <h2 className="text-7xl font-black text-slate-800 leading-tight">
                   {lastScanned.name}
                 </h2>
                 <div className="flex gap-6 text-slate-400 font-mono text-2xl font-bold">
