                   <div className="bg-slate-50 px-5 py-2 rounded-2xl border border-slate-100">代號: {lastScanned.productCode}</div>
                 </div>
               </div>
             ) : (
               <div className="text-center space-y-6 text-slate-300 py-12">
                 <div className="bg-slate-50 w-32 h-32 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Scan size={64} className="opacity-20" />
                 </div>
                 <p className="text-3xl font-black italic">READY FOR SCANNING</p>
               </div>
             )}
          </div>

          {/* Qty Stats Cards */}
          <div className="lg:col-span-2 grid grid-cols-2 gap-6">
            <div className="bg-white rounded-[2rem] p-8 shadow-lg border border-slate-100 flex flex-col justify-center items-center text-center">
