                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Summary Footer */}
      <footer className="w-full bg-slate-900 text-white rounded-[2rem] p-8 shadow-2xl mt-auto">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 items-center">
