            <div className="text-3xl font-black text-emerald-400">
              {data.filter(i => i.actualQty > 0).length} / {data.length}
            </div>
          </div>
          <div className="space-y-1">
            <span className="text-red-500 text-xs font-black uppercase tracking-widest">異常項目</span>
            <div className="text-3xl font-black text-red-400">
              {data.filter(i => i.diff !== 0 && i.actualQty > 0).length}
            </div>
          </div>
          <div className="flex flex-col items-end">
             <div className="bg-slate-800 px-6 py-3 rounded-2xl flex items-center space-x-3 border border-slate-700">
               <div className="w-3 h-3 bg-emerald-500 rounded-full animate-ping"></div>
               <span className="text-slate-300 font-black text-sm uppercase">Scanner Active</span>
             </div>
          </div>
        </div>
      </footer>

      <style>{`
        .shake { animation: shake 0.4s cubic-bezier(.36,.07,.19,.97) both; }
