          // 正規表達式處理 CSV 分隔，支援包含逗號的引號欄位
          const values = line.split(/,(?=(?:(?:[^"]*"){2})*[^"]*$)/).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => {
            if (h === '條碼編號') item.barcode = values[i] || '';
            if (h === '產品代號') item.productCode = values[i] || '';
