              {lastScanned && (
                <div className="mt-8 px-10 py-4 bg-white/20 rounded-3xl font-black text-3xl backdrop-blur-md border border-white/20">
                  {lastScanned.diff === 0 ? "數據完全符合" : "庫存不符警示"}
                </div>
