import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileUp, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  RefreshCw,
  Package,
  History,
  Trash2,
  Building2,
  FileSpreadsheet,
  Keyboard
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // 自動聚焦：確保掃描器永遠有效
  const focusInput = useCallback(() => {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }, []);

  useEffect(() => {
    focusInput();
    const handleGlobalClick = () => focusInput();
    window.addEventListener('click', handleGlobalClick);
    return () => window.removeEventListener('click', handleGlobalClick);
  }, [focusInput]);

  // 解析大豐 ERP Excel 專用邏輯
  const processRawData = (jsonData: any[]) => {
    if (jsonData.length === 0) throw new Error("檔案內容為空，請檢查 Excel 資料。");

    // 定義大豐 ERP 的標準欄位名稱 (根據截圖)
    const COL_BARCODE = '條碼編號';
    const COL_PROD_CODE = '產品代號';
    const COL_NAME = '品名';
    const COL_QTY = '期末數量';

    const firstRow = jsonData[0];
    const headers = Object.keys(firstRow);

    // 檢查核心必填欄位 (至少要有代號和品名)
    if (!headers.includes(COL_PROD_CODE) || !headers.includes(COL_NAME)) {
      throw new Error(`Excel 格式不符！必須包含「${COL_PROD_CODE}」與「${COL_NAME}」欄位。`);
    }

    return jsonData.map((row, idx) => {
      const barcode = String(row[COL_BARCODE] || '').trim();
      const productCode = String(row[COL_PROD_CODE] || '').trim();
      const name = String(row[COL_NAME] || '').trim();
      const bookQty = parseFloat(row[COL_QTY]) || 0;

      return {
        barcode,
        productCode,
        name,
        bookQty,
        actualQty: 0,
        diff: -bookQty
      };
    });
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    const isExcel = file.name.endsWith('.xlsx') || file.name.endsWith('.xls');

    reader.onload = (event) => {
      try {
        let mappedData: InventoryItem[] = [];

        if (isExcel) {
          const buffer = new Uint8Array(event.target?.result as ArrayBuffer);
          const workbook = XLSX.read(buffer, { type: 'array' });
          const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
          const jsonData = XLSX.utils.sheet_to_json(firstSheet);
          mappedData = processRawData(jsonData);
