              <span className="text-[7.5rem] font-black text-blue-600 leading-none">
                {lastScanned ? lastScanned.actualQty : '-'}
              </span>
            </div>
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-slate-200 flex flex-col justify-center items-center text-center">
              <span className="text-slate-400 font-black mb-2 uppercase tracking-widest text-lg">ERP 帳面</span>
              <span className="text-[7.5rem] font-black text-slate-300 leading-none">
                {lastScanned ? lastScanned.bookQty : '-'}
              </span>
            </div>
            <div className={`col-span-2 rounded-[3rem] p-12 shadow-2xl flex flex-col justify-center items-center text-center transition-all duration-500 ${
              !lastScanned 
                ? 'bg-slate-100 text-slate-400' 
                : lastScanned.diff === 0 
                  ? 'bg-emerald-600 text-white scale-[1.02]' 
                  : 'bg-red-600 text-white'
            }`}>
              <span className="font-black mb-4 opacity-80 uppercase tracking-[0.2em] text-xl">庫存差異</span>
              <span className="text-[10rem] font-black leading-none tracking-tighter">
                {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
              </span>
              {lastScanned && (
                <div className="mt-8 px-10 py-4 bg-white/20 rounded-3xl font-black text-3xl backdrop-blur-md border border-white/20">
                  {lastScanned.diff === 0 ? "與 ERP 帳面符合" : "庫存差異警示"}
