              )}
            </div>
          </div>
        </div>
      </main>

      {/* Summary Footer */}
      <footer className="w-full bg-slate-900 text-white rounded-[3rem] p-10 shadow-2xl">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-12 items-center">
