        if (isExcel) {
          const buffer = new Uint8Array(event.target?.result as ArrayBuffer);
          const workbook = XLSX.read(buffer, { type: 'array' });
          const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
          const jsonData = XLSX.utils.sheet_to_json(firstSheet);
          mappedData = processRawData(jsonData);
        } else {
          const text = event.target?.result as string;
          const workbook = XLSX.read(text, { type: 'string' });
          const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
          mappedData = processRawData(jsonData);
        }

        setData(mappedData);
        setError(null);
        setLastScanned(null);
        audioService.playSuccess();
        alert(`系統提示：成功讀取 ${mappedData.length} 筆資料。`);
      } catch (err: any) {
        setError(err.message || "檔案讀取失敗");
        audioService.playError();
      }
    };

    if (isExcel) {
      reader.readAsArrayBuffer(file);
    } else {
      reader.readAsText(file);
    }
    e.target.value = ''; 
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code) return;

    if (data.length === 0) {
      setError("請先上傳 ERP 庫存清單");
      audioService.playError();
      setInputValue('');
      return;
    }

    const index = data.findIndex(item => 
      (item.barcode && item.barcode === code) || 
      (item.productCode && item.productCode === code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      const item = { ...updatedData[index] };
      item.actualQty += 1;
      item.diff = item.actualQty - item.bookQty;
      updatedData[index] = item;

      setData(updatedData);
      setLastScanned(item);
      setError(null);
      setIsSuccess(true);
      audioService.playSuccess();

      setTimeout(() => setIsSuccess(false), 400);
    } else {
      setLastScanned(null);
      setError(`核對失敗：找不到條碼或代號 "${code}"`);
      audioService.playError();
    }

    setInputValue('');
  };

  const handleExport = () => {
    if (data.length === 0) return;

    const exportData = data.map(item => {
      let remark = '相符';
      if (item.actualQty === 0 && item.bookQty > 0) {
        remark = `盤虧 (現場未找到)`;
      } else if (item.diff > 0) {
        remark = `盤盈 ${item.diff}`;
      } else if (item.diff < 0) {
        remark = `盤虧 ${Math.abs(item.diff)}`;
      }

      return {
        ...(item.originalRow || {}), 
        '實際盤點數量': item.actualQty,
        '備註': remark
      };
    });

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果報表");
    XLSX.writeFile(wb, `大豐盤點報表_${new Date().toLocaleDateString().replace(/\//g, '')}.xlsx`);
  };

  const unscannedItems = data.filter(i => i.actualQty === 0 && i.bookQty > 0);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-10 space-y-8 max-w-7xl mx-auto relative">
      {/* Brand Header */}
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-6 border-b-2 border-slate-100 pb-8">
        <div className="flex items-center space-x-5">
          <div className="bg-slate-900 p-4 rounded-3xl shadow-2xl">
            <Building2 className="text-white w-10 h-10" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">大豐資訊</h1>
            <p className="text-blue-600 font-bold tracking-widest mt-1 text-sm uppercase">ERP Web Inventory System</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          {data.length === 0 ? (
            <label className="flex items-center space-x-3 bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-2xl cursor-pointer transition-all shadow-xl shadow-blue-100 active:scale-95 font-black text-xl">
              <FileSpreadsheet size={28} />
              <div className="text-left leading-tight">
                <span>匯入 ERP 庫存檔</span>
                <p className="text-xs font-normal opacity-80">支援 Excel (XLSX/CSV)</p>
              </div>
              <input type="file" accept=".csv, .xlsx, .xls" onChange={handleFileUpload} className="hidden" />
            </label>
          ) : (
            <div className="flex gap-4">
              <button 
                onClick={() => { if(confirm('確定要清除所有盤點紀錄？')) setData([]); setLastScanned(null); }}
                className="flex items-center space-x-2 bg-slate-100 hover:bg-red-50 hover:text-red-600 text-slate-600 px-6 py-4 rounded-2xl transition-all font-bold border border-slate-200"
              >
                <Trash2 size={22} />
                <span>重置盤點</span>
              </button>
              <button 
                onClick={handleExport}
                className="flex items-center space-x-3 bg-slate-900 hover:bg-slate-800 text-white px-10 py-5 rounded-2xl transition-all shadow-xl active:scale-95 font-black text-xl"
              >
                <FileDown size={28} />
                <span>匯出盤點報表</span>
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Main Scanner Section */}
      <main className="w-full grid grid-cols-1 gap-8">
        {/* Scanning Box */}
        <div className={`bg-white rounded-[2.5rem] p-10 shadow-2xl border-4 transition-all duration-300 ${
          isSuccess ? 'border-emerald-500 scale-[1.01]' : error ? 'border-red-500 shake' : 'border-blue-600 shadow-blue-50'
        }`}>
          <form onSubmit={handleScan} className="relative">
            <div className={`absolute left-8 top-1/2 -translate-y-1/2 transition-colors ${error ? 'text-red-500' : 'text-blue-600'}`}>
              <Search size={48} strokeWidth={3} />
            </div>
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "刷入條碼，或鍵盤輸入「產品代號」..." : "系統待命中，請先匯入 ERP 檔案"}
              disabled={data.length === 0}
              className="w-full pl-24 pr-10 py-10 text-5xl font-black bg-slate-50 border-none rounded-3xl scan-focus outline-none placeholder:text-slate-300 transition-all text-slate-900"
              autoComplete="off"
            />
            <div className="absolute right-8 top-1/2 -translate-y-1/2 bg-white p-4 rounded-2xl border-2 border-slate-100 shadow-sm flex items-center space-x-2">
              <Keyboard className="text-slate-300" size={32} />
              <div className="w-px h-8 bg-slate-200"></div>
              <Scan size={48} className={`text-blue-600 ${data.length > 0 ? 'animate-pulse' : 'opacity-10'}`} />
            </div>
          </form>
          <div className="mt-4 flex justify-between items-center text-slate-400 font-bold px-4">
             <p className="flex items-center gap-2 text-lg"><Keyboard size={20} /> 支援手動輸入產品代號 (例: HB-2549)</p>
             <p className="text-lg">按 Enter 鍵確認盤點</p>
          </div>
          {error && (
            <div className="mt-6 flex items-center justify-center text-red-600 space-x-3 bg-red-50 p-6 rounded-2xl border-2 border-red-100">
              <AlertCircle size={32} strokeWidth={3} />
              <span className="font-black text-3xl tracking-tight">{error}</span>
            </div>
          )}
        </div>

        {/* Info Display Area */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Main Info Card */}
          <div className="lg:col-span-7 bg-white rounded-[3rem] p-12 shadow-xl min-h-[450px] flex flex-col justify-center border-b-8 border-blue-600 relative overflow-hidden">
             {lastScanned ? (
               <div className="space-y-8 animate-in fade-in slide-in-from-bottom-12 duration-500 relative z-10">
                 <div className="flex items-center space-x-3 text-emerald-600 font-black text-2xl uppercase">
                   <CheckCircle2 size={32} />
                   <span>核對成功</span>
                 </div>
                 <h2 className="text-[5.5rem] font-black text-slate-900 leading-[1.1]">
                   {lastScanned.name}
                 </h2>
                 <div className="flex flex-wrap gap-6 font-mono text-3xl font-black">
                   {lastScanned.barcode && <div className="bg-blue-50 text-blue-700 px-8 py-3 rounded-2xl border border-blue-100">條碼: {lastScanned.barcode}</div>}
                   <div className="bg-slate-100 px-8 py-3 rounded-2xl border border-slate-200 text-slate-600">型號: {lastScanned.productCode}</div>
                 </div>
               </div>
             ) : (
               <div className="text-center space-y-8 text-slate-300 py-16">
                 <div className="bg-slate-50 w-40 h-40 rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-dashed border-slate-200">
                    <Scan size={80} className="opacity-20" />
                 </div>
                 <p className="text-4xl font-black tracking-widest text-slate-200 uppercase">等待掃描中</p>
               </div>
             )}
          </div>

          {/* Stats Grid */}
          <div className="lg:col-span-5 grid grid-cols-2 gap-8">
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-blue-500 flex flex-col justify-center items-center text-center">
              <span className="text-slate-400 font-black mb-2 uppercase tracking-widest text-lg">目前盤點</span>
              <span className="text-[7.5rem] font-black text-blue-600 leading-none">
                {lastScanned ? lastScanned.actualQty : '-'}
              </span>
            </div>
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-slate-200 flex flex-col justify-center items-center text-center">
              <span className="text-slate-400 font-black mb-2 uppercase tracking-widest text-lg">ERP 帳面</span>
              <span className="text-[7.5rem] font-black text-slate-300 leading-none">
                {lastScanned ? lastScanned.bookQty : '-'}
              </span>
            </div>
            <div className={`col-span-2 rounded-[3rem] p-12 shadow-2xl flex flex-col justify-center items-center text-center transition-all duration-500 ${
              !lastScanned 
                ? 'bg-slate-100 text-slate-400' 
                : lastScanned.diff === 0 
                  ? 'bg-emerald-600 text-white scale-[1.02]' 
                  : 'bg-red-600 text-white'
            }`}>
              <span className="font-black mb-4 opacity-80 uppercase tracking-[0.2em] text-xl">庫存差異</span>
              <span className="text-[10rem] font-black leading-none tracking-tighter">
                {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
              </span>
              {lastScanned && (
                <div className="mt-8 px-10 py-4 bg-white/20 rounded-3xl font-black text-3xl backdrop-blur-md border border-white/20">
                  {lastScanned.diff === 0 ? "與 ERP 帳面符合" : "庫存差異警示"}
                </div>
              )}
            </div>
          </div>
        </div>
      </main>

      {/* Summary Footer */}
      <footer className="w-full bg-slate-900 text-white rounded-[3rem] p-10 shadow-2xl">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-12 items-center">
          <div className="space-y-2">
            <span className="text-slate-500 text-sm font-black uppercase tracking-widest">匯入總項目</span>
            <div className="text-4xl font-black">{data.length}</div>
          </div>
          <div className="space-y-2">
            <span className="text-emerald-500 text-sm font-black uppercase tracking-widest">已掃描項目</span>
            <div className="text-4xl font-black text-emerald-400">
              {data.filter(i => i.actualQty > 0).length}
            </div>
          </div>
          <div className="space-y-2 flex flex-col group cursor-pointer" onClick={() => setShowUnscannedList(true)}>
            <span className="text-amber-500 text-sm font-black uppercase tracking-widest flex items-center gap-1 group-hover:text-amber-400 transition-colors">
              帳面有但未盤到 <ListFilter size={14} />
            </span>
            <div className="text-4xl font-black text-amber-400 underline decoration-dotted underline-offset-8">
              {unscannedItems.length}
            </div>
          </div>
          <div className="flex flex-col items-end">
             <div className="bg-slate-800 px-8 py-4 rounded-3xl flex items-center space-x-4 border border-slate-700">
               <div className="w-4 h-4 bg-emerald-500 rounded-full animate-pulse"></div>
               <span className="text-slate-100 font-black text-lg">系統穩定運行中</span>
             </div>
          </div>
        </div>
      </footer>

      {/* Unscanned Items Modal/Drawer */}
      {showUnscannedList && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl max-h-[85vh] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col">
            <div className="p-8 border-b-2 border-slate-100 flex justify-between items-center bg-slate-50">
               <div>
                  <h3 className="text-3xl font-black text-slate-900">帳面有但現場未盤到 (盤虧候選)</h3>
                  <p className="text-slate-500 font-bold mt-1">請依照代號前往貨架再次確認</p>
               </div>
               <button 
                 onClick={() => setShowUnscannedList(false)}
                 className="p-4 bg-slate-200 hover:bg-red-100 hover:text-red-600 rounded-2xl transition-all"
               >
                 <X size={32} />
               </button>
            </div>
            <div className="flex-1 overflow-y-auto p-8">
               {unscannedItems.length > 0 ? (
                 <table className="w-full text-left">
                   <thead className="sticky top-0 bg-white">
                     <tr className="text-slate-400 font-black uppercase tracking-widest text-sm border-b-2 border-slate-50">
                       <th className="pb-4 pl-4">產品代號</th>
                       <th className="pb-4">品名</th>
                       <th className="pb-4 text-right pr-4">帳面數量</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-50">
                     {unscannedItems.map((item, idx) => (
                       <tr key={idx} className="hover:bg-slate-50 transition-colors">
                         <td className="py-5 pl-4 font-mono font-black text-blue-600 text-lg">{item.productCode}</td>
                         <td className="py-5 font-bold text-slate-800 text-lg">{item.name}</td>
                         <td className="py-5 text-right pr-4 font-black text-slate-400 text-xl">{item.bookQty}</td>
                       </tr>
                     ))}
                   </tbody>
                 </table>
               ) : (
                 <div className="text-center py-20 text-emerald-500">
                    <CheckCircle2 size={100} className="mx-auto mb-6 opacity-20" />
                    <p className="text-3xl font-black">恭喜！所有帳面品項皆已掃描到。</p>
                 </div>
               )}
            </div>
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
              <p className="font-bold text-slate-400 italic">※ 若最終仍未盤到，匯出報表時將自動計為「盤虧」</p>
              <button 
                 onClick={() => setShowUnscannedList(false)}
                 className="bg-blue-600 px-10 py-4 rounded-2xl font-black text-xl hover:bg-blue-500 transition-all"
              >
                 關閉清單並繼續掃描
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileUp, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  RefreshCw,
  Package,
  History,
  Trash2,
  Building2,
  FileSpreadsheet,
  Keyboard,
  ListFilter,
  X,
  Save,
  UploadCloud,
  Clock
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_session';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [lastSaveTime, setLastSaveTime] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // 初始化：檢查瀏覽器是否有尚未完成的盤點紀錄
  useEffect(() => {
    const savedSession = localStorage.getItem(STORAGE_KEY);
    if (savedSession) {
      try {
        const { items, time } = JSON.parse(savedSession);
        if (items && items.length > 0) {
          if (confirm(`發現 ${time} 有未完成的盤點紀錄（共 ${items.length} 筆），是否要恢復進度繼續盤點？`)) {
            setData(items);
            setLastSaveTime(time);
          } else {
            localStorage.removeItem(STORAGE_KEY);
          }
        }
      } catch (e) {
        console.error("無法恢復暫存檔", e);
      }
    }
  }, []);

  // 當數據變動時，自動存入瀏覽器快取 (Auto-Save)
  useEffect(() => {
    if (data.length > 0) {
      const time = new Date().toLocaleString();
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, time }));
      setLastSaveTime(time);
    }
  }, [data]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList) {
      inputRef.current.focus();
    }
  }, [showUnscannedList]);

  useEffect(() => {
    focusInput();
    const handleGlobalClick = () => focusInput();
    window.addEventListener('click', handleGlobalClick);
    return () => window.removeEventListener('click', handleGlobalClick);
  }, [focusInput]);

  const processRawData = (jsonData: any[]) => {
    if (jsonData.length === 0) throw new Error("檔案內容為空，請檢查 Excel 資料。");
    const COL_BARCODE = '條碼編號';
    const COL_PROD_CODE = '產品代號';
    const COL_NAME = '品名';
    const COL_QTY = '期末數量';
    const headers = Object.keys(jsonData[0]);
    if (!headers.includes(COL_PROD_CODE) || !headers.includes(COL_NAME)) {
      throw new Error(`Excel 格式不符！必須包含「${COL_PROD_CODE}」與「${COL_NAME}」欄位。`);
    }
    return jsonData.map((row) => ({
      barcode: String(row[COL_BARCODE] || '').trim(),
      productCode: String(row[COL_PROD_CODE] || '').trim(),
      name: String(row[COL_NAME] || '').trim(),
      bookQty: parseFloat(row[COL_QTY]) || 0,
      actualQty: 0,
      diff: -parseFloat(row[COL_QTY]) || 0,
      originalRow: row 
    }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    const isExcel = file.name.endsWith('.xlsx') || file.name.endsWith('.xls');
    reader.onload = (event) => {
      try {
        let mappedData: InventoryItem[] = [];
        if (isExcel) {
          const buffer = new Uint8Array(event.target?.result as ArrayBuffer);
          const workbook = XLSX.read(buffer, { type: 'array' });
          mappedData = processRawData(XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]));
        } else {
          const workbook = XLSX.read(event.target?.result as string, { type: 'string' });
          mappedData = processRawData(XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]));
        }
        setData(mappedData);
        setError(null);
        setLastScanned(null);
        audioService.playSuccess();
      } catch (err: any) {
        setError(err.message || "檔案讀取失敗");
        audioService.playError();
      }
    };
    if (isExcel) reader.readAsArrayBuffer(file);
    else reader.readAsText(file);
    e.target.value = ''; 
  };

  // 手動備份進度到檔案 (跨裝置或長期保存用)
  const saveProgressToFile = () => {
    if (data.length === 0) return;
    const session = {
      items: data,
      time: new Date().toLocaleString(),
      type: 'DAFENG_PROGRESS_BACKUP'
    };
    const blob = new Blob([JSON.stringify(session, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `大豐盤點進度備份_${new Date().toLocaleDateString().replace(/\//g, '')}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  // 載入備份進度檔案
  const loadProgressFromFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const session = JSON.parse(event.target?.result as string);
        if (session.type !== 'DAFENG_PROGRESS_BACKUP') throw new Error("非有效的盤點進度備份檔");
        setData(session.items);
        setLastSaveTime(session.time);
        audioService.playSuccess();
        alert(`進度載入成功！恢復至 ${session.time} 的狀態。`);
      } catch (err: any) {
        alert("載入失敗：" + err.message);
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;
    const index = data.findIndex(item => 
      (item.barcode && item.barcode === code) || 
      (item.productCode && item.productCode === code)
    );
    if (index !== -1) {
      const updatedData = [...data];
      const item = { ...updatedData[index] };
      item.actualQty += 1;
      item.diff = item.actualQty - item.bookQty;
      updatedData[index] = item;
      setData(updatedData);
      setLastScanned(item);
      setError(null);
      setIsSuccess(true);
      audioService.playSuccess();
      setTimeout(() => setIsSuccess(false), 400);
    } else {
      setLastScanned(null);
      setError(`核對失敗：找不到條碼或代號 "${code}"`);
      audioService.playError();
    }
    setInputValue('');
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const exportData = data.map(item => ({
      ...(item.originalRow || {}), 
      '實際盤點數量': item.actualQty,
      '備註': item.actualQty === 0 && item.bookQty > 0 ? '盤虧 (未找到)' : item.diff > 0 ? `盤盈 ${item.diff}` : item.diff < 0 ? `盤虧 ${Math.abs(item.diff)}` : '相符'
    }));
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點報表");
    XLSX.writeFile(wb, `大豐正式盤點報表_${new Date().toLocaleDateString().replace(/\//g, '')}.xlsx`);
  };

  const unscannedItems = data.filter(i => i.actualQty === 0 && i.bookQty > 0);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-10 space-y-8 max-w-7xl mx-auto relative">
      {/* Brand Header */}
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-6 border-b-2 border-slate-100 pb-8">
        <div className="flex items-center space-x-5">
          <div className="bg-slate-900 p-4 rounded-3xl shadow-2xl relative">
            <Building2 className="text-white w-10 h-10" />
            {data.length > 0 && (
              <div className="absolute -top-2 -right-2 w-6 h-6 bg-blue-500 rounded-full border-4 border-white animate-pulse"></div>
            )}
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">大豐資訊</h1>
            <p className="text-blue-600 font-bold tracking-widest mt-1 text-sm uppercase">分段作業盤點系統</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {data.length > 0 && (
            <div className="flex bg-slate-100 p-2 rounded-2xl gap-2 mr-4 border border-slate-200">
               <button onClick={saveProgressToFile} className="flex items-center gap-2 px-4 py-3 bg-white hover:bg-blue-50 text-blue-600 rounded-xl transition-all font-bold shadow-sm">
                  <Save size={20} /> 暫存進度到檔案
               </button>
               <label className="flex items-center gap-2 px-4 py-3 bg-white hover:bg-emerald-50 text-emerald-600 rounded-xl transition-all font-bold shadow-sm cursor-pointer">
                  <UploadCloud size={20} /> 載入舊進度
                  <input type="file" accept=".json" onChange={loadProgressFromFile} className="hidden" />
               </label>
            </div>
          )}

          {data.length === 0 ? (
            <label className="flex items-center space-x-3 bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-2xl cursor-pointer transition-all shadow-xl shadow-blue-100 active:scale-95 font-black text-xl">
              <FileSpreadsheet size={28} />
              <span>匯入 ERP 庫存檔</span>
              <input type="file" accept=".csv, .xlsx, .xls" onChange={handleFileUpload} className="hidden" />
            </label>
          ) : (
            <div className="flex gap-3">
              <button onClick={() => { if(confirm('確定重置？這會清除目前的暫存紀錄。')) { setData([]); localStorage.removeItem(STORAGE_KEY); setLastSaveTime(null); } }} className="p-5 bg-slate-100 hover:bg-red-50 hover:text-red-600 text-slate-400 rounded-2xl transition-all">
                <Trash2 size={28} />
              </button>
              <button onClick={handleExport} className="flex items-center space-x-3 bg-slate-900 hover:bg-slate-800 text-white px-10 py-5 rounded-2xl transition-all shadow-xl active:scale-95 font-black text-xl">
                <FileDown size={28} />
                <span>產出正式報表</span>
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Auto-save Status */}
      {lastSaveTime && data.length > 0 && (
        <div className="w-full bg-blue-50 border border-blue-100 px-6 py-3 rounded-2xl flex items-center justify-between animate-in fade-in slide-in-from-top-4">
           <div className="flex items-center gap-2 text-blue-700 font-bold">
              <Clock size={18} />
              <span>進度已自動儲存：{lastSaveTime}</span>
           </div>
           <span className="text-blue-400 text-sm">倉庫很大別擔心，您可以隨時關閉網頁，明天繼續。</span>
        </div>
      )}

      {/* Main Scanner Section */}
      <main className="w-full grid grid-cols-1 gap-8">
        <div className={`bg-white rounded-[2.5rem] p-10 shadow-2xl border-4 transition-all duration-300 ${
          isSuccess ? 'border-emerald-500 scale-[1.01]' : error ? 'border-red-500 shake' : 'border-blue-600 shadow-blue-50'
        }`}>
          <form onSubmit={handleScan} className="relative">
            <div className={`absolute left-8 top-1/2 -translate-y-1/2 transition-colors ${error ? 'text-red-500' : 'text-blue-600'}`}>
              <Search size={48} strokeWidth={3} />
            </div>
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "刷入條碼或輸入產品代號..." : "請先匯入 ERP 檔案"}
              disabled={data.length === 0}
              className="w-full pl-24 pr-10 py-10 text-5xl font-black bg-slate-50 border-none rounded-3xl scan-focus outline-none text-slate-900"
              autoComplete="off"
            />
            <div className="absolute right-8 top-1/2 -translate-y-1/2 flex items-center space-x-3 opacity-20">
              <Keyboard size={32} />
              <div className="w-px h-8 bg-slate-400"></div>
              <Scan size={48} />
            </div>
          </form>
          {error && (
            <div className="mt-6 flex items-center justify-center text-red-600 space-x-3 bg-red-50 p-6 rounded-2xl border-2 border-red-100">
              <AlertCircle size={32} />
              <span className="font-black text-3xl">{error}</span>
            </div>
          )}
        </div>

        {/* Info Display */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-7 bg-white rounded-[3rem] p-12 shadow-xl min-h-[400px] flex flex-col justify-center border-b-8 border-blue-600">
             {lastScanned ? (
               <div className="space-y-8 animate-in fade-in slide-in-from-bottom-12">
                 <div className="flex items-center space-x-3 text-emerald-600 font-black text-2xl uppercase">
                   <CheckCircle2 size={32} />
                   <span>核對成功</span>
                 </div>
                 <h2 className="text-[5.5rem] font-black text-slate-900 leading-tight">{lastScanned.name}</h2>
                 <div className="flex gap-4 font-mono text-2xl font-black">
                   <span className="bg-slate-100 px-6 py-2 rounded-xl text-slate-600">型號: {lastScanned.productCode}</span>
                 </div>
               </div>
             ) : (
               <div className="text-center space-y-6 text-slate-200 py-12">
                 <Scan size={100} className="mx-auto opacity-10" />
                 <p className="text-4xl font-black uppercase tracking-widest">等待掃描...</p>
               </div>
             )}
          </div>

          <div className="lg:col-span-5 grid grid-cols-2 gap-8">
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-blue-500 text-center">
              <span className="text-slate-400 font-black uppercase text-sm tracking-widest">目前盤點</span>
              <div className="text-[7rem] font-black text-blue-600 leading-none mt-2">{lastScanned ? lastScanned.actualQty : '-'}</div>
            </div>
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-slate-200 text-center">
              <span className="text-slate-400 font-black uppercase text-sm tracking-widest">ERP 帳面</span>
              <div className="text-[7rem] font-black text-slate-300 leading-none mt-2">{lastScanned ? lastScanned.bookQty : '-'}</div>
            </div>
            <div className={`col-span-2 rounded-[3rem] p-10 shadow-2xl flex flex-col justify-center items-center text-center transition-all ${
              !lastScanned ? 'bg-slate-100 text-slate-300' : lastScanned.diff === 0 ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              <span className="font-black opacity-80 uppercase tracking-widest mb-2">庫存差異</span>
              <div className="text-[9rem] font-black leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
              {lastScanned && <div className="mt-6 px-8 py-3 bg-white/20 rounded-2xl font-black text-2xl">{lastScanned.diff === 0 ? "與帳面一致" : "差異警示"}</div>}
            </div>
          </div>
        </div>
      </main>

      {/* Footer Stats */}
      <footer className="w-full bg-slate-900 text-white rounded-[3rem] p-10 shadow-2xl grid grid-cols-2 md:grid-cols-4 gap-8">
          <div>
            <p className="text-slate-500 text-xs font-black uppercase tracking-widest mb-1">匯入總項</p>
            <p className="text-4xl font-black">{data.length}</p>
          </div>
          <div>
            <p className="text-emerald-500 text-xs font-black uppercase tracking-widest mb-1">已掃描項目</p>
            <p className="text-4xl font-black text-emerald-400">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
          <div className="cursor-pointer group" onClick={() => setShowUnscannedList(true)}>
            <p className="text-amber-500 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-1">待找出品項 <ListFilter size={14}/></p>
            <p className="text-4xl font-black text-amber-400 underline decoration-dotted group-hover:text-amber-300">{unscannedItems.length}</p>
          </div>
          <div className="flex justify-end items-center">
             <div className="flex items-center gap-3 bg-white/5 px-6 py-4 rounded-2xl border border-white/10">
                <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse"></div>
                <span className="font-bold text-slate-300">雲端存檔啟動中</span>
             </div>
          </div>
      </footer>

      {/* Unscanned Modal */}
      {showUnscannedList && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/90 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-4xl max-h-[80vh] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
               <h3 className="text-3xl font-black text-slate-900">待盤點清單 (帳面有但現場未找到)</h3>
               <button onClick={() => setShowUnscannedList(false)} className="p-4 hover:bg-red-50 hover:text-red-600 rounded-2xl transition-all"><X size={32}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8">
               <table className="w-full text-left border-separate border-spacing-y-2">
                 <thead>
                   <tr className="text-slate-400 font-black text-sm uppercase tracking-widest">
                     <th className="px-4">產品代號</th>
                     <th>品名</th>
                     <th className="text-right px-4">帳面數</th>
                   </tr>
                 </thead>
                 <tbody>
                   {unscannedItems.map((item, idx) => (
                     <tr key={idx} className="bg-slate-50 hover:bg-slate-100 transition-colors">
                       <td className="p-4 rounded-l-2xl font-mono font-black text-blue-600">{item.productCode}</td>
                       <td className="p-4 font-bold">{item.name}</td>
                       <td className="p-4 rounded-r-2xl text-right font-black text-slate-400">{item.bookQty}</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
            </div>
            <div className="p-8 bg-slate-900 text-white flex justify-between items-center">
               <p className="font-bold text-slate-400">※ 按 ESC 或點擊右上角關閉</p>
               <button onClick={() => setShowUnscannedList(false)} className="bg-blue-600 px-12 py-4 rounded-2xl font-black text-xl hover:bg-blue-500 transition-all">關閉清單</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface InventoryItem {
  barcode: string;      // 條碼編號
  productCode: string;  // 產品代號
  name: string;         // 品名
  bookQty: number;      // 期末數量 (ERP)
  actualQty: number;    // 盤點數量
  diff: number;         // 差異數
  originalRow?: any;    // 原始 Excel 完整列資料
  mappedBarcodes?: string[]; // 記錄額外關聯到此項目的錯誤條碼
  remarks?: string;     // 額外備註
}

export interface ScanResult {
  success: boolean;
  message: string;
  item?: InventoryItem;
}

export interface AISearchResult {
  text: string;
  sources: { title: string; uri: string }[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  Trash2,
  Building2,
  FileSpreadsheet,
  Keyboard,
  ListFilter,
  X,
  Save,
  UploadCloud,
  Clock,
  Link,
  Sparkles,
  ExternalLink,
  Loader2
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem, AISearchResult } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_session_v2';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');
  const [lastSaveTime, setLastSaveTime] = useState<string | null>(null);

  // AI 狀態
  const [aiEnabled, setAiEnabled] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AISearchResult | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  // 初始化與自動存檔
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { items, time } = JSON.parse(saved);
        if (items?.length > 0 && confirm(`發現 ${time} 的暫存紀錄，是否恢復？`)) {
          setData(items);
          setLastSaveTime(time);
        } else {
          localStorage.removeItem(STORAGE_KEY);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      const time = new Date().toLocaleString();
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, time }));
      setLastSaveTime(time);
    }
  }, [data]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  // AI 搜尋功能
  const fetchProductAIInfo = async (item: InventoryItem) => {
    if (!aiEnabled || !process.env.API_KEY) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `請搜尋產品「${item.name}」型號為「${item.productCode}」的外觀特徵與用途。
      這是一個倉儲盤點輔助，請提供簡短的外觀描述（顏色、形狀、材質）幫助人員確認是否拿對貨。`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const text = response.text || "無法取得 AI 描述";
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      setAiResult({ text, sources });
    } catch (e) {
      console.error("AI Search Error:", e);
    } finally {
      setAiLoading(false);
    }
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    // 搜尋現有條碼、產品代號或已手動關聯的條碼
    const index = data.findIndex(item => 
      (item.barcode === code) || 
      (item.productCode === code) ||
      (item.mappedBarcodes?.includes(code))
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      setData(updatedData);
      setLastScanned(updatedData[index]);
      setError(null);
      setIsSuccess(true);
      audioService.playSuccess();
      if (aiEnabled) fetchProductAIInfo(updatedData[index]);
      setTimeout(() => setIsSuccess(false), 400);
    } else {
      // 找不到條碼，觸發手動關聯流程
      setUnknownBarcode(code);
      setShowMappingModal(true);
      audioService.playError();
    }
    setInputValue('');
  };

  const mapBarcodeToProduct = (productIndex: number) => {
    const updatedData = [...data];
    const item = updatedData[productIndex];

    // 建立關聯
    if (!item.mappedBarcodes) item.mappedBarcodes = [];
    if (!item.mappedBarcodes.includes(unknownBarcode)) {
      item.mappedBarcodes.push(unknownBarcode);
      item.remarks = (item.remarks || "") + ` [關聯新條碼: ${unknownBarcode}]`;
    }

    // 計入盤點
    item.actualQty += 1;
    item.diff = item.actualQty - item.bookQty;

    setData(updatedData);
    setLastScanned(item);
    setShowMappingModal(false);
    setUnknownBarcode('');
    setMappingSearch('');
    audioService.playSuccess();
    if (aiEnabled) fetchProductAIInfo(item);
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const exportData = data.map(item => ({
      ...(item.originalRow || {}), 
      '實際盤點數量': item.actualQty,
      '手動關聯條碼': item.mappedBarcodes?.join(', ') || '',
      '盤點備註': (item.remarks || "") + (item.actualQty === 0 && item.bookQty > 0 ? ' (未找到)' : '')
    }));
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點報表");
    XLSX.writeFile(wb, `大豐盤點報表_${new Date().toLocaleDateString().replace(/\//g, '')}.xlsx`);
  };

  const unscannedItems = data.filter(i => i.actualQty === 0 && i.bookQty > 0);
  const filteredMapping = data.filter(i => 
    i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || 
    i.name.toLowerCase().includes(mappingSearch.toLowerCase())
  ).slice(0, 50);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-10 space-y-8 max-w-7xl mx-auto relative">
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-6 border-b-2 border-slate-100 pb-8">
        <div className="flex items-center space-x-5">
          <div className="bg-slate-900 p-4 rounded-3xl shadow-2xl relative">
            <Building2 className="text-white w-10 h-10" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">大豐資訊</h1>
            <p className="text-blue-600 font-bold tracking-widest mt-1 text-sm uppercase">高階實務盤點系統</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <button 
            onClick={() => setAiEnabled(!aiEnabled)}
            className={`flex items-center gap-2 px-6 py-4 rounded-2xl font-black transition-all shadow-lg ${
              aiEnabled ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-slate-100 text-slate-400'
            }`}
          >
            <Sparkles size={20} className={aiEnabled ? 'animate-pulse' : ''} />
            AI 智慧輔助 {aiEnabled ? 'ON' : 'OFF'}
          </button>

          {data.length === 0 ? (
            <label className="flex items-center space-x-3 bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-2xl cursor-pointer transition-all shadow-xl font-black text-xl">
              <FileSpreadsheet size={28} />
              <span>匯入 ERP 庫存檔</span>
              <input type="file" accept=".csv, .xlsx, .xls" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                  try {
                    const workbook = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
                    const mapped = (jsonData as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || '').trim(),
                      bookQty: parseFloat(row['期末數量']) || 0,
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量']) || 0,
                      originalRow: row
                    }));
                    setData(mapped);
                    audioService.playSuccess();
                  } catch (e) { alert("讀取失敗"); }
                };
                reader.readAsArrayBuffer(file);
              }} className="hidden" />
            </label>
          ) : (
            <button onClick={handleExport} className="flex items-center space-x-3 bg-slate-900 hover:bg-slate-800 text-white px-10 py-5 rounded-2xl transition-all shadow-xl font-black text-xl">
              <FileDown size={28} />
              <span>匯出正式報表</span>
            </button>
          )}
        </div>
      </header>

      <main className="w-full grid grid-cols-1 gap-8">
        {/* Scanner Form */}
        <div className={`bg-white rounded-[2.5rem] p-10 shadow-2xl border-4 transition-all duration-300 ${
          isSuccess ? 'border-emerald-500 scale-[1.01]' : error ? 'border-red-500' : 'border-blue-600 shadow-blue-50'
        }`}>
          <form onSubmit={handleScan} className="relative">
            <Search size={48} className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-600" />
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "刷入條碼... (若條碼錯誤將開啟關聯視窗)" : "請先匯入 ERP 檔案"}
              disabled={data.length === 0}
              className="w-full pl-24 pr-10 py-10 text-5xl font-black bg-slate-50 border-none rounded-3xl outline-none text-slate-900"
              autoComplete="off"
            />
          </form>
        </div>

        {/* Display Panel */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Main Product Info */}
