          <form onSubmit={handleScan} className="relative">
            <Search size={48} className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-600" />
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "刷入條碼... (掃描後將自動播報品名)" : "請先匯入 ERP 檔案"}
              disabled={data.length === 0}
              className="w-full pl-24 pr-10 py-10 text-5xl font-black bg-slate-50 border-none rounded-3xl outline-none text-slate-900"
              autoComplete="off"
