          </form>
        </div>

        {/* Display Panel */}
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-8 bg-white rounded-[3rem] p-12 shadow-xl border-b-8 border-blue-600 min-h-[500px] flex flex-col relative overflow-hidden">
             {lastScanned ? (
               <div className="h-full flex flex-col">
                 <div className="flex items-center space-x-3 text-emerald-600 font-black text-2xl uppercase mb-4">
                   <CheckCircle2 size={32} />
                   <span>核對成功 {lastScanned.mappedBarcodes?.includes(lastScanned.barcode) ? '(手動關聯)' : ''}</span>
