                 <h2 className="text-[5rem] font-black text-slate-900 leading-tight mb-8">{lastScanned.name}</h2>

                 <div className="grid grid-cols-2 gap-6 mt-auto">
                    <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                       <span className="text-slate-400 font-black text-sm uppercase tracking-widest block mb-2">產品代號</span>
                       <span className="text-4xl font-black text-slate-700">{lastScanned.productCode}</span>
                    </div>
                    <div className="bg-slate-50 p-8 rounded-3xl border border-slate-100">
                       <span className="text-slate-400 font-black text-sm uppercase tracking-widest block mb-2">主條碼</span>
                       <span className="text-4xl font-black text-slate-700">{lastScanned.barcode || '無'}</span>
                    </div>
                 </div>

                 {aiEnabled && (
                   <div className="mt-8 pt-8 border-t border-slate-100">
                      <div className="flex items-center gap-2 mb-4">
                        <Sparkles size={20} className="text-indigo-600" />
                        <h4 className="font-black text-slate-400 uppercase tracking-widest">AI 智慧辨識輔助</h4>
                      </div>
                      {aiLoading ? (
                        <div className="flex items-center gap-3 text-slate-400 animate-pulse">
                          <Loader2 className="animate-spin" /> 正在聯網搜尋商品資訊...
                        </div>
                      ) : aiResult ? (
                        <div className="bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100">
                          <p className="text-xl font-bold text-slate-700 leading-relaxed mb-4">{aiResult.text}</p>
                          <div className="flex flex-wrap gap-2">
                            {aiResult.sources.slice(0, 3).map((s, i) => (
                              <a key={i} href={s.uri} target="_blank" className="flex items-center gap-1 text-xs bg-white px-3 py-1.5 rounded-lg border border-indigo-200 text-indigo-600 hover:bg-indigo-600 hover:text-white transition-all">
                                <ExternalLink size={12} /> {s.title.substring(0, 20)}...
                              </a>
                            ))}
                          </div>
                        </div>
                      ) : (
                        <p className="text-slate-300 italic">掃描後自動顯示外觀參考資料</p>
                      )}
                   </div>
                 )}
               </div>
             ) : (
               <div className="flex flex-col items-center justify-center h-full text-slate-200 space-y-6">
                 <Scan size={120} className="opacity-10" />
                 <p className="text-4xl font-black uppercase tracking-[0.2em]">等待掃描中</p>
               </div>
             )}
          </div>

          <div className="lg:col-span-4 grid grid-cols-1 gap-8">
            <div className="bg-white rounded-[2.5rem] p-8 shadow-lg border-t-8 border-blue-500 text-center">
              <span className="text-slate-400 font-black uppercase text-sm tracking-widest">目前盤點</span>
              <div className="text-[8rem] font-black text-blue-600 leading-none">{lastScanned?.actualQty || '-'}</div>
            </div>
            <div className={`rounded-[3.5rem] p-10 shadow-2xl flex flex-col justify-center items-center text-center transition-all ${
              !lastScanned ? 'bg-slate-100 text-slate-300' : lastScanned.diff === 0 ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
            }`}>
              <span className="font-black opacity-80 uppercase tracking-widest mb-2 text-lg">庫存差異</span>
              <div className="text-[10rem] font-black leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
              {lastScanned && <div className="mt-6 px-10 py-4 bg-white/20 rounded-3xl font-black text-3xl">{lastScanned.diff === 0 ? "帳面符合" : "差異警示"}</div>}
            </div>
          </div>
        </div>
      </main>

      {/* Mapping Modal */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-6 bg-slate-900/95 backdrop-blur-xl animate-in fade-in zoom-in duration-300">
          <div className="bg-white w-full max-w-3xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col">
            <div className="p-10 bg-red-600 text-white">
               <div className="flex items-center gap-4 mb-2">
                 <AlertCircle size={40} />
                 <h3 className="text-4xl font-black">偵測到不明條碼</h3>
               </div>
               <p className="text-xl opacity-80 font-bold">條碼：<span className="font-mono bg-black/20 px-4 py-1 rounded-xl">{unknownBarcode}</span> 不在清單中</p>
            </div>

            <div className="p-8 border-b">
              <div className="relative">
                <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" />
                <input 
                  autoFocus
                  type="text" 
                  value={mappingSearch}
                  onChange={(e) => setMappingSearch(e.target.value)}
                  placeholder="輸入關鍵字搜尋現有產品..."
                  className="w-full pl-16 pr-8 py-6 text-2xl font-bold bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 ring-blue-500/20"
                />
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 max-h-[400px]">
               {filteredMapping.length > 0 ? filteredMapping.map((item, idx) => {
                 const originalIndex = data.findIndex(d => d.productCode === item.productCode);
                 return (
                   <button 
                     key={idx} 
                     onClick={() => mapBarcodeToProduct(originalIndex)}
                     className="w-full text-left p-6 hover:bg-blue-50 rounded-2xl transition-all border-b border-slate-50 flex justify-between items-center group"
                   >
                     <div>
                       <div className="text-2xl font-black text-slate-900 group-hover:text-blue-600">{item.productCode}</div>
                       <div className="text-lg font-bold text-slate-400">{item.name}</div>
                     </div>
                     <Link size={24} className="text-slate-200 group-hover:text-blue-500" />
                   </button>
                 );
               }) : (
                 <div className="text-center py-10 text-slate-300 font-bold">找不到匹配的產品</div>
               )}
            </div>

            <div className="p-8 bg-slate-50 flex justify-between items-center">
               <button onClick={() => { setShowMappingModal(false); setUnknownBarcode(''); }} className="text-slate-400 font-black text-xl hover:text-slate-600">放棄關聯</button>
               <p className="text-slate-400 font-bold italic">※ 系統將自動記住此關聯條碼</p>
            </div>
          </div>
        </div>
      )}

      {/* Summary Footer */}
      <footer className="w-full bg-slate-900 text-white rounded-[3rem] p-10 shadow-2xl grid grid-cols-2 md:grid-cols-4 gap-8">
          <div>
            <p className="text-slate-500 text-xs font-black uppercase tracking-widest mb-1">匯入總項</p>
            <p className="text-4xl font-black">{data.length}</p>
          </div>
          <div>
            <p className="text-emerald-500 text-xs font-black uppercase tracking-widest mb-1">已完成盤點</p>
            <p className="text-4xl font-black text-emerald-400">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
          <div className="cursor-pointer group" onClick={() => setShowUnscannedList(true)}>
            <p className="text-amber-500 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-1">待盤點清單 <ListFilter size={14}/></p>
            <p className="text-4xl font-black text-amber-400 underline decoration-dotted">{unscannedItems.length}</p>
          </div>
          <div className="flex flex-col items-end justify-center">
             <div className="flex items-center gap-3 bg-white/5 px-6 py-4 rounded-2xl border border-white/10">
                <div className={`w-3 h-3 rounded-full ${lastSaveTime ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`}></div>
                <span className="font-bold text-slate-300 text-sm">本地存檔：{lastSaveTime || '未啟動'}</span>
             </div>
          </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality } from "@google/genai";

class AudioService {
  private audioCtx: AudioContext | null = null;

  private init() {
    if (!this.audioCtx) {
      this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
  }

  private decodeBase64(base64: string): Uint8Array {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  private async decodePCM(data: Uint8Array, ctx: AudioContext): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length;
    const buffer = ctx.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  }

  async speak(text: string) {
    if (!process.env.API_KEY) return;
    this.init();
    if (!this.audioCtx) return;

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }, 
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const audioData = this.decodeBase64(base64Audio);
        const audioBuffer = await this.decodePCM(audioData, this.audioCtx);
        const source = this.audioCtx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(this.audioCtx.destination);
        source.start();
      }
    } catch (error) {
      console.error("TTS Error:", error);
      // 失敗時回退到簡單嗶聲
      this.playSimpleBeep(text.includes('無') ? 110 : 880);
    }
  }

  private playSimpleBeep(freq: number) {
    this.init();
    if (!this.audioCtx) return;
    const osc = this.audioCtx.createOscillator();
    const gain = this.audioCtx.createGain();
    osc.frequency.setValueAtTime(freq, this.audioCtx.currentTime);
    gain.gain.setValueAtTime(0.05, this.audioCtx.currentTime);
    osc.connect(gain);
    gain.connect(this.audioCtx.destination);
    osc.start();
    osc.stop(this.audioCtx.currentTime + 0.1);
  }

  // 簡化報號內容：直接報 品名, 數量
  speakSuccess(name: string, qty: number) {
    this.speak(`${name}，${qty}`);
  }

  speakError() {
    this.speak("無此品項");
  }

  speakMappingSuccess() {
    this.speak("已關聯");
  }
}

export const audioService = new AudioService();

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  Building2,
  FileSpreadsheet,
  ListFilter,
  X,
  Sparkles,
  ExternalLink,
  Loader2,
  Volume2,
  VolumeX,
  Link
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem, AISearchResult } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_session_v2';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');
  const [lastSaveTime, setLastSaveTime] = useState<string | null>(null);

  // 設定狀態
  const [aiEnabled, setAiEnabled] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(true); // 語音開關
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AISearchResult | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  // 初始化與自動存檔
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { items, time, config } = JSON.parse(saved);
        if (items?.length > 0 && confirm(`發現 ${time} 的暫存紀錄，是否恢復？`)) {
          setData(items);
          setLastSaveTime(time);
          if (config) {
            setAiEnabled(!!config.aiEnabled);
            setVoiceEnabled(config.voiceEnabled !== false);
          }
        } else {
          localStorage.removeItem(STORAGE_KEY);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      const time = new Date().toLocaleString();
      const config = { aiEnabled, voiceEnabled };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, time, config }));
      setLastSaveTime(time);
    }
  }, [data, aiEnabled, voiceEnabled]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const fetchProductAIInfo = async (item: InventoryItem) => {
    if (!aiEnabled || !process.env.API_KEY) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `請搜尋產品「${item.name}」型號為「${item.productCode}」的外觀特徵。
      這是一個倉儲盤點輔助，請提供極簡短的外觀描述（顏色、形狀）幫助人員確認。`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const text = response.text || "無法取得 AI 描述";
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      setAiResult({ text, sources });
    } catch (e) {
      console.error("AI Search Error:", e);
    } finally {
      setAiLoading(false);
    }
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      (item.barcode === code) || 
      (item.productCode === code) ||
      (item.mappedBarcodes?.includes(code))
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      setData(updatedData);
      setLastScanned(updatedData[index]);
      setError(null);
      setIsSuccess(true);

      if (voiceEnabled) {
        audioService.speakSuccess(updatedData[index].name, updatedData[index].actualQty);
      }

      if (aiEnabled) fetchProductAIInfo(updatedData[index]);
      setTimeout(() => setIsSuccess(false), 400);
    } else {
      setUnknownBarcode(code);
      setShowMappingModal(true);
      if (voiceEnabled) audioService.speakError();
    }
    setInputValue('');
  };

  const mapBarcodeToProduct = (productIndex: number) => {
    const updatedData = [...data];
    const item = updatedData[productIndex];

    if (!item.mappedBarcodes) item.mappedBarcodes = [];
    if (!item.mappedBarcodes.includes(unknownBarcode)) {
      item.mappedBarcodes.push(unknownBarcode);
      item.remarks = (item.remarks || "") + ` [關聯條碼: ${unknownBarcode}]`;
    }

    item.actualQty += 1;
    item.diff = item.actualQty - item.bookQty;

    setData(updatedData);
    setLastScanned(item);
    setShowMappingModal(false);
    setUnknownBarcode('');
    setMappingSearch('');

    if (voiceEnabled) audioService.speakMappingSuccess();
    if (aiEnabled) fetchProductAIInfo(item);
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const exportData = data.map(item => ({
      ...(item.originalRow || {}), 
      '實際盤點數量': item.actualQty,
      '手動關聯條碼': item.mappedBarcodes?.join(', ') || '',
      '盤點備註': (item.remarks || "") + (item.actualQty === 0 && item.bookQty > 0 ? ' (未找到)' : '')
    }));
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點報表");
    XLSX.writeFile(wb, `大豐盤點報表_${new Date().toLocaleDateString().replace(/\//g, '')}.xlsx`);
  };

  const unscannedItems = data.filter(i => i.actualQty === 0 && i.bookQty > 0);
  const filteredMapping = data.filter(i => 
    i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || 
    i.name.toLowerCase().includes(mappingSearch.toLowerCase())
  ).slice(0, 50);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-10 space-y-8 max-w-7xl mx-auto relative">
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-6 border-b-2 border-slate-100 pb-8">
        <div className="flex items-center space-x-5">
          <div className="bg-slate-900 p-4 rounded-3xl shadow-2xl relative">
            <Building2 className="text-white w-10 h-10" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">大豐資訊</h1>
            <p className="text-blue-600 font-bold tracking-widest mt-1 text-sm uppercase">高階實務盤點系統</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setVoiceEnabled(!voiceEnabled)}
            title={voiceEnabled ? "關閉語音提醒" : "開啟語音提醒"}
            className={`flex items-center gap-2 px-5 py-4 rounded-2xl font-black transition-all shadow-lg ${
              voiceEnabled ? 'bg-emerald-600 text-white shadow-emerald-200' : 'bg-slate-100 text-slate-400'
            }`}
          >
            {voiceEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
            語音報號
          </button>

          <button 
            onClick={() => setAiEnabled(!aiEnabled)}
            className={`flex items-center gap-2 px-5 py-4 rounded-2xl font-black transition-all shadow-lg ${
              aiEnabled ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-slate-100 text-slate-400'
            }`}
          >
            <Sparkles size={20} className={aiEnabled ? 'animate-pulse' : ''} />
            AI 智慧輔助
          </button>

          {data.length === 0 ? (
            <label className="flex items-center space-x-3 bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl cursor-pointer transition-all shadow-xl font-black text-lg">
              <FileSpreadsheet size={24} />
              <span>匯入 ERP 庫存</span>
              <input type="file" accept=".csv, .xlsx, .xls" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                  try {
                    const workbook = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
                    const mapped = (jsonData as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || row['數量'] || row['庫存量']) || 0,
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量'] || row['數量'] || row['庫存量']) || 0,
                      originalRow: row
                    }));
                    setData(mapped);
                    if (voiceEnabled) audioService.speak("檔案匯入成功");
                  } catch (e) { alert("讀取失敗"); }
                };
                reader.readAsArrayBuffer(file);
              }} className="hidden" />
            </label>
          ) : (
            <button onClick={handleExport} className="flex items-center space-x-3 bg-slate-900 hover:bg-slate-800 text-white px-8 py-4 rounded-2xl transition-all shadow-xl font-black text-lg">
              <FileDown size={24} />
              <span>匯出報表</span>
            </button>
          )}
        </div>
      </header>

      <main className="w-full grid grid-cols-1 gap-8">
        <div className={`bg-white rounded-[2.5rem] p-10 shadow-2xl border-4 transition-all duration-300 ${
          isSuccess ? 'border-emerald-500 scale-[1.01]' : error ? 'border-red-500' : 'border-blue-600 shadow-blue-50'
        }`}>
          <form onSubmit={handleScan} className="relative">
            <Search size={48} className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-600" />
            <input
              ref={inputRef}
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
