          <div className="cursor-pointer group" onClick={() => setShowUnscannedList(true)}>
            <p className="text-amber-500 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-1">未盤清單 <ListFilter size={14}/></p>
            <p className="text-4xl font-black text-amber-400 underline decoration-dotted">{unscannedItems.length}</p>
          </div>
          <div className="flex flex-col items-end justify-center">
             <div className="flex items-center gap-3 bg-white/5 px-6 py-4 rounded-2xl border border-white/10">
                <div className={`w-3 h-3 rounded-full ${lastSaveTime ? 'bg-emerald-500 animate-pulse' : 'bg-slate-600'}`}></div>
                <span className="font-bold text-slate-300 text-sm">本地存檔中</span>
             </div>
          </div>
      </footer>

      {showUnscannedList && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-6 bg-slate-900/90 backdrop-blur-md">
          <div className="bg-white w-full max-w-4xl max-h-[80vh] rounded-[3rem] shadow-2xl overflow-hidden flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-slate-50">
               <h3 className="text-3xl font-black text-slate-900">未盤點項目</h3>
               <button onClick={() => setShowUnscannedList(false)} className="p-4 hover:bg-red-50 text-slate-400 hover:text-red-600 rounded-2xl"><X size={32}/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-8">
               <table className="w-full text-left">
                 <thead>
                   <tr className="text-slate-400 font-black text-sm uppercase tracking-widest border-b-2">
                     <th className="pb-4">代號</th>
                     <th className="pb-4">品名</th>
                     <th className="pb-4 text-right">數量</th>
                   </tr>
                 </thead>
                 <tbody>
                   {unscannedItems.map((item, idx) => (
                     <tr key={idx} className="border-b border-slate-50">
                       <td className="py-4 font-mono font-black text-blue-600">{item.productCode}</td>
                       <td className="py-4 font-bold">{item.name}</td>
                       <td className="py-4 text-right font-black text-slate-400">{item.bookQty}</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

