import { GoogleGenAI, Modality } from "@google/genai";

class AudioService {
  private audioCtx: AudioContext | null = null;
  private currentSource: AudioBufferSourceNode | null = null;

  private init() {
    if (!this.audioCtx) {
      this.audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
  }

  private decodeBase64(base64: string): Uint8Array {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
      bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
  }

  private async decodePCM(data: Uint8Array, ctx: AudioContext): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length;
    const buffer = ctx.createBuffer(1, frameCount, 24000);
    const channelData = buffer.getChannelData(0);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i] / 32768.0;
    }
    return buffer;
  }

  // 即時的極短嗶聲，用於掃描瞬間的反饋
  playFeedback(type: 'success' | 'error') {
    this.init();
    if (!this.audioCtx) return;
    const osc = this.audioCtx.createOscillator();
    const gain = this.audioCtx.createGain();
    osc.frequency.setValueAtTime(type === 'success' ? 880 : 110, this.audioCtx.currentTime);
    gain.gain.setValueAtTime(0.05, this.audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, this.audioCtx.currentTime + 0.1);
    osc.connect(gain);
    gain.connect(this.audioCtx.destination);
    osc.start();
    osc.stop(this.audioCtx.currentTime + 0.1);
  }

  async speak(text: string) {
    if (!process.env.API_KEY) return;
    this.init();
    if (!this.audioCtx) return;

    // 如果正在播報，立即停止（支援連續掃描中斷）
    if (this.currentSource) {
      try { this.currentSource.stop(); } catch(e) {}
      this.currentSource = null;
    }

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: `僅播報以下文字，不要有任何多餘字：${text}` }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }, 
            },
          },
        },
      });

      const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (base64Audio) {
        const audioData = this.decodeBase64(base64Audio);
        const audioBuffer = await this.decodePCM(audioData, this.audioCtx);
        const source = this.audioCtx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(this.audioCtx.destination);
        this.currentSource = source;
        source.start();
      }
    } catch (error) {
      console.error("TTS Error:", error);
    }
  }

  speakSuccess(name: string, qty: number) {
    this.playFeedback('success');
    this.speak(`${name}，${qty}`);
  }

  speakError() {
    this.playFeedback('error');
    this.speak("無此品項");
  }

  speakMappingSuccess() {
    this.playFeedback('success');
    this.speak("已關聯");
  }
}

export const audioService = new AudioService();

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, 
  FileDown, 
  AlertCircle, 
  CheckCircle2, 
  Search,
  Building2,
  FileSpreadsheet,
  ListFilter,
  X,
  Sparkles,
  ExternalLink,
  Loader2,
  Volume2,
  VolumeX,
  Link
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem, AISearchResult } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_session_v2';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSuccess, setIsSuccess] = useState(false);

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');
  const [lastSaveTime, setLastSaveTime] = useState<string | null>(null);

  const [aiEnabled, setAiEnabled] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(true); 
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AISearchResult | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { items, time, config } = JSON.parse(saved);
        if (items?.length > 0 && confirm(`發現 ${time} 的暫存紀錄，是否恢復？`)) {
          setData(items);
          setLastSaveTime(time);
          if (config) {
            setAiEnabled(!!config.aiEnabled);
            setVoiceEnabled(config.voiceEnabled !== false);
          }
        } else {
          localStorage.removeItem(STORAGE_KEY);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      const time = new Date().toLocaleString();
      const config = { aiEnabled, voiceEnabled };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, time, config }));
      setLastSaveTime(time);
    }
  }, [data, aiEnabled, voiceEnabled]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const fetchProductAIInfo = async (item: InventoryItem) => {
    if (!aiEnabled || !process.env.API_KEY) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `請搜尋產品「${item.name}」型號為「${item.productCode}」的外觀特徵。
      這是一個倉儲盤點輔助，請提供極簡短的外觀描述（顏色、形狀）幫助人員確認。`;

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { tools: [{ googleSearch: {} }] },
      });

      const text = response.text || "無法取得 AI 描述";
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks
        .filter((c: any) => c.web)
        .map((c: any) => ({ title: c.web.title, uri: c.web.uri }));

      setAiResult({ text, sources });
    } catch (e) {
      console.error("AI Search Error:", e);
    } finally {
      setAiLoading(false);
    }
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      (item.barcode === code) || 
      (item.productCode === code) ||
      (item.mappedBarcodes?.includes(code))
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      setData(updatedData);
      setLastScanned(updatedData[index]);
      setError(null);
      setIsSuccess(true);

      // 播放極簡報號（品名 + 數量）
      if (voiceEnabled) {
        audioService.speakSuccess(updatedData[index].name, updatedData[index].actualQty);
      } else {
        audioService.playFeedback('success');
      }

      if (aiEnabled) fetchProductAIInfo(updatedData[index]);
      setTimeout(() => setIsSuccess(false), 200);
    } else {
      setUnknownBarcode(code);
      setShowMappingModal(true);
      if (voiceEnabled) audioService.speakError();
      else audioService.playFeedback('error');
    }
    setInputValue('');
  };

  const mapBarcodeToProduct = (productIndex: number) => {
    const updatedData = [...data];
    const item = updatedData[productIndex];

    if (!item.mappedBarcodes) item.mappedBarcodes = [];
    if (!item.mappedBarcodes.includes(unknownBarcode)) {
      item.mappedBarcodes.push(unknownBarcode);
      item.remarks = (item.remarks || "") + ` [關聯條碼: ${unknownBarcode}]`;
    }

    item.actualQty += 1;
    item.diff = item.actualQty - item.bookQty;

    setData(updatedData);
    setLastScanned(item);
    setShowMappingModal(false);
    setUnknownBarcode('');
    setMappingSearch('');

    if (voiceEnabled) audioService.speakMappingSuccess();
    else audioService.playFeedback('success');
    if (aiEnabled) fetchProductAIInfo(item);
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const exportData = data.map(item => ({
      ...(item.originalRow || {}), 
      '實際盤點數量': item.actualQty,
      '手動關聯條碼': item.mappedBarcodes?.join(', ') || '',
      '盤點備註': (item.remarks || "") + (item.actualQty === 0 && item.bookQty > 0 ? ' (未找到)' : '')
    }));
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點報表");
    XLSX.writeFile(wb, `大豐盤點報表_${new Date().toLocaleDateString().replace(/\//g, '')}.xlsx`);
  };

  const unscannedItems = data.filter(i => i.actualQty === 0 && i.bookQty > 0);
  const filteredMapping = data.filter(i => 
    i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || 
    i.name.toLowerCase().includes(mappingSearch.toLowerCase())
  ).slice(0, 50);

  return (
    <div className="min-h-screen flex flex-col items-center p-4 md:p-10 space-y-8 max-w-7xl mx-auto relative">
      <header className="w-full flex flex-col md:flex-row justify-between items-center gap-6 border-b-2 border-slate-100 pb-8">
        <div className="flex items-center space-x-5">
          <div className="bg-slate-900 p-4 rounded-3xl shadow-2xl relative">
            <Building2 className="text-white w-10 h-10" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight leading-none">大豐資訊</h1>
            <p className="text-blue-600 font-bold tracking-widest mt-1 text-sm uppercase">高階實務盤點系統</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => setVoiceEnabled(!voiceEnabled)}
            className={`flex items-center gap-2 px-5 py-4 rounded-2xl font-black transition-all shadow-lg ${
              voiceEnabled ? 'bg-emerald-600 text-white shadow-emerald-200' : 'bg-slate-100 text-slate-400'
            }`}
          >
            {voiceEnabled ? <Volume2 size={20} /> : <VolumeX size={20} />}
            語音報號
          </button>

          <button 
            onClick={() => setAiEnabled(!aiEnabled)}
            className={`flex items-center gap-2 px-5 py-4 rounded-2xl font-black transition-all shadow-lg ${
              aiEnabled ? 'bg-indigo-600 text-white shadow-indigo-200' : 'bg-slate-100 text-slate-400'
            }`}
          >
            <Sparkles size={20} className={aiEnabled ? 'animate-pulse' : ''} />
            AI 輔助
          </button>

          {data.length === 0 ? (
            <label className="flex items-center space-x-3 bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl cursor-pointer transition-all shadow-xl font-black text-lg">
              <FileSpreadsheet size={24} />
              <span>匯入庫存檔</span>
              <input type="file" accept=".csv, .xlsx, .xls" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                  try {
                    const workbook = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const jsonData = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
                    const mapped = (jsonData as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || row['數量'] || row['庫存量']) || 0,
                      actualQty: 0,
