import os
import json
import pandas as pd
from flask import Flask, request, jsonify, send_file, render_template_string
from flask_cors import CORS
from io import BytesIO

app = Flask(__name__)
CORS(app)

# 全域變數存儲目前的盤點資料
# 在實際企業環境中，這裡可以改用 SQLite，但在輕量工具中，記憶體 + 存檔即可
current_inventory = []
raw_df = None

@app.route('/')
def index():
    # 這裡會讀取同目錄下的 index.html (由前端建置產出)
    try:
        with open('index.html', 'r', encoding='utf-8') as f:
            return f.read()
    except FileNotFoundError:
        return "請確保 index.html 存在於同目錄下。"

@app.route('/api/upload', methods=['POST'])
def upload_file():
    global current_inventory, raw_df
    file = request.files.get('file')
    if not file:
        return jsonify({"error": "未收到檔案"}), 400

    try:
        filename = file.filename.lower()
        if filename.endswith('.csv'):
            # 處理可能的多種編碼
            try:
                df = pd.read_csv(file, encoding='utf-8-sig')
            except:
                df = pd.read_csv(file, encoding='cp950')
        else:
            df = pd.read_excel(file)

        # 欄位清理
        df.columns = [str(c).strip() for c in df.columns]
        raw_df = df.copy()

        # 建立標準化結構
        new_data = []
        for _, row in df.iterrows():
            # 容錯處理：尋找可能的欄位名稱
            barcode = str(row.get('條碼編號', row.get('條碼', ''))).strip()
            p_code = str(row.get('產品代號', row.get('代號', ''))).strip()
            name = str(row.get('品名', row.get('名稱', ''))).strip()
            book_qty = float(row.get('期末數量', row.get('庫存量', 0)))

            new_data.append({
                "barcode": barcode,
                "productCode": p_code,
                "name": name,
                "bookQty": book_qty,
                "actualQty": 0,
                "diff": -book_qty,
                "mappedBarcodes": [],
                "remarks": ""
            })

        current_inventory = new_data
        return jsonify({"message": f"成功匯入 {len(new_data)} 筆資料", "count": len(new_data)})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

@app.route('/api/data', methods=['GET'])
def get_data():
    return jsonify(current_inventory)

@app.route('/api/scan', methods=['POST'])
def scan_item():
    global current_inventory
    req = request.json
    code = str(req.get('code', '')).strip()

    found_item = None
    for item in current_inventory:
        if (item['barcode'] == code or 
            item['productCode'] == code or 
            code in item['mappedBarcodes']):

            item['actualQty'] += 1
            item['diff'] = item['actualQty'] - item['bookQty']
            found_item = item
            break

    if found_item:
        return jsonify({"success": True, "item": found_item})
    else:
        return jsonify({"success": False, "message": "查無此條碼"}), 404

@app.route('/api/map', methods=['POST'])
def map_barcode():
    global current_inventory
    req = request.json
    unknown_code = str(req.get('barcode', '')).strip()
    target_pcode = str(req.get('productCode', '')).strip()

    found_item = None
    for item in current_inventory:
        if item['productCode'] == target_pcode:
            if unknown_code not in item['mappedBarcodes']:
                item['mappedBarcodes'].append(unknown_code)
                item['remarks'] += f" [關聯:{unknown_code}]"

            item['actualQty'] += 1
            item['diff'] = item['actualQty'] - item['bookQty']
            found_item = item
            break

    if found_item:
        return jsonify({"success": True, "item": found_item})
    return jsonify({"success": False}), 404

@app.route('/api/export', methods=['GET'])
def export_file():
    if not current_inventory:
        return "無資料可匯出", 400

    df_export = pd.DataFrame(current_inventory)
    # 這裡可以根據原始 DataFrame 合併更多欄位，簡化起見直接輸出結果
    output = BytesIO()
    with pd.ExcelWriter(output, engine='openpyxl') as writer:
        df_export.to_excel(writer, index=False, sheet_name='盤點結果')

    output.seek(0)
    return send_file(
        output, 
        mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        as_attachment=True,
        download_name="大豐盤點結果.xlsx"
    )

if __name__ == '__main__':
    # host='0.0.0.0' 允許區域網路內所有電腦連接
