import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, FileDown, CheckCircle2, Search,
  Building2, FileSpreadsheet, X, Sparkles,
  Volume2, VolumeX, Link, Info
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem, AISearchResult } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v1';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 設定狀態
  const [aiEnabled, setAiEnabled] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(true); 
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AISearchResult | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { items, config } = JSON.parse(saved);
        if (items?.length > 0) {
          setData(items);
          if (config) {
            setAiEnabled(!!config.aiEnabled);
            setVoiceEnabled(config.voiceEnabled !== false);
          }
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      const config = { aiEnabled, voiceEnabled };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, aiEnabled, voiceEnabled]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const fetchProductAIInfo = async (item: InventoryItem) => {
    if (!aiEnabled || !process.env.API_KEY) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `產品「${item.name}」型號「${item.productCode}」的盤點檢查重點，20字內。`;
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
      });
      setAiResult({ text: response.text || "", sources: [] });
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      if (voiceEnabled) audioService.speakSuccess(updatedData[index].name, updatedData[index].actualQty);
      else audioService.playFeedback('success');

      if (aiEnabled) fetchProductAIInfo(updatedData[index]);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setShowMappingModal(true);
      if (voiceEnabled) audioService.speakError();
      else audioService.playFeedback('error');
    }
    setInputValue('');
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-4 select-none">
      {/* 頂部導覽列：輕量化 */}
      <header className="flex justify-between items-center mb-4 px-2">
        <div className="flex items-center gap-4">
          <Building2 className="text-blue-500 w-8 h-8" />
          <h1 className="text-2xl font-black tracking-tighter">大豐資訊 <span className="text-blue-500">LIVE 盤點</span></h1>
        </div>

        <div className="flex items-center gap-2">
           <button onClick={() => setVoiceEnabled(!voiceEnabled)} className={`p-3 rounded-xl transition-all ${voiceEnabled ? 'bg-emerald-600' : 'bg-slate-800 text-slate-500'}`}>
            {voiceEnabled ? <Volume2 size={24} /> : <VolumeX size={24} />}
           </button>
           <button onClick={() => setAiEnabled(!aiEnabled)} className={`p-3 rounded-xl transition-all ${aiEnabled ? 'bg-indigo-600' : 'bg-slate-800 text-slate-500'}`}>
            <Sparkles size={24} />
           </button>
           {data.length === 0 ? (
             <label className="bg-blue-600 hover:bg-blue-700 px-6 py-3 rounded-xl cursor-pointer font-bold flex items-center gap-2 transition-all">
                <FileSpreadsheet size={20} /> 匯入檔案
                <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  const r = new FileReader();
                  r.onload = (ev) => {
                    const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                    setData((json as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || 0),
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量'] || 0),
                      originalRow: row
                    })));
                  };
                  r.readAsArrayBuffer(file);
                }} className="hidden" />
             </label>
           ) : (
             <button onClick={handleExport} className="bg-slate-800 hover:bg-slate-700 px-6 py-3 rounded-xl font-bold flex items-center gap-2 transition-all">
               <FileDown size={20} /> 匯出
             </button>
           )}
        </div>
      </header>

      {/* 掃描區域：超大型輸入框 */}
      <section className={`mb-6 p-2 rounded-3xl transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20' : 'bg-slate-900'}`}>
        <form onSubmit={handleScan} className="relative">
          <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-blue-500 w-10 h-10" />
          <input 
            ref={inputRef}
            type="text" 
            value={inputValue} 
            onChange={(e) => setInputValue(e.target.value)}
            placeholder={data.length > 0 ? "請掃描條碼..." : "請先匯入庫存檔"}
            disabled={data.length === 0}
            className="w-full bg-transparent pl-20 pr-10 py-8 text-6xl font-black text-white outline-none placeholder:text-slate-700"
            autoComplete="off"
          />
        </form>
      </section>

      {/* 主工作區：左右分割 */}
      <main className="flex-1 grid grid-cols-12 gap-6 min-h-0">
        {/* 左側：產品詳情 */}
        <div className="col-span-8 bg-slate-900/50 border border-slate-800 rounded-[3rem] p-10 flex flex-col justify-between overflow-hidden relative">
          {lastScanned ? (
            <div className="animate-in fade-in slide-in-from-left-4 duration-500">
              <div className="flex items-center gap-3 text-emerald-400 font-black text-2xl mb-4">
                <CheckCircle2 size={32} /> 核對完成
              </div>
              <h2 className="text-huge font-black tracking-tighter break-words text-white drop-shadow-2xl">
                {lastScanned.name}
              </h2>
              <div className="mt-8 flex gap-4">
                <div className="bg-slate-800 px-6 py-4 rounded-2xl border border-slate-700">
                  <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-1">代號</p>
                  <p className="text-4xl font-black text-blue-400">{lastScanned.productCode}</p>
                </div>
                <div className="bg-slate-800 px-6 py-4 rounded-2xl border border-slate-700">
                  <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-1">條碼</p>
                  <p className="text-4xl font-black text-slate-300">{lastScanned.barcode || '---'}</p>
                </div>
              </div>
              {aiEnabled && aiResult && (
                <div className="mt-10 p-6 bg-indigo-900/30 border-l-8 border-indigo-500 rounded-r-2xl">
                  <p className="text-2xl font-bold text-indigo-100 flex items-center gap-3">
                    <Info className="text-indigo-400" /> {aiResult.text}
                  </p>
                </div>
              )}
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <Scan size={200} />
              <p className="text-4xl font-black mt-4 uppercase tracking-[1em]">Ready</p>
            </div>
          )}
        </div>

        {/* 右側：數據儀表板 */}
        <div className="col-span-4 flex flex-col gap-6">
          <div className="flex-1 bg-blue-600 rounded-[3rem] flex flex-col items-center justify-center shadow-2xl">
            <span className="text-blue-200 font-black text-xl mb-2 uppercase tracking-widest">目前累計</span>
            <div className="text-huge font-black">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[3rem] flex flex-col items-center justify-center shadow-2xl transition-colors duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-600' : lastScanned.diff === 0 ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
            <span className="font-black text-xl mb-2 uppercase tracking-widest opacity-80">庫存差異</span>
            <div className="text-huge font-black">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態：緊湊型 */}
      <footer className="h-16 mt-6 flex justify-between items-center px-4 bg-slate-900 rounded-2xl border border-slate-800">
        <div className="flex gap-8">
          <div className="flex items-center gap-2"><span className="text-slate-500 font-bold uppercase text-xs">庫存總項</span><span className="text-xl font-black">{data.length}</span></div>
          <div className="flex items-center gap-2"><span className="text-emerald-500 font-bold uppercase text-xs">已盤項數</span><span className="text-xl font-black">{data.filter(i => i.actualQty > 0).length}</span></div>
          <button onClick={() => setShowUnscannedList(true)} className="flex items-center gap-2 group">
            <span className="text-amber-500 font-bold uppercase text-xs">未盤清單</span>
            <span className="text-xl font-black group-hover:underline">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</span>
          </button>
        </div>
        <div className="text-slate-500 font-bold text-xs uppercase tracking-widest">
          大豐資訊盤點系統 V1.0 | 本地作業中
        </div>
      </footer>

      {/* 異常處理模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-xl">
          <div className="bg-white text-slate-950 w-full max-w-4xl rounded-[3rem] overflow-hidden flex flex-col">
            <div className="p-10 bg-red-600 text-white">
              <h3 className="text-5xl font-black mb-2">未登錄條碼: {unknownBarcode}</h3>
              <p className="text-2xl font-bold opacity-80">請從下方選擇對應產品進行關聯</p>
            </div>
            <div className="p-8 border-b">
              <input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="快速搜尋代號或品名..." className="w-full px-8 py-6 text-4xl font-bold bg-slate-100 rounded-3xl outline-none" />
            </div>
            <div className="flex-1 overflow-y-auto max-h-[40vh] p-4">
              {data.filter(i => i.productCode.includes(mappingSearch) || i.name.includes(mappingSearch)).slice(0, 10).map((item, idx) => (
                <button key={idx} onClick={() => {
                  const dIdx = data.findIndex(d => d.productCode === item.productCode);
                  const updated = [...data];
                  updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                  updated[dIdx].actualQty += 1;
                  updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                  setData(updated);
                  setLastScanned(updated[dIdx]);
                  setShowMappingModal(false);
                  audioService.speakMappingSuccess();
                }} className="w-full text-left p-8 hover:bg-blue-600 hover:text-white rounded-3xl transition-all border-b border-slate-100 group flex justify-between items-center">
                  <div>
                    <div className="text-3xl font-black">{item.productCode}</div>
                    <div className="text-xl font-bold opacity-60">{item.name}</div>
                  </div>
                  <Link size={32} />
                </button>
              ))}
            </div>
            <div className="p-8 text-center bg-slate-50">
              <button onClick={() => setShowMappingModal(false)} className="text-slate-400 font-black text-2xl">放棄關聯</button>
            </div>
          </div>
        </div>
      )}

      {/* 未盤清單：全螢幕遮罩 */}
      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/95 flex items-center justify-center p-10">
          <div className="w-full max-w-5xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-5xl font-black text-amber-500">未完成盤點清單</h3>
              <button onClick={() => setShowUnscannedList(false)} className="text-white hover:text-red-500"><X size={64}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-4">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 border-b-4 border-slate-800">
                  <tr className="text-slate-500 text-2xl font-black uppercase">
                    <th className="pb-6">產品代號</th>
                    <th className="pb-6">品名名稱</th>
                    <th className="pb-6 text-right px-6">ERP 庫存</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="text-white">
                      <td className="py-8 text-4xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-8 text-3xl font-bold">{item.name}</td>
                      <td className="py-8 text-4xl font-black text-right px-6 text-slate-500">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

