export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  Scan, FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X, Sparkles,
  Volume2, VolumeX, Link, Info, Package, ClipboardCheck, AlertCircle
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { GoogleGenAI } from "@google/genai";
import { InventoryItem, AISearchResult } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v1';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 設定狀態
  const [aiEnabled, setAiEnabled] = useState(false);
  const [voiceEnabled, setVoiceEnabled] = useState(true); 
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AISearchResult | null>(null);

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { items, config } = JSON.parse(saved);
        if (items?.length > 0) {
          setData(items);
          if (config) {
            setAiEnabled(!!config.aiEnabled);
            setVoiceEnabled(config.voiceEnabled !== false);
          }
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0) {
      const config = { aiEnabled, voiceEnabled };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, aiEnabled, voiceEnabled]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const fetchProductAIInfo = async (item: InventoryItem) => {
    if (!aiEnabled || !process.env.API_KEY) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `產品「${item.name}」型號「${item.productCode}」的盤點檢查重點，20字內。`;
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
      });
      setAiResult({ text: response.text || "", sources: [] });
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      if (voiceEnabled) audioService.speakSuccess(updatedData[index].name, updatedData[index].actualQty);
      else audioService.playFeedback('success');

      if (aiEnabled) fetchProductAIInfo(updatedData[index]);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setShowMappingModal(true);
      if (voiceEnabled) audioService.speakError();
      else audioService.playFeedback('error');
    }
    setInputValue('');
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 頂部導覽列 */}
      <header className="flex justify-between items-center mb-6 px-2">
        <div className="flex items-center gap-4">
          <ScanBarcode className="text-blue-500 w-12 h-12" />
          <h1 className="text-4xl font-black tracking-tighter">大豐資訊盤點系統</h1>
        </div>

        <div className="flex items-center gap-4">
           <button onClick={() => setVoiceEnabled(!voiceEnabled)} className={`p-4 rounded-2xl transition-all ${voiceEnabled ? 'bg-emerald-600' : 'bg-slate-800 text-slate-500'}`}>
            {voiceEnabled ? <Volume2 size={28} /> : <VolumeX size={28} />}
           </button>
           <button onClick={() => setAiEnabled(!aiEnabled)} className={`p-4 rounded-2xl transition-all ${aiEnabled ? 'bg-indigo-600' : 'bg-slate-800 text-slate-500'}`}>
            <Sparkles size={28} />
           </button>
           {data.length === 0 ? (
             <label className="bg-blue-600 hover:bg-blue-700 px-8 py-4 rounded-2xl cursor-pointer text-xl font-bold flex items-center gap-3 transition-all">
                <FileSpreadsheet size={24} /> 匯入檔案
                <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  const r = new FileReader();
                  r.onload = (ev) => {
                    const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                    setData((json as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || 0),
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量'] || 0),
                      originalRow: row
                    })));
                  };
                  r.readAsArrayBuffer(file);
                }} className="hidden" />
             </label>
           ) : (
             <button onClick={handleExport} className="bg-slate-800 hover:bg-slate-700 px-8 py-4 rounded-2xl text-xl font-bold flex items-center gap-3 transition-all">
               <FileDown size={24} /> 匯出
             </button>
           )}
        </div>
      </header>

      {/* 掃描區域 */}
      <section className={`mb-6 p-2 rounded-[2.5rem] transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border border-slate-800'}`}>
        <form onSubmit={handleScan} className="relative">
          <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
          <input 
            ref={inputRef}
            type="text" 
            value={inputValue} 
            onChange={(e) => setInputValue(e.target.value)}
            placeholder={data.length > 0 ? "請掃描條碼..." : "請先匯入庫存檔"}
            disabled={data.length === 0}
            className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
            autoComplete="off"
          />
        </form>
      </section>

      {/* 主工作區：重新設計為等分橫條 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              {/* 第一橫條：品名 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              {/* 第二橫條：產品代號 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              {/* 第三橫條：條碼編號 */}
              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 uppercase tracking-[1em]">SYSTEM READY</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">本次累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態列 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤項數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">未盤清單 (點擊)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-5xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-16 bg-red-600 text-white">
              <h3 className="text-6xl font-black mb-4 tracking-tighter">未登錄條碼: {unknownBarcode}</h3>
              <p className="text-3xl font-bold opacity-80">查無此商品，請在下方選擇正確品項進行「人工關聯」</p>
            </div>
            <div className="p-12 border-b-2 border-slate-100">
              <input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入產品代號或名稱進行過濾..." className="w-full px-10 py-8 text-5xl font-black bg-slate-50 rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500" />
            </div>
            <div className="flex-1 overflow-y-auto max-h-[40vh] p-8">
