                }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                  <div>
                    <div className="text-4xl font-black mb-2">{item.productCode}</div>
                    <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                  </div>
                  <Link size={48} />
