  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
          if (parsed.config) {
            setLocationEnabled(!!parsed.config.locationEnabled);
            setCurrentLocation(parsed.config.currentLocation || '');
          }
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || locationEnabled) {
      const config = { locationEnabled, currentLocation };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
      // 更新儲位 (如果已啟用且有輸入)
      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess(updatedData[index].name, updatedData[index].actualQty);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '儲位': i.location || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 頂部導覽列 */}
      <header className="flex justify-between items-center mb-6 px-2">
        <div className="flex items-center gap-4">
          <ScanBarcode className="text-blue-500 w-12 h-12" />
          <h1 className="text-4xl font-black tracking-tighter">大豐資訊盤點系統</h1>
        </div>

        <div className="flex items-center gap-4">
           {/* 儲位開關按鈕 */}
           <button 
             onClick={() => setLocationEnabled(!locationEnabled)} 
             className={`flex items-center gap-3 px-6 py-4 rounded-2xl transition-all font-bold text-xl ${locationEnabled ? 'bg-amber-600 text-white shadow-lg' : 'bg-slate-800 text-slate-500'}`}
             title={locationEnabled ? "已開啟儲位輸入" : "已關閉儲位輸入"}
           >
            <MapPin size={28} />
            {locationEnabled ? "儲位模式: ON" : "儲位模式: OFF"}
           </button>

           {data.length === 0 ? (
             <label className="bg-blue-600 hover:bg-blue-700 px-8 py-4 rounded-2xl cursor-pointer text-xl font-bold flex items-center gap-3 transition-all shadow-lg">
                <FileSpreadsheet size={24} /> 匯入檔案
                <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  const r = new FileReader();
                  r.onload = (ev) => {
                    const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                    setData((json as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || 0),
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量'] || 0),
                      originalRow: row
                    })));
                  };
                  r.readAsArrayBuffer(file);
                }} className="hidden" />
             </label>
           ) : (
             <button onClick={handleExport} className="bg-slate-800 hover:bg-slate-700 px-8 py-4 rounded-2xl text-xl font-bold flex items-center gap-3 transition-all border border-slate-700">
               <FileDown size={24} /> 匯出報告
             </button>
           )}
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border border-slate-800'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描條碼..." : "請先匯入庫存檔"}
              disabled={data.length === 0}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10 animate-in slide-in-from-right-10 duration-500">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
              placeholder="請輸入儲位..."
              className="bg-transparent text-6xl font-black text-amber-400 outline-none placeholder:text-amber-900/50"
              autoComplete="off"
            />
          </section>
        )}
      </div>

      {/* 主工作區 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              {/* 第一橫條：品名 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              {/* 第二橫條：產品代號 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                  {lastScanned.location && (
                    <div className="ml-auto flex items-center gap-3 text-amber-500 font-black text-2xl bg-amber-500/10 px-6 py-2 rounded-full border border-amber-500/30">
                      <MapPin size={24} /> {lastScanned.location}
                    </div>
                  )}
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              {/* 第三橫條：條碼編號 */}
              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em]">盤點系統就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">本次累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態列 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤項數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group shadow-xl"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">未盤清單 (點擊)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 模態視窗：增加手動新增選項 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇要「關聯至現出品項」或「建立全新商品」</p>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => setIsCreatingNew(false)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  搜尋關聯
                </button>
                <button 
                  onClick={() => setIsCreatingNew(true)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  建立新商品
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                /* 手動建立表單 */
                <div className="flex-1 p-20 bg-slate-50 animate-in fade-in duration-300">
                  <div className="max-w-4xl mx-auto space-y-12">
                    <div className="grid grid-cols-2 gap-8">
                       <div>
                        <label className="block text-2xl font-black text-slate-400 uppercase tracking-widest mb-4">條碼編號</label>
                        <input disabled type="text" value={unknownBarcode} className="w-full px-10 py-6 text-4xl font-black bg-slate-200 text-slate-500 rounded-3xl outline-none" />
                      </div>
                      <div>
                        <label className="block text-2xl font-black text-amber-600 uppercase tracking-widest mb-4">目前儲位 {locationEnabled ? '(將同步存入)' : '(未啟用)'}</label>
                        <input disabled type="text" value={locationEnabled ? currentLocation : '---'} className="w-full px-10 py-6 text-4xl font-black bg-amber-50 text-amber-700 rounded-3xl outline-none" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">產品代號 / 型號 (必填)</label>
                      <input 
                        autoFocus 
                        type="text" 
                        value={newProductCode} 
                        onChange={(e) => setNewProductCode(e.target.value)}
                        placeholder="例如: ABC-12345" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">品名名稱 (必填)</label>
                      <input 
                        type="text" 
                        value={newProductName} 
                        onChange={(e) => setNewProductName(e.target.value)}
                        placeholder="例如: 大豐智慧型路由器" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <button 
                      onClick={handleCreateNewItem}
                      className="w-full py-10 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl text-5xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6"
                    >
                      <PlusCircle size={48} /> 確認新增並開始盤點
                    </button>
                  </div>
                </div>
              ) : (
                /* 搜尋關聯清單 */
                <div className="flex-1 flex flex-col animate-in fade-in duration-300">
                  <div className="p-12 border-b-2 border-slate-100">
                    <input 
                      autoFocus 
                      type="text" 
                      value={mappingSearch} 
                      onChange={(e) => setMappingSearch(e.target.value)} 
                      placeholder="輸入產品代號或名稱進行過濾..." 
                      className="w-full px-10 py-8 text-5xl font-black bg-slate-50 rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500" 
                    />
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 10).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        // 更新儲位
                        if (locationEnabled && currentLocation.trim()) {
                          updated[dIdx].location = currentLocation.trim();
                        }

                        setData(updated);
                        setLastScanned(updated[dIdx]);
                        setShowMappingModal(false);
                        audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div>
                          <div className="text-4xl font-black mb-2">{item.productCode}</div>
                          <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                        </div>
                        <Link size={48} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-12 text-center bg-slate-50 border-t border-slate-200">
              <button onClick={() => setShowMappingModal(false)} className="px-16 py-6 rounded-full bg-slate-200 text-slate-500 font-black text-3xl hover:bg-slate-300">取消並關閉</button>
            </div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-6">
                 <AlertCircle size={64} className="text-amber-500" />
                 <h3 className="text-7xl font-black text-white">待盤點清單 <span className="text-amber-500 ml-4">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length} 項</span></h3>
              </div>
              <button onClick={() => setShowUnscannedList(false)} className="p-4 rounded-full hover:bg-white/10 text-white transition-all"><X size={80}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-6 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10">
                  <tr className="text-slate-500 text-3xl font-black uppercase border-b-8 border-slate-900">
                    <th className="pb-8 pl-4">產品代號</th>
                    <th className="pb-8">品名名稱</th>
                    <th className="pb-8 text-right pr-10">ERP 庫存</th>
                  </tr>
                </thead>
                <tbody className="divide-y-8 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/50 hover:bg-slate-800 transition-colors">
                      <td className="py-10 pl-8 text-5xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-10 text-4xl font-bold text-white">{item.name}</td>
                      <td className="py-10 text-5xl font-black text-right pr-10 text-slate-400">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface InventoryItem {
  barcode: string;      // 條碼編號
  productCode: string;  // 產品代號
  name: string;         // 品名
  bookQty: number;      // 期末數量 (ERP)
  actualQty: number;    // 盤點數量
  diff: number;         // 差異數
  location?: string;    // 儲位資訊
  scanTime?: string;    // 掃描日期時間
  originalRow?: any;    // 原始 Excel 完整列資料
  mappedBarcodes?: string[]; // 記錄額外關聯到此項目的錯誤條碼
  remarks?: string;     // 額外備註
}

export interface ScanResult {
  success: boolean;
  message: string;
  item?: InventoryItem;
}

export interface AISearchResult {
  text: string;
  sources: { title: string; uri: string }[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v3';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 儲位與時間功能狀態
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
          if (parsed.config) {
            setLocationEnabled(!!parsed.config.locationEnabled);
            setCurrentLocation(parsed.config.currentLocation || '');
            setTimeFormat(parsed.config.timeFormat || 'off');
          }
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || locationEnabled || timeFormat !== 'off') {
      const config = { locationEnabled, currentLocation, timeFormat };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;

    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      // 更新儲位
      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }
      // 更新時間
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess('', 0); // 僅播放嗶聲
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 頂部導覽列 */}
      <header className="flex justify-between items-center mb-6 px-2">
        <div className="flex items-center gap-4">
          <ScanBarcode className="text-blue-500 w-12 h-12" />
          <h1 className="text-4xl font-black tracking-tighter">大豐資訊盤點系統</h1>
        </div>

        <div className="flex items-center gap-4">
           {/* 時間紀錄格式切換 */}
           <div className="flex bg-slate-800 p-1 rounded-2xl border border-slate-700">
             <button 
                onClick={() => setTimeFormat('off')}
                className={`px-4 py-2 rounded-xl text-lg font-bold transition-all ${timeFormat === 'off' ? 'bg-slate-600 text-white' : 'text-slate-500'}`}
             >
               關閉時間
             </button>
             <button 
                onClick={() => setTimeFormat('datetime')}
                className={`px-4 py-2 rounded-xl text-lg font-bold transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
             >
               <Clock size={18} /> 年月日時分
             </button>
             <button 
                onClick={() => setTimeFormat('date')}
                className={`px-4 py-2 rounded-xl text-lg font-bold transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}
             >
               年月日
             </button>
           </div>

           {/* 儲位開關按鈕 */}
           <button 
             onClick={() => setLocationEnabled(!locationEnabled)} 
             className={`flex items-center gap-3 px-6 py-4 rounded-2xl transition-all font-bold text-xl ${locationEnabled ? 'bg-amber-600 text-white shadow-lg' : 'bg-slate-800 text-slate-500'}`}
           >
            <MapPin size={28} />
            {locationEnabled ? "儲位: ON" : "儲位: OFF"}
           </button>

           {data.length === 0 ? (
             <label className="bg-blue-600 hover:bg-blue-700 px-8 py-4 rounded-2xl cursor-pointer text-xl font-bold flex items-center gap-3 transition-all shadow-lg">
                <FileSpreadsheet size={24} /> 匯入檔案
                <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (!file) return;
                  const r = new FileReader();
                  r.onload = (ev) => {
                    const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                    const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                    setData((json as any[]).map(row => ({
                      barcode: String(row['條碼編號'] || '').trim(),
                      productCode: String(row['產品代號'] || '').trim(),
                      name: String(row['品名'] || row['名稱'] || '').trim(),
                      bookQty: parseFloat(row['期末數量'] || 0),
                      actualQty: 0,
                      diff: -parseFloat(row['期末數量'] || 0),
                      originalRow: row
                    })));
                  };
                  r.readAsArrayBuffer(file);
                }} className="hidden" />
             </label>
           ) : (
             <button onClick={handleExport} className="bg-slate-800 hover:bg-slate-700 px-8 py-4 rounded-2xl text-xl font-bold flex items-center gap-3 transition-all border border-slate-700 shadow-md">
               <FileDown size={24} /> 匯出報告
             </button>
           )}
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border border-slate-800'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描條碼..." : "請先匯入庫存檔"}
              disabled={data.length === 0}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10 animate-in slide-in-from-right-10 duration-500">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
              placeholder="請輸入儲位..."
              className="bg-transparent text-6xl font-black text-amber-400 outline-none placeholder:text-amber-900/50"
              autoComplete="off"
            />
          </section>
        )}
      </div>

      {/* 主工作區 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              {/* 第一橫條：品名 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              {/* 第二橫條：產品代號 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-3">
                    {lastScanned.scanTime && (
                      <div className="flex items-center gap-3 text-indigo-400 font-black text-2xl bg-indigo-500/10 px-6 py-2 rounded-full border border-indigo-500/30">
                        <Clock size={24} /> {lastScanned.scanTime}
                      </div>
                    )}
                    {lastScanned.location && (
                      <div className="flex items-center gap-3 text-amber-500 font-black text-2xl bg-amber-500/10 px-6 py-2 rounded-full border border-amber-500/30">
                        <MapPin size={24} /> {lastScanned.location}
                      </div>
                    )}
                  </div>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              {/* 第三橫條：條碼編號 */}
              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em]">盤點系統就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">本次累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態列 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤項數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group shadow-xl"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">未盤清單 (點擊)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇要「關聯至現出品項」或「建立全新商品」</p>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => setIsCreatingNew(false)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  搜尋關聯
                </button>
                <button 
                  onClick={() => setIsCreatingNew(true)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  建立新商品
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50 animate-in fade-in duration-300">
                  <div className="max-w-4xl mx-auto space-y-12">
                    <div className="grid grid-cols-2 gap-8">
                       <div>
                        <label className="block text-2xl font-black text-slate-400 uppercase tracking-widest mb-4">條碼編號</label>
                        <input disabled type="text" value={unknownBarcode} className="w-full px-10 py-6 text-4xl font-black bg-slate-200 text-slate-500 rounded-3xl outline-none" />
                      </div>
                      <div>
                        <label className="block text-2xl font-black text-amber-600 uppercase tracking-widest mb-4">目前儲位 {locationEnabled ? '(將同步存入)' : '(未啟用)'}</label>
                        <input disabled type="text" value={locationEnabled ? currentLocation : '---'} className="w-full px-10 py-6 text-4xl font-black bg-amber-50 text-amber-700 rounded-3xl outline-none" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">產品代號 / 型號 (必填)</label>
                      <input 
                        autoFocus 
                        type="text" 
                        value={newProductCode} 
                        onChange={(e) => setNewProductCode(e.target.value)}
                        placeholder="例如: ABC-12345" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">品名名稱 (必填)</label>
                      <input 
                        type="text" 
                        value={newProductName} 
                        onChange={(e) => setNewProductName(e.target.value)}
                        placeholder="例如: 大豐智慧型路由器" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <button 
                      onClick={handleCreateNewItem}
                      className="w-full py-10 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl text-5xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6"
                    >
                      <PlusCircle size={48} /> 確認新增並開始盤點
                    </button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col animate-in fade-in duration-300">
                  <div className="p-12 border-b-2 border-slate-100">
                    <input 
                      autoFocus 
                      type="text" 
                      value={mappingSearch} 
                      onChange={(e) => setMappingSearch(e.target.value)} 
                      placeholder="輸入產品代號或名稱進行過濾..." 
                      className="w-full px-10 py-8 text-5xl font-black bg-slate-50 rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500" 
                    />
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 10).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;

                        if (locationEnabled && currentLocation.trim()) {
                          updated[dIdx].location = currentLocation.trim();
                        }
                        const t = getFormattedTime();
                        if (t) updated[dIdx].scanTime = t;

                        setData(updated);
                        setLastScanned(updated[dIdx]);
                        setShowMappingModal(false);
                        audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div>
                          <div className="text-4xl font-black mb-2">{item.productCode}</div>
                          <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                        </div>
                        <Link size={48} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-12 text-center bg-slate-50 border-t border-slate-200">
              <button onClick={() => setShowMappingModal(false)} className="px-16 py-6 rounded-full bg-slate-200 text-slate-500 font-black text-3xl hover:bg-slate-300">取消並關閉</button>
            </div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-6">
                 <AlertCircle size={64} className="text-amber-500" />
                 <h3 className="text-7xl font-black text-white">待盤點清單 <span className="text-amber-500 ml-4">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length} 項</span></h3>
              </div>
              <button onClick={() => setShowUnscannedList(false)} className="p-4 rounded-full hover:bg-white/10 text-white transition-all"><X size={80}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-6 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10">
                  <tr className="text-slate-500 text-3xl font-black uppercase border-b-8 border-slate-900">
                    <th className="pb-8 pl-4">產品代號</th>
                    <th className="pb-8">品名名稱</th>
                    <th className="pb-8 text-right pr-10">ERP 庫存</th>
                  </tr>
                </thead>
                <tbody className="divide-y-8 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/50 hover:bg-slate-800 transition-colors">
                      <td className="py-10 pl-8 text-5xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-10 text-4xl font-bold text-white">{item.name}</td>
                      <td className="py-10 text-5xl font-black text-right pr-10 text-slate-400">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v3';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 儲位與時間功能狀態
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
          if (parsed.config) {
            setLocationEnabled(!!parsed.config.locationEnabled);
            setCurrentLocation(parsed.config.currentLocation || '');
            setTimeFormat(parsed.config.timeFormat || 'off');
          }
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || locationEnabled || timeFormat !== 'off') {
      const config = { locationEnabled, currentLocation, timeFormat };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;

    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 標題列：左側為作業功能流，右側為系統標題 */}
      <header className="flex justify-between items-center mb-6 px-2">

        {/* 左側：作業順序 (1.匯入 -> 2.設定 -> 3.匯出) */}
        <div className="flex items-center gap-6">

          {/* 1. 匯入資料區 */}
          <div className="flex items-center gap-3">
            <label className={`flex items-center gap-3 px-6 py-4 rounded-2xl cursor-pointer text-xl font-bold transition-all shadow-lg ${data.length === 0 ? 'bg-blue-600 hover:bg-blue-700 animate-pulse' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
               <FileSpreadsheet size={24} /> 
               {data.length === 0 ? "1. 匯入庫存清冊" : "重新匯入"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0];
                 if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="h-10 w-px bg-slate-800" /> {/* 分隔線 */}

          {/* 2. 作業設定區 */}
          <div className="flex items-center gap-4 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-800">
            {/* 時間模式 */}
            <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800">
              <button onClick={() => setTimeFormat('off')} className={`px-4 py-2 rounded-lg text-lg font-bold transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white shadow' : 'text-slate-600'}`}>時間關閉</button>
              <button onClick={() => setTimeFormat('datetime')} className={`px-4 py-2 rounded-lg text-lg font-bold transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={16} />年月日時分</button>
              <button onClick={() => setTimeFormat('date')} className={`px-4 py-2 rounded-lg text-lg font-bold transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>年月日</button>
            </div>

            {/* 儲位開關 */}
            <button 
              onClick={() => setLocationEnabled(!locationEnabled)} 
              className={`flex items-center gap-3 px-6 py-3 rounded-xl transition-all font-bold text-lg ${locationEnabled ? 'bg-amber-600 text-white shadow-lg' : 'bg-slate-950 text-slate-600 border border-slate-800'}`}
            >
             <MapPin size={22} />
             {locationEnabled ? "儲位紀錄: ON" : "儲位紀錄: OFF"}
            </button>
          </div>

          <div className="h-10 w-px bg-slate-800" /> {/* 分隔線 */}

          {/* 3. 匯出結果區 */}
          <button 
            onClick={handleExport} 
            disabled={data.length === 0}
            className={`flex items-center gap-3 px-8 py-4 rounded-2xl text-xl font-bold transition-all shadow-md ${data.length > 0 ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-slate-800'}`}
          >
            <FileDown size={24} /> 匯出報告
          </button>
        </div>

        {/* 右側：系統標題 */}
        <div className="flex items-center gap-5">
          <div className="text-right">
            <h1 className="text-4xl font-black tracking-tighter text-white">大豐資訊盤點系統</h1>
            <p className="text-slate-500 font-bold text-sm tracking-[0.2em] uppercase">Inventory Control System</p>
          </div>
          <div className="bg-blue-600 p-3 rounded-2xl shadow-[0_0_20px_rgba(37,99,235,0.4)]">
            <ScanBarcode className="text-white w-10 h-10" />
          </div>
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border border-slate-800'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描條碼..." : "請先點擊左上方匯入檔案"}
              disabled={data.length === 0}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10 animate-in slide-in-from-right-10 duration-500">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
              placeholder="請輸入儲位..."
              className="bg-transparent text-6xl font-black text-amber-400 outline-none placeholder:text-amber-900/50"
              autoComplete="off"
            />
          </section>
        )}
      </div>

      {/* 主工作區 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-3">
                    {lastScanned.scanTime && (
                      <div className="flex items-center gap-3 text-indigo-400 font-black text-2xl bg-indigo-500/10 px-6 py-2 rounded-full border border-indigo-500/30">
                        <Clock size={24} /> {lastScanned.scanTime}
                      </div>
                    )}
                    {lastScanned.location && (
                      <div className="flex items-center gap-3 text-amber-500 font-black text-2xl bg-amber-500/10 px-6 py-2 rounded-full border border-amber-500/30">
                        <MapPin size={24} /> {lastScanned.location}
                      </div>
                    )}
                  </div>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em]">盤點系統就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">本次累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態列 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤項數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group shadow-xl"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">未盤清單 (點擊)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇要「關聯至現出品項」或「建立全新商品」</p>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => setIsCreatingNew(false)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  搜尋關聯
                </button>
                <button 
                  onClick={() => setIsCreatingNew(true)} 
                  className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}
                >
                  建立新商品
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50 animate-in fade-in duration-300">
                  <div className="max-w-4xl mx-auto space-y-12">
                    <div className="grid grid-cols-2 gap-8">
                       <div>
                        <label className="block text-2xl font-black text-slate-400 uppercase tracking-widest mb-4">條碼編號</label>
                        <input disabled type="text" value={unknownBarcode} className="w-full px-10 py-6 text-4xl font-black bg-slate-200 text-slate-500 rounded-3xl outline-none" />
                      </div>
                      <div>
                        <label className="block text-2xl font-black text-amber-600 uppercase tracking-widest mb-4">目前儲位 {locationEnabled ? '(將同步存入)' : '(未啟用)'}</label>
                        <input disabled type="text" value={locationEnabled ? currentLocation : '---'} className="w-full px-10 py-6 text-4xl font-black bg-amber-50 text-amber-700 rounded-3xl outline-none" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">產品代號 / 型號 (必填)</label>
                      <input 
                        autoFocus 
                        type="text" 
                        value={newProductCode} 
                        onChange={(e) => setNewProductCode(e.target.value)}
                        placeholder="例如: ABC-12345" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">品名名稱 (必填)</label>
                      <input 
                        type="text" 
                        value={newProductName} 
                        onChange={(e) => setNewProductName(e.target.value)}
                        placeholder="例如: 大豐智慧型路由器" 
                        className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" 
                      />
                    </div>
                    <button 
                      onClick={handleCreateNewItem}
                      className="w-full py-10 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl text-5xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6"
                    >
                      <PlusCircle size={48} /> 確認新增並開始盤點
                    </button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col animate-in fade-in duration-300">
                  <div className="p-12 border-b-2 border-slate-100">
                    <input 
                      autoFocus 
                      type="text" 
                      value={mappingSearch} 
                      onChange={(e) => setMappingSearch(e.target.value)} 
                      placeholder="輸入產品代號或名稱進行過濾..." 
                      className="w-full px-10 py-8 text-5xl font-black bg-slate-50 rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500" 
                    />
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 10).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;

                        if (locationEnabled && currentLocation.trim()) {
                          updated[dIdx].location = currentLocation.trim();
                        }
                        const t = getFormattedTime();
                        if (t) updated[dIdx].scanTime = t;

                        setData(updated);
                        setLastScanned(updated[dIdx]);
                        setShowMappingModal(false);
                        audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div>
                          <div className="text-4xl font-black mb-2">{item.productCode}</div>
                          <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                        </div>
                        <Link size={48} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-12 text-center bg-slate-50 border-t border-slate-200">
              <button onClick={() => setShowMappingModal(false)} className="px-16 py-6 rounded-full bg-slate-200 text-slate-500 font-black text-3xl hover:bg-slate-300">取消並關閉</button>
            </div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-6">
                 <AlertCircle size={64} className="text-amber-500" />
                 <h3 className="text-7xl font-black text-white">待盤點清單 <span className="text-amber-500 ml-4">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length} 項</span></h3>
              </div>
              <button onClick={() => setShowUnscannedList(false)} className="p-4 rounded-full hover:bg-white/10 text-white transition-all"><X size={80}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-6 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10">
                  <tr className="text-slate-500 text-3xl font-black uppercase border-b-8 border-slate-900">
                    <th className="pb-8 pl-4">產品代號</th>
                    <th className="pb-8">品名名稱</th>
                    <th className="pb-8 text-right pr-10">ERP 庫存</th>
                  </tr>
                </thead>
                <tbody className="divide-y-8 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/50 hover:bg-slate-800 transition-colors">
                      <td className="py-10 pl-8 text-5xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-10 text-4xl font-bold text-white">{item.name}</td>
                      <td className="py-10 text-5xl font-black text-right pr-10 text-slate-400">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export interface InventoryItem {
  barcode: string;      // 條碼編號
  productCode: string;  // 產品代號
  name: string;         // 品名
  bookQty: number;      // 期末數量 (ERP)
  actualQty: number;    // 盤點數量
  diff: number;         // 差異數
  location?: string;    // 儲位資訊
  scanTime?: string;    // 掃描日期時間
  operator?: string;    // 作業員
  originalRow?: any;    // 原始 Excel 完整列資料
  mappedBarcodes?: string[]; // 記錄額外關聯到此項目的錯誤條碼
  remarks?: string;     // 額外備註
}

export interface ScanResult {
  success: boolean;
  message: string;
  item?: InventoryItem;
}

export interface AISearchResult {
  text: string;
  sources: { title: string; uri: string }[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v4';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 作業資訊狀態
  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
        }
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off') {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;

    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      // 更新作業資訊
      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 標題列：左側為 SOP 流程排列，右側為系統標題 */}
      <header className="flex justify-between items-center mb-6 px-2">

        {/* 左側：按作業 SOP 順序排列 */}
        <div className="flex items-center gap-6">

          {/* STEP 1: 資料準備 */}
          <div className="group relative">
            <label className={`flex items-center gap-3 px-5 py-4 rounded-2xl cursor-pointer text-lg font-bold transition-all shadow-lg ${data.length === 0 ? 'bg-blue-600 hover:bg-blue-700 animate-pulse' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}>
               <FileSpreadsheet size={20} /> 
               {data.length === 0 ? "1. 匯入清冊" : "重匯清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0];
                 if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="h-8 w-px bg-slate-800" />

          {/* STEP 2: 作業員登錄 */}
          <div className="flex items-center gap-3 bg-slate-900 border border-slate-800 p-1.5 rounded-2xl">
            <div className="pl-4 text-blue-500"><User size={20} /></div>
            <input 
              type="text"
              value={operatorName}
              onChange={(e) => setOperatorName(e.target.value)}
              placeholder="2. 輸入作業員"
              className="bg-transparent text-lg font-bold outline-none placeholder:text-slate-700 w-36 py-2"
            />
          </div>

          <div className="h-8 w-px bg-slate-800" />

          {/* STEP 3: 模式設定 */}
          <div className="flex items-center gap-4 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-800">
            {/* 時間模式切換 */}
            <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800">
              <button onClick={() => setTimeFormat('off')} className={`px-3 py-1.5 rounded-lg text-sm font-bold transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white shadow' : 'text-slate-600'}`}>時間 OFF</button>
              <button onClick={() => setTimeFormat('datetime')} className={`px-3 py-1.5 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={14} />年月日時分</button>
              <button onClick={() => setTimeFormat('date')} className={`px-3 py-1.5 rounded-lg text-sm font-bold transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>年月日</button>
            </div>

            {/* 儲位開關 */}
            <button 
              onClick={() => setLocationEnabled(!locationEnabled)} 
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl transition-all font-bold text-sm ${locationEnabled ? 'bg-amber-600 text-white shadow-lg' : 'bg-slate-950 text-slate-600 border border-slate-800'}`}
            >
             <MapPin size={18} />
             {locationEnabled ? "儲位: ON" : "儲位: OFF"}
            </button>
          </div>

          <div className="h-8 w-px bg-slate-800" />

          {/* STEP 4: 匯出結果 */}
          <button 
            onClick={handleExport} 
            disabled={data.length === 0}
            className={`flex items-center gap-2 px-6 py-4 rounded-2xl text-lg font-bold transition-all shadow-md ${data.length > 0 ? 'bg-emerald-600 hover:bg-emerald-700 text-white' : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-slate-800'}`}
          >
            <FileDown size={20} /> 4. 匯出報告
          </button>
        </div>

        {/* 右側：系統資訊 */}
        <div className="flex items-center gap-4">
          <div className="text-right">
            <h1 className="text-3xl font-black tracking-tighter text-white">大豐資訊盤點系統</h1>
            <p className="text-slate-600 font-bold text-[10px] tracking-[0.2em] uppercase">Inventory Solution v4</p>
          </div>
          <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg">
            <ScanBarcode className="text-white w-8 h-8" />
          </div>
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 ${isSuccess ? 'bg-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border border-slate-800'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描條碼..." : "請先完成步驟 1 匯入清冊"}
              disabled={data.length === 0}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10 animate-in slide-in-from-right-10 duration-500">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
              placeholder="輸入儲位..."
              className="bg-transparent text-6xl font-black text-amber-400 outline-none placeholder:text-amber-900/50"
              autoComplete="off"
            />
          </section>
        )}
      </div>

      {/* 主工作區 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-3">
                    {lastScanned.operator && (
                      <div className="flex items-center gap-3 text-blue-400 font-black text-2xl bg-blue-500/10 px-6 py-2 rounded-full border border-blue-500/30">
                        <User size={24} /> {lastScanned.operator}
                      </div>
                    )}
                    {lastScanned.scanTime && (
                      <div className="flex items-center gap-3 text-indigo-400 font-black text-2xl bg-indigo-500/10 px-6 py-2 rounded-full border border-indigo-500/30">
                        <Clock size={24} /> {lastScanned.scanTime}
                      </div>
                    )}
                    {lastScanned.location && (
                      <div className="flex items-center gap-3 text-amber-500 font-black text-2xl bg-amber-500/10 px-6 py-2 rounded-full border border-amber-500/30">
                        <MapPin size={24} /> {lastScanned.location}
                      </div>
                    )}
                  </div>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em]">盤點系統就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">本次累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部狀態列 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤項數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group shadow-xl"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">未盤清單 (點擊)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇要「關聯至現出品項」或「建立全新商品」</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>建立新商品</button>
              </div>
            </div>

            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50 animate-in fade-in duration-300">
                  <div className="max-w-4xl mx-auto space-y-12">
                    <div className="grid grid-cols-3 gap-8">
                      <div>
                        <label className="block text-2xl font-black text-slate-400 uppercase tracking-widest mb-4">條碼編號</label>
                        <input disabled type="text" value={unknownBarcode} className="w-full px-10 py-6 text-4xl font-black bg-slate-200 text-slate-500 rounded-3xl outline-none" />
                      </div>
                      <div>
                        <label className="block text-2xl font-black text-blue-600 uppercase tracking-widest mb-4">盤點人</label>
                        <input disabled type="text" value={operatorName || '未設定'} className="w-full px-10 py-6 text-4xl font-black bg-blue-50 text-blue-700 rounded-3xl outline-none" />
                      </div>
                      <div>
                        <label className="block text-2xl font-black text-amber-600 uppercase tracking-widest mb-4">目前儲位</label>
                        <input disabled type="text" value={locationEnabled ? currentLocation : '未開啟'} className="w-full px-10 py-6 text-4xl font-black bg-amber-50 text-amber-700 rounded-3xl outline-none" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">產品代號 / 型號 (必填)</label>
                      <input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="例如: ABC-12345" className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" />
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">品名名稱 (必填)</label>
                      <input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="例如: 大豐智慧型路由器" className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" />
                    </div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl text-5xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6"><PlusCircle size={48} /> 確認新增並開始盤點</button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col animate-in fade-in duration-300">
                  <div className="p-12 border-b-2 border-slate-100">
                    <input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="搜尋產品代號或名稱進行關聯..." className="w-full px-10 py-8 text-5xl font-black bg-slate-50 rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500" />
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 10).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;

                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime();
                        if (t) updated[dIdx].scanTime = t;

                        setData(updated);
                        setLastScanned(updated[dIdx]);
                        setShowMappingModal(false);
                        audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div>
                          <div className="text-4xl font-black mb-2">{item.productCode}</div>
                          <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                        </div>
                        <Link size={48} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-12 text-center bg-slate-50 border-t border-slate-200">
              <button onClick={() => setShowMappingModal(false)} className="px-16 py-6 rounded-full bg-slate-200 text-slate-500 font-black text-3xl hover:bg-slate-300">取消並關閉</button>
            </div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-6">
                 <AlertCircle size={64} className="text-amber-500" />
                 <h3 className="text-7xl font-black text-white">待盤點清單 <span className="text-amber-500 ml-4">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length} 項</span></h3>
              </div>
              <button onClick={() => setShowUnscannedList(false)} className="p-4 rounded-full hover:bg-white/10 text-white transition-all"><X size={80}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-6 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10">
                  <tr className="text-slate-500 text-3xl font-black uppercase border-b-8 border-slate-900">
                    <th className="pb-8 pl-4">產品代號</th>
                    <th className="pb-8">品名名稱</th>
                    <th className="pb-8 text-right pr-10">ERP 庫存</th>
                  </tr>
                </thead>
                <tbody className="divide-y-8 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/50 hover:bg-slate-800 transition-colors">
                      <td className="py-10 pl-8 text-5xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-10 text-4xl font-bold text-white">{item.name}</td>
                      <td className="py-10 text-5xl font-black text-right pr-10 text-slate-400">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Settings2
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v4';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 作業資訊狀態
  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
        }
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off') {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;

    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none">
      {/* 標題列：左側為 SOP 導航塊，右側為系統標題 */}
      <header className="flex justify-between items-start mb-8 px-2">

        {/* SOP 作業流程導航 */}
        <div className="flex gap-4 items-stretch">

          {/* STEP 1: 資料匯入 */}
          <div className="flex flex-col gap-2">
            <span className="text-xs font-black text-blue-500 uppercase tracking-widest pl-2">Step 1. 數據初始化</span>
            <label className={`h-16 flex items-center gap-3 px-6 rounded-2xl cursor-pointer text-xl font-black transition-all shadow-lg border-2 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={24} /> 
               {data.length === 0 ? "匯入庫存清冊" : "重匯資料"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0];
                 if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          {/* STEP 2: 作業員 */}
          <div className="flex flex-col gap-2">
            <span className="text-xs font-black text-slate-500 uppercase tracking-widest pl-2">Step 2. 登錄作業員</span>
            <div className="h-16 flex items-center bg-slate-900 border-2 border-slate-800 rounded-2xl focus-within:border-blue-500 transition-all px-4 gap-3">
              <User size={24} className="text-slate-500" />
              <input 
                type="text"
                value={operatorName}
                onChange={(e) => setOperatorName(e.target.value)}
                placeholder="輸入姓名"
                className="bg-transparent text-xl font-black outline-none placeholder:text-slate-800 w-32"
              />
            </div>
          </div>

          {/* STEP 3: 紀錄設定 */}
          <div className="flex flex-col gap-2">
            <span className="text-xs font-black text-slate-500 uppercase tracking-widest pl-2">Step 3. 紀錄模式設定</span>
            <div className="h-16 flex items-center gap-3 bg-slate-900/50 p-1.5 rounded-2xl border-2 border-slate-800">
              {/* 時間段選器 */}
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-3 py-1 rounded-lg text-sm font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>時間 OFF</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-4 py-1 rounded-lg text-sm font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={16} />年月日時分</button>
                <button onClick={() => setTimeFormat('date')} className={`px-4 py-1 rounded-lg text-sm font-black transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>年月日</button>
              </div>

              {/* 儲位開關 */}
              <button 
                onClick={() => setLocationEnabled(!locationEnabled)} 
                className={`h-full flex items-center gap-2 px-5 rounded-xl transition-all font-black text-sm border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}
              >
               <MapPin size={20} />
               {locationEnabled ? "儲位紀錄: ON" : "儲位: OFF"}
              </button>
            </div>
          </div>

          {/* STEP 4: 匯出報告 */}
          <div className="flex flex-col gap-2">
            <span className="text-xs font-black text-emerald-500 uppercase tracking-widest pl-2">Step 4. 結案產出</span>
            <button 
              onClick={handleExport} 
              disabled={data.length === 0}
              className={`h-16 flex items-center gap-2 px-8 rounded-2xl text-xl font-black transition-all shadow-md border-2 ${data.length > 0 ? 'bg-emerald-600 border-emerald-400 hover:bg-emerald-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}
            >
              <FileDown size={24} /> 匯出盤點報告
            </button>
          </div>

        </div>

        {/* 右側：標題與品牌 */}
        <div className="flex items-center gap-6 mt-4">
          <div className="text-right">
            <h1 className="text-4xl font-black tracking-tighter text-white leading-none mb-1">大豐資訊盤點系統</h1>
            <div className="flex justify-end items-center gap-2">
               <span className="bg-slate-800 text-slate-500 px-2 py-0.5 rounded text-[10px] font-bold tracking-widest">VERSION 5.0</span>
               <span className="text-blue-500 font-bold text-xs tracking-[0.3em] uppercase">Inventory Solution</span>
            </div>
          </div>
          <div className="bg-blue-600 p-4 rounded-3xl shadow-[0_0_30px_rgba(37,99,235,0.4)] rotate-3">
            <ScanBarcode className="text-white w-10 h-10" />
          </div>
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={data.length > 0 ? "請掃描或輸入條碼..." : "請先完成步驟 1 匯入檔案"}
              disabled={data.length === 0}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10 animate-in slide-in-from-right-10 duration-500">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
              placeholder="輸入代號..."
              className="bg-transparent text-6xl font-black text-amber-400 outline-none placeholder:text-amber-900/50"
              autoComplete="off"
            />
          </section>
        )}
      </div>

      {/* 主工作區 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col animate-in fade-in slide-in-from-left-8 duration-500">
              {/* 第一橫條：品名 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2">
                  <Package className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">品名名稱</p>
                  <div className="flex items-center gap-2 text-emerald-400 font-black text-xl ml-auto">
                    <CheckCircle2 size={24} /> 已完成核對
                  </div>
                </div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">
                  {lastScanned.name}
                </h2>
              </div>

              {/* 第二橫條：產品代號與作業資訊 */}
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2">
                  <Info className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-4">
                    {lastScanned.operator && (
                      <div className="flex items-center gap-2 text-blue-400 font-black text-xl bg-blue-500/10 px-6 py-2 rounded-2xl border border-blue-500/30">
                        <User size={20} /> {lastScanned.operator}
                      </div>
                    )}
                    {lastScanned.scanTime && (
                      <div className="flex items-center gap-2 text-indigo-400 font-black text-xl bg-indigo-500/10 px-6 py-2 rounded-2xl border border-indigo-500/30">
                        <Clock size={20} /> {lastScanned.scanTime}
                      </div>
                    )}
                    {lastScanned.location && (
                      <div className="flex items-center gap-2 text-amber-500 font-black text-xl bg-amber-500/10 px-6 py-2 rounded-2xl border border-amber-500/30">
                        <MapPin size={20} /> {lastScanned.location}
                      </div>
                    )}
                  </div>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">
                  {lastScanned.productCode}
                </p>
              </div>

              {/* 第三橫條：條碼編號 */}
              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2">
                  <ScanBarcode className="text-slate-500" size={32} />
                  <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">掃描條碼編號</p>
                </div>
                <p className="text-9xl font-black text-slate-300 font-mono tracking-tighter">
                  {lastScanned.barcode || '---'}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={240} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em]">系統盤點就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-[0_20px_60px_rgba(37,99,235,0.3)]">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">當前累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-[0_20px_60px_rgba(16,185,129,0.3)]' : 'bg-red-600 shadow-[0_20px_60px_rgba(220,38,38,0.3)] animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">
              {lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}
            </div>
          </div>
        </div>
      </main>

      {/* 底部數據卡 */}
      <footer className="h-40 flex gap-8 items-stretch">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-slate-800 p-6 rounded-3xl text-slate-400"><Package size={48} /></div>
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase tracking-widest">庫存總項數</p>
            <p className="text-7xl font-black text-white">{data.length}</p>
          </div>
        </div>

        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8">
          <div className="bg-emerald-900/30 p-6 rounded-3xl text-emerald-500"><ClipboardCheck size={48} /></div>
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase tracking-widest">已盤清點數</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>

        <button 
          onClick={() => setShowUnscannedList(true)}
          className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 hover:bg-slate-800 rounded-[2.5rem] flex items-center px-10 gap-8 transition-all group shadow-xl"
        >
          <div className="bg-amber-900/30 p-6 rounded-3xl text-amber-500 group-hover:scale-110 transition-transform"><AlertCircle size={48} /></div>
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase tracking-widest">待盤點清單 (檢視)</p>
            <p className="text-7xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 關聯模態視窗 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇「搜尋關聯現出品項」或「手動建立全新商品」</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>建立新商品</button>
              </div>
            </div>

            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50 animate-in fade-in duration-300">
                  <div className="max-w-4xl mx-auto space-y-12">
                    <div className="grid grid-cols-3 gap-8">
                      <div className="bg-slate-200 p-6 rounded-3xl">
                        <label className="block text-xl font-black text-slate-500 uppercase tracking-widest mb-2">條碼編號</label>
                        <p className="text-3xl font-black text-slate-700">{unknownBarcode}</p>
                      </div>
                      <div className="bg-blue-50 p-6 rounded-3xl border border-blue-100">
                        <label className="block text-xl font-black text-blue-600 uppercase tracking-widest mb-2">作業員</label>
                        <p className="text-3xl font-black text-blue-700">{operatorName || '未設定'}</p>
                      </div>
                      <div className="bg-amber-50 p-6 rounded-3xl border border-amber-100">
                        <label className="block text-xl font-black text-amber-600 uppercase tracking-widest mb-2">目前儲位</label>
                        <p className="text-3xl font-black text-amber-700">{locationEnabled ? currentLocation : '未開啟'}</p>
                      </div>
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">產品代號 / 型號 (必填)</label>
                      <input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="例如: DF-M-888" className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" />
                    </div>
                    <div>
                      <label className="block text-2xl font-black text-slate-700 uppercase tracking-widest mb-4">品名名稱 (必填)</label>
                      <input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="例如: 大豐工業級感應器" className="w-full px-10 py-8 text-5xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 transition-all" />
                    </div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl text-5xl font-black shadow-2xl transition-all active:scale-95 flex items-center justify-center gap-6"><PlusCircle size={48} /> 確認新增並開始盤點</button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col animate-in fade-in duration-300">
                  <div className="p-12 border-b-2 border-slate-100 bg-slate-50">
                    <div className="relative">
                      <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-slate-400" size={32} />
                      <input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入代號或名稱快速搜尋..." className="w-full px-20 py-8 text-5xl font-black bg-white rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500 shadow-inner" />
                    </div>
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime();
                        if (t) updated[dIdx].scanTime = t;
                        setData(updated);
                        setLastScanned(updated[dIdx]);
                        setShowMappingModal(false);
                        audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div>
                          <div className="text-4xl font-black mb-2">{item.productCode}</div>
                          <div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div>
                        </div>
                        <div className="bg-slate-100 group-hover:bg-blue-500 p-4 rounded-full transition-colors">
                          <Link size={40} className="text-blue-600 group-hover:text-white" />
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="p-12 text-center bg-slate-50 border-t border-slate-200">
              <button onClick={() => setShowMappingModal(false)} className="px-16 py-6 rounded-full bg-slate-300 text-slate-600 font-black text-3xl hover:bg-slate-400 transition-colors">取消並返回</button>
            </div>
          </div>
        </div>
      )}

      {/* 待盤點清單清單 */}
      {showUnscannedList && (
        <div className="fixed inset-0 z-50 bg-slate-950/98 flex items-center justify-center p-12 animate-in fade-in zoom-in duration-300">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-6">
                 <div className="bg-amber-500 p-6 rounded-[2rem] text-slate-950"><AlertCircle size={64} /></div>
                 <h3 className="text-7xl font-black text-white">待盤點清單 <span className="text-amber-500 ml-4 font-mono">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length} ITEMS</span></h3>
              </div>
              <button onClick={() => setShowUnscannedList(false)} className="p-4 rounded-full hover:bg-white/10 text-white transition-all"><X size={80}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-6 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10">
                  <tr className="text-slate-500 text-3xl font-black uppercase border-b-8 border-slate-900">
                    <th className="pb-8 pl-8">產品代號</th>
                    <th className="pb-8">品名名稱</th>
                    <th className="pb-8 text-right pr-12">ERP 庫存數</th>
                  </tr>
                </thead>
                <tbody className="divide-y-8 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/50 hover:bg-slate-800 transition-colors rounded-2xl overflow-hidden group">
                      <td className="py-10 pl-8 text-5xl font-black text-blue-400 font-mono group-hover:text-blue-300">{item.productCode}</td>
                      <td className="py-10 text-4xl font-bold text-slate-300 group-hover:text-white">{item.name}</td>
                      <td className="py-10 text-6xl font-black text-right pr-12 text-slate-500 group-hover:text-slate-200">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, Save, LogOut
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v5';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 作業資訊狀態
  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) {
          setData(parsed.items);
        }
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;

    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    const code = inputValue.trim();
    if (!code || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === code || item.productCode === code || item.mappedBarcodes?.includes(code)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += 1;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) {
        updatedData[index].location = currentLocation.trim();
      }
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);

      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(code);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }

    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: 1,
      diff: 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };

    const updatedData = [newItem, ...data];
    setData(updatedData);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    const confirmEnd = window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。");
    if (confirmEnd) {
      handleExport();
      const clearAll = window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？");
      if (clearAll) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextState = !isPaused;
    setIsPaused(nextState);
    if (nextState) {
      audioService.playFeedback('mapping');
    } else {
      audioService.playFeedback('success');
    }
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {/* 暫停模式遮罩 */}
      {isPaused && (
        <div 
          onClick={togglePause}
          className="absolute inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300"
        >
          <div className="bg-amber-600 p-12 rounded-[4rem] shadow-[0_0_100px_rgba(217,119,6,0.4)] group-hover:scale-110 transition-transform mb-10">
            <Play size={160} fill="currentColor" />
          </div>
          <h2 className="text-9xl font-black tracking-widest text-white drop-shadow-2xl">盤點暫停中</h2>
          <p className="text-4xl font-bold text-amber-500 mt-6 animate-pulse uppercase tracking-[0.5em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 標題列：左側為 SOP 導航塊，右側為系統標題 */}
      <header className="flex justify-between items-start mb-8 px-2">

        {/* SOP 作業流程導航 */}
        <div className="flex gap-3 items-stretch">

          {/* STEP 1: 資料匯入 */}
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest pl-2">Step 1. 數據初始化</span>
            <label className={`h-14 flex items-center gap-3 px-5 rounded-2xl cursor-pointer text-base font-black transition-all shadow-lg border-2 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={20} /> 
               {data.length === 0 ? "匯入庫存" : "重匯"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0];
                 if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          {/* STEP 2: 作業員 */}
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Step 2. 登錄作業員</span>
            <div className="h-14 flex items-center bg-slate-900 border-2 border-slate-800 rounded-2xl focus-within:border-blue-500 transition-all px-4 gap-3">
              <User size={20} className="text-slate-500" />
              <input 
                type="text"
                value={operatorName}
                onChange={(e) => setOperatorName(e.target.value)}
                placeholder="輸入人員"
                className="bg-transparent text-lg font-black outline-none placeholder:text-slate-800 w-28"
              />
            </div>
          </div>

          {/* STEP 3: 紀錄設定 */}
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Step 3. 紀錄模式</span>
            <div className="h-14 flex items-center gap-2 bg-slate-900/50 p-1 rounded-2xl border-2 border-slate-800">
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-2 py-1 rounded-lg text-[10px] font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>時間 OFF</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all flex items-center gap-1 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={12} />日期時分</button>
                <button onClick={() => setTimeFormat('date')} className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>日期</button>
              </div>
              <button 
                onClick={() => setLocationEnabled(!locationEnabled)} 
                className={`h-full flex items-center gap-1 px-3 rounded-xl transition-all font-black text-[10px] border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}
              >
               <MapPin size={14} />
               {locationEnabled ? "儲位 ON" : "儲位 OFF"}
              </button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-2 self-center h-10" />

          {/* STEP 4: 暫停作業 */}
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest pl-2">Step 4. 暫停與存檔</span>
            <button 
              onClick={togglePause}
              disabled={data.length === 0}
              className={`h-14 flex items-center gap-2 px-6 rounded-2xl text-base font-black transition-all shadow-md border-2 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}
            >
              {isPaused ? <Play size={20} /> : <Pause size={20} />}
              {isPaused ? "繼續盤點" : "休息暫停"}
            </button>
          </div>

          {/* STEP 5: 結束工作 */}
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-red-500 uppercase tracking-widest pl-2">Step 5. 結束與匯出</span>
            <button 
              onClick={handleEndJob} 
              disabled={data.length === 0}
              className={`h-14 flex items-center gap-2 px-6 rounded-2xl text-base font-black transition-all shadow-md border-2 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}
            >
              <LogOut size={20} /> 結束工作
            </button>
          </div>

        </div>

        {/* 右側標題 */}
        <div className="flex items-center gap-4 mt-2">
          <div className="text-right">
            <h1 className="text-3xl font-black tracking-tighter text-white leading-none mb-1">大豐資訊盤點系統</h1>
            <div className="flex justify-end items-center gap-2">
               <span className="bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded text-[8px] font-bold tracking-widest">PRO v6.0</span>
               <span className="text-blue-500 font-bold text-[10px] tracking-[0.3em] uppercase">Inventory System</span>
            </div>
          </div>
          <div className="bg-blue-600 p-3 rounded-2xl shadow-lg">
            <ScanBarcode className="text-white w-7 h-7" />
          </div>
        </div>
      </header>

      {/* 掃描區域與儲位輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 p-2 rounded-[2.5rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <form onSubmit={handleScan} className="relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
