              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/3 p-2 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10">
            <div className="flex items-center gap-3 mb-2 text-amber-500">
              <MapPin size={32} />
              <span className="text-2xl font-black uppercase tracking-widest">目前儲位</span>
            </div>
            <input 
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)}
