            <p className="text-4xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 rounded-[2rem] flex items-center px-8 gap-6 group transition-all">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={40} />
          <div className="text-left">
            <p className="text-sm font-black text-amber-600 uppercase tracking-widest">待盤點清單</p>
            <p className="text-4xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 關聯模態視窗與清單模態視窗保持原樣，僅需調整對應 z-index 以避免與暫停遮罩衝突 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          {/* ... 關聯邏輯代碼維持不變，確保作業流程一致 ... */}
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div>
                <h3 className="text-5xl font-black mb-2 tracking-tighter">找不到條碼: {unknownBarcode}</h3>
                <p className="text-2xl font-bold opacity-80">請選擇「搜尋關聯」或「手動建立」</p>
              </div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-10 py-4 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl scale-105' : 'bg-red-700 text-red-200'}`}>建立新商品</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50">
                  <div className="max-w-4xl mx-auto space-y-8">
                    <div className="grid grid-cols-3 gap-8">
                      <div className="bg-slate-200 p-6 rounded-3xl"><label className="block text-xl font-black text-slate-500 mb-2">條碼</label><p className="text-2xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-50 p-6 rounded-3xl"><label className="block text-xl font-black text-blue-600 mb-2">人員</label><p className="text-2xl font-black">{operatorName || '---'}</p></div>
                      <div className="bg-amber-50 p-6 rounded-3xl"><label className="block text-xl font-black text-amber-600 mb-2">儲位</label><p className="text-2xl font-black">{locationEnabled ? currentLocation : '---'}</p></div>
                    </div>
                    <div><label className="block text-xl font-black mb-2">產品代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="型號..." className="w-full px-8 py-6 text-4xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none" /></div>
                    <div><label className="block text-xl font-black mb-2">品名名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="名稱..." className="w-full px-8 py-6 text-4xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-8 bg-blue-600 text-white rounded-3xl text-4xl font-black shadow-2xl flex items-center justify-center gap-4"><PlusCircle size={32} /> 確認新增並盤點</button>
                  </div>
                </div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-10 border-b-2 border-slate-100 bg-slate-50">
                    <input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="快速搜尋產品..." className="w-full px-12 py-6 text-4xl font-black bg-white rounded-[2rem] outline-none border-4 border-transparent focus:border-blue-500 shadow-inner" />
                  </div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-8 hover:bg-blue-600 hover:text-white rounded-[2.5rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div><div className="text-3xl font-black mb-1">{item.productCode}</div><div className="text-xl font-bold opacity-60">{item.name}</div></div>
                        <Link size={32} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-8 text-center bg-slate-50 border-t"><button onClick={() => setShowMappingModal(false)} className="px-12 py-4 rounded-full bg-slate-300 text-slate-600 font-black text-2xl">取消</button></div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-[150] bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-5xl font-black text-white flex items-center gap-4"><AlertCircle size={48} className="text-amber-500" /> 待盤點清單</h3>
              <button onClick={() => setShowUnscannedList(false)} className="text-white hover:rotate-90 transition-transform"><X size={64}/></button>
            </div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10 border-b-4 border-slate-900">
                  <tr className="text-slate-500 text-2xl font-black"><th className="pb-6 pl-4">代號</th><th className="pb-6">名稱</th><th className="pb-6 text-right pr-8">庫存</th></tr>
                </thead>
                <tbody className="divide-y-4 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/40 hover:bg-slate-800 transition-colors">
                      <td className="py-6 pl-6 text-3xl font-black text-blue-400 font-mono">{item.productCode}</td>
                      <td className="py-6 text-2xl font-bold">{item.name}</td>
                      <td className="py-6 text-4xl font-black text-right pr-8 text-slate-500">{item.bookQty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v6';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1'); // 預設每次掃描增加 1
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  // UI 狀態
  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  // 手動新增品項狀態
  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  // 作業資訊狀態
  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    // 支援 50*BARCODE 語法
    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    audioService.playFeedback(!isPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[100] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-12 rounded-[4rem] shadow-[0_0_100px_rgba(217,119,6,0.4)] group-hover:scale-110 transition-transform mb-10"><Play size={160} fill="currentColor" /></div>
          <h2 className="text-9xl font-black tracking-widest">盤點暫停中</h2>
          <p className="text-4xl font-bold text-amber-500 mt-6 animate-pulse uppercase tracking-[0.5em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* Header 與各 Step 維持原樣，僅針對佈局與順序優化 */}
      <header className="flex justify-between items-start mb-8 px-2">
        <div className="flex gap-3 items-stretch">
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest pl-2">Step 1. 數據初始化</span>
            <label className={`h-14 flex items-center gap-3 px-5 rounded-2xl cursor-pointer text-base font-black transition-all shadow-lg border-2 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={20} /> {data.length === 0 ? "匯入庫存" : "重匯"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Step 2. 登錄作業員</span>
            <div className="h-14 flex items-center bg-slate-900 border-2 border-slate-800 rounded-2xl focus-within:border-blue-500 transition-all px-4 gap-3">
              <User size={20} className="text-slate-500" /><input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入人員" className="bg-transparent text-lg font-black outline-none placeholder:text-slate-800 w-28" />
            </div>
          </div>
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest pl-2">Step 3. 紀錄模式</span>
            <div className="h-14 flex items-center gap-2 bg-slate-900/50 p-1 rounded-2xl border-2 border-slate-800">
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-2 py-1 rounded-lg text-[10px] font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>時間 OFF</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all flex items-center gap-1 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={12} />日期時分</button>
                <button onClick={() => setTimeFormat('date')} className={`px-3 py-1 rounded-lg text-[10px] font-black transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>日期</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-1 px-3 rounded-xl transition-all font-black text-[10px] border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={14} />{locationEnabled ? "儲位 ON" : "儲位 OFF"}</button>
            </div>
          </div>
          <div className="w-px bg-slate-800 mx-2 self-center h-10" />
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-amber-500 uppercase tracking-widest pl-2">Step 4. 暫停與存檔</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-14 flex items-center gap-2 px-6 rounded-2xl text-base font-black transition-all shadow-md border-2 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={20} /> : <Pause size={20} />}{isPaused ? "繼續盤點" : "休息暫停"}</button>
          </div>
          <div className="flex flex-col gap-2">
            <span className="text-[10px] font-black text-red-500 uppercase tracking-widest pl-2">Step 5. 結束與匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-14 flex items-center gap-2 px-6 rounded-2xl text-base font-black transition-all shadow-md border-2 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={20} /> 結束工作</button>
          </div>
        </div>
        <div className="flex items-center gap-4 mt-2">
          <div className="text-right"><h1 className="text-3xl font-black tracking-tighter leading-none mb-1">大豐資訊盤點系統</h1><div className="flex justify-end items-center gap-2"><span className="bg-slate-800 text-slate-500 px-1.5 py-0.5 rounded text-[8px] font-bold tracking-widest">ELITE v7.0</span><span className="text-blue-500 font-bold text-[10px] tracking-[0.3em] uppercase">Inventory Solution</span></div></div>
          <div className="bg-blue-600 p-3 rounded-2xl shadow-lg"><ScanBarcode className="text-white w-7 h-7" /></div>
        </div>
      </header>

      {/* 掃描區域與倍率輸入 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 flex p-2 rounded-[2.5rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2rem] px-6 gap-3 ml-2 border border-slate-800">
            <Hash className="text-blue-500" size={24} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-4xl font-black text-blue-400 w-16 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-2xl font-black">X</span>
          </div>

          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描條碼或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-2 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-8">
            <div className="flex items-center gap-2 mb-1 text-amber-500"><MapPin size={24} /><span className="text-xl font-black uppercase tracking-widest">目前儲位</span></div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="代號..." disabled={isPaused} className="bg-transparent text-5xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-8">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><Package size={32} /><p className="text-2xl font-black uppercase tracking-widest">品名名稱</p></div>
                <h2 className="text-7xl font-black text-white truncate drop-shadow-lg">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><Info size={32} /><p className="text-2xl font-black uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-4">
                    {lastScanned.operator && <div className="flex items-center gap-2 text-blue-400 font-black text-xl bg-blue-500/10 px-6 py-2 rounded-2xl border border-blue-500/30"><User size={20} /> {lastScanned.operator}</div>}
                    {lastScanned.location && <div className="flex items-center gap-2 text-amber-500 font-black text-xl bg-amber-500/10 px-6 py-2 rounded-2xl border border-amber-500/30"><MapPin size={20} /> {lastScanned.location}</div>}
                  </div>
                </div>
                <p className="text-9xl font-black text-blue-400 font-mono tracking-tighter">{lastScanned.productCode}</p>
              </div>
              <div className="flex-1 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><ScanBarcode size={32} /><p className="text-2xl font-black uppercase tracking-widest">掃描條碼 / 最後更新</p></div>
                <p className="text-8xl font-black text-slate-300 font-mono tracking-tighter flex items-center gap-6">
                  {lastScanned.barcode || '---'}
                  {lastScanned.scanTime && <span className="text-3xl font-black text-indigo-500 border-2 border-indigo-500/30 px-6 py-2 rounded-2xl bg-indigo-500/5"><Clock size={24} className="inline mr-2" /> {lastScanned.scanTime}</span>}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10"><ScanBarcode size={240} /><p className="text-5xl font-black mt-8 tracking-[0.5em]">系統盤點就緒</p></div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative group">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.2em]">當前累計</span>
            <div className="text-huge font-black drop-shadow-lg">{lastScanned?.actualQty ?? '0'}</div>

            {lastScanned && (
              <button 
                onClick={manualSetTotalQty}
                className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 p-6 rounded-full transition-all flex items-center gap-3 text-2xl font-black backdrop-blur-md"
              >
                <Edit3 size={32} /> 手動修改
              </button>
            )}
          </div>

          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-emerald-900/40' : 'bg-red-600 shadow-red-900/40 animate-pulse'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-huge font-black text-white">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      <footer className="h-28 flex gap-8 items-stretch mb-4">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2rem] flex items-center px-8 gap-6"><Package className="text-slate-500" size={32} /><div><p className="text-xs font-black text-slate-500 uppercase">總項數</p><p className="text-3xl font-black text-white">{data.length}</p></div></div>
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[2rem] flex items-center px-8 gap-6"><ClipboardCheck className="text-emerald-500" size={32} /><div><p className="text-xs font-black text-emerald-600 uppercase">已盤項</p><p className="text-3xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p></div></div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 rounded-[2rem] flex items-center px-8 gap-6 transition-all group"><AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={32} /><div className="text-left"><p className="text-xs font-black text-amber-600 uppercase">待盤點清單 (檢視)</p><p className="text-3xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p></div></button>
      </footer>

      {/* 關聯模態與其他 UI 邏輯維持不變 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[4rem] overflow-hidden flex flex-col shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="p-10 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-4xl font-black mb-1">找不到條碼: {unknownBarcode}</h3><p className="text-xl font-bold opacity-80">請選擇「搜尋關聯」或「建立新商品」</p></div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-8 py-4 rounded-2xl font-black text-xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl' : 'bg-red-700 text-red-200'}`}>搜尋現有</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-8 py-4 rounded-2xl font-black text-xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50"><div className="max-w-3xl mx-auto space-y-6">
                    <div className="grid grid-cols-3 gap-6">
                      <div className="bg-slate-200 p-6 rounded-3xl"><label className="block text-sm font-black text-slate-500 mb-1">條碼</label><p className="text-xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-50 p-6 rounded-3xl"><label className="block text-sm font-black text-blue-600 mb-1">本次數量</label><p className="text-xl font-black text-blue-700">{scanQty}</p></div>
                      <div className="bg-amber-50 p-6 rounded-3xl"><label className="block text-sm font-black text-amber-600 mb-1">人員</label><p className="text-xl font-black text-amber-700">{operatorName || '---'}</p></div>
                    </div>
                    <div><label className="block text-lg font-black mb-2">產品代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入產品代號..." className="w-full px-8 py-5 text-3xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none" /></div>
                    <div><label className="block text-lg font-black mb-2">品名名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入完整品名..." className="w-full px-8 py-5 text-3xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-8 bg-blue-600 text-white rounded-3xl text-3xl font-black shadow-2xl flex items-center justify-center gap-4"><PlusCircle size={32} /> 確定並新增盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-8 border-b-2 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="快速搜尋..." className="w-full px-12 py-5 text-4xl font-black bg-white rounded-3xl outline-none border-4 border-transparent focus:border-blue-500" /></div>
                  <div className="flex-1 overflow-y-auto p-6 bg-white">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-6 hover:bg-blue-600 hover:text-white rounded-[2rem] transition-all border-b border-slate-100 group flex justify-between items-center mb-4">
                        <div><div className="text-3xl font-black mb-1">{item.productCode}</div><div className="text-xl font-bold opacity-60">{item.name}</div></div>
                        <Link size={32} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-8 text-center bg-slate-50 border-t"><button onClick={() => setShowMappingModal(false)} className="px-12 py-4 rounded-full bg-slate-300 text-slate-600 font-black text-2xl">返回</button></div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-[150] bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-7xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-8"><h3 className="text-5xl font-black text-white flex items-center gap-4"><AlertCircle size={48} className="text-amber-500" /> 待盤點清單</h3><button onClick={() => setShowUnscannedList(false)} className="text-white hover:rotate-90 transition-transform"><X size={64}/></button></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10 border-b-4 border-slate-900"><tr className="text-slate-500 text-2xl font-black"><th className="pb-6 pl-4">代號</th><th className="pb-6">名稱</th><th className="pb-6 text-right pr-8">ERP 庫存</th></tr></thead>
                <tbody className="divide-y-4 divide-slate-950">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/40 hover:bg-slate-800 transition-colors"><td className="py-6 pl-6 text-3xl font-black text-blue-400 font-mono">{item.productCode}</td><td className="py-6 text-2xl font-bold">{item.name}</td><td className="py-6 text-4xl font-black text-right pr-8 text-slate-500">{item.bookQty}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v7';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    audioService.playFeedback(!isPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8"><Play size={120} fill="currentColor" /></div>
          <h2 className="text-8xl font-black tracking-widest">盤點暫停中</h2>
          <p className="text-3xl font-bold text-amber-500 mt-6 animate-pulse uppercase tracking-[0.5em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航優化：說明文字放大，視覺更平衡 */}
      <header className="flex justify-between items-end mb-6 px-2">
        <div className="flex gap-4 items-stretch">

          <div className="flex flex-col gap-2">
            <span className="text-sm font-bold text-blue-500 uppercase tracking-widest pl-1">Step 1. 數據初始化</span>
            <label className={`h-16 flex items-center gap-3 px-6 rounded-2xl cursor-pointer text-lg font-black transition-all shadow-lg border-2 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={24} /> {data.length === 0 ? "匯入清冊" : "重匯數據"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-sm font-bold text-slate-400 uppercase tracking-widest pl-1">Step 2. 登錄人員</span>
            <div className="h-16 flex items-center bg-slate-900 border-2 border-slate-800 rounded-2xl focus-within:border-blue-500 transition-all px-5 gap-3">
              <User size={24} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="點擊輸入姓名" className="bg-transparent text-xl font-black outline-none placeholder:text-slate-700 w-36" />
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-sm font-bold text-slate-400 uppercase tracking-widest pl-1">Step 3. 紀錄模式</span>
            <div className="h-16 flex items-center gap-2 bg-slate-900/50 p-1.5 rounded-2xl border-2 border-slate-800">
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-4 py-1 rounded-lg text-xs font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>時間 OFF</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-5 py-1 rounded-lg text-xs font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={16} />時分</button>
                <button onClick={() => setTimeFormat('date')} className={`px-5 py-1 rounded-lg text-xs font-black transition-all ${timeFormat === 'date' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}>日期</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-2 px-5 rounded-xl transition-all font-black text-xs border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={18} />{locationEnabled ? "儲位 ON" : "儲位 OFF"}</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-2 self-center h-12" />

          <div className="flex flex-col gap-2">
            <span className="text-sm font-bold text-amber-500 uppercase tracking-widest pl-1">Step 4. 休息暫停</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-16 flex items-center gap-3 px-8 rounded-2xl text-lg font-black transition-all shadow-md border-2 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={24} /> : <Pause size={24} />}{isPaused ? "恢復作業" : "休息存檔"}</button>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-sm font-bold text-red-500 uppercase tracking-widest pl-1">Step 5. 完工結算</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-16 flex items-center gap-3 px-8 rounded-2xl text-lg font-black transition-all shadow-md border-2 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={24} /> 結束工作</button>
          </div>
        </div>

        <div className="flex flex-col items-end gap-1 pb-1">
          <div className="flex items-center gap-4">
             <div className="text-right">
                <h1 className="text-2xl font-black tracking-tighter text-white leading-none">大豐資訊盤點系統</h1>
                <span className="text-blue-500 font-bold text-[10px] tracking-[0.4em] uppercase">Inventory Solution</span>
             </div>
             <div className="bg-blue-600 p-3 rounded-2xl shadow-lg rotate-3"><ScanBarcode className="text-white w-6 h-6" /></div>
          </div>
        </div>
      </header>

      {/* 掃描區域：合理縮小整體高度 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 flex p-2 rounded-[2rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_40px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[1.5rem] px-5 gap-2 ml-1 border border-slate-800">
            <Hash className="text-blue-500" size={20} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-3xl font-black text-blue-400 w-14 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-xl font-black">X</span>
          </div>

          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-blue-500 w-10 h-10" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描條碼或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-20 pr-8 py-7 text-6xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-1.5 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2rem] flex flex-col justify-center px-8">
            <div className="flex items-center gap-2 mb-1 text-amber-500"><MapPin size={24} /><span className="text-lg font-black uppercase tracking-widest">目前儲位</span></div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="代號..." disabled={isPaused} className="bg-transparent text-5xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 主工作區：調整文字比例，不再為了極大化而犧牲清晰度 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-6">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[3rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b border-slate-800/30 flex flex-col justify-center px-10 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><Package size={28} /><p className="text-xl font-black uppercase tracking-widest">品名名稱</p></div>
                <h2 className="text-6xl font-black text-white truncate drop-shadow-md">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b border-slate-800/30 flex flex-col justify-center px-10">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><Info size={28} /><p className="text-xl font-black uppercase tracking-widest">產品代號</p>
                  <div className="ml-auto flex gap-4">
                    {lastScanned.operator && <div className="flex items-center gap-2 text-blue-400 font-black text-lg bg-blue-500/10 px-5 py-2 rounded-xl border border-blue-500/20"><User size={18} /> {lastScanned.operator}</div>}
                    {lastScanned.location && <div className="flex items-center gap-2 text-amber-500 font-black text-lg bg-amber-500/10 px-5 py-2 rounded-xl border border-amber-500/20"><MapPin size={18} /> {lastScanned.location}</div>}
                  </div>
                </div>
                <p className="text-8xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
              <div className="flex-1 flex flex-col justify-center px-10 bg-slate-800/5">
                <div className="flex items-center gap-4 mb-2 text-slate-500"><ScanBarcode size={28} /><p className="text-xl font-black uppercase tracking-widest">掃描條碼 / 異動時間</p></div>
                <p className="text-6xl font-black text-slate-300 font-mono tracking-tighter flex items-center gap-6">
                  {lastScanned.barcode || '---'}
                  {lastScanned.scanTime && <span className="text-2xl font-black text-indigo-400 bg-indigo-500/10 px-5 py-2 rounded-xl border border-indigo-500/20"><Clock size={20} className="inline mr-2" /> {lastScanned.scanTime}</span>}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10 animate-pulse">
              <ScanBarcode size={200} />
              <p className="text-4xl font-black mt-8 tracking-[0.5em]">系統盤點就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-6">
          <div className="flex-1 bg-blue-600 rounded-[3rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-2xl mb-4 uppercase tracking-[0.2em]">當前累計</span>
            <div className="text-8xl font-black drop-shadow-lg text-white">{lastScanned?.actualQty ?? '0'}</div>

            {lastScanned && (
              <button 
                onClick={manualSetTotalQty}
                className="absolute bottom-8 right-8 bg-white/20 hover:bg-white text-white hover:text-blue-600 p-4 rounded-full transition-all flex items-center gap-2 text-xl font-black backdrop-blur-md shadow-lg"
              >
                <Edit3 size={24} /> 修正
              </button>
            )}
          </div>

          <div className={`flex-1 rounded-[3rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600 shadow-emerald-900/40' : 'bg-red-600 shadow-red-900/40'}`}>
            <span className="font-black text-2xl mb-4 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-8xl font-black text-white">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      <footer className="h-24 flex gap-6 items-stretch mb-2">
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[1.5rem] flex items-center px-6 gap-4 shadow-lg"><Package className="text-slate-500" size={28} /><div><p className="text-[10px] font-black text-slate-500 uppercase">總項數</p><p className="text-3xl font-black text-white">{data.length}</p></div></div>
        <div className="flex-1 bg-slate-900/80 border border-slate-800 rounded-[1.5rem] flex items-center px-6 gap-4 shadow-lg"><ClipboardCheck className="text-emerald-500" size={28} /><div><p className="text-[10px] font-black text-emerald-600 uppercase">已盤項</p><p className="text-3xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p></div></div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900/80 border border-slate-800 hover:border-amber-500/50 rounded-[1.5rem] flex items-center px-6 gap-4 transition-all group shadow-lg"><AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={28} /><div className="text-left"><p className="text-[10px] font-black text-amber-600 uppercase">待盤點清單 (檢視)</p><p className="text-3xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p></div></button>
      </footer>

      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-6xl rounded-[3rem] overflow-hidden flex flex-col shadow-[0_0_120px_rgba(0,0,0,0.8)]">
            <div className="p-8 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-3xl font-black mb-1">找不到條碼: {unknownBarcode}</h3><p className="text-lg font-bold opacity-80">請選擇對應操作</p></div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-8 py-3 rounded-xl font-black text-lg transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-xl' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-8 py-3 rounded-xl font-black text-lg transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-xl' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[400px]">
              {isCreatingNew ? (
                <div className="flex-1 p-16 bg-slate-50"><div className="max-w-2xl mx-auto space-y-6">
                    <div className="grid grid-cols-3 gap-6">
                      <div className="bg-slate-200 p-5 rounded-2xl"><label className="block text-[10px] font-black text-slate-500 mb-1">條碼</label><p className="text-lg font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-50 p-5 rounded-2xl"><label className="block text-[10px] font-black text-blue-600 mb-1">本次數量</label><p className="text-lg font-black text-blue-700">{scanQty}</p></div>
                      <div className="bg-amber-50 p-5 rounded-2xl"><label className="block text-[10px] font-black text-amber-600 mb-1">人員</label><p className="text-lg font-black text-amber-700">{operatorName || '---'}</p></div>
                    </div>
                    <div><label className="block text-base font-black mb-2 text-slate-600 uppercase">產品代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入產品代號..." className="w-full px-8 py-4 text-3xl font-black bg-white border-4 border-slate-200 rounded-2xl outline-none focus:border-blue-500 transition-all" /></div>
                    <div><label className="block text-base font-black mb-2 text-slate-600 uppercase">品名名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入完整品名..." className="w-full px-8 py-4 text-3xl font-black bg-white border-4 border-slate-200 rounded-2xl outline-none focus:border-blue-500 transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-6 bg-blue-600 text-white rounded-2xl text-3xl font-black shadow-2xl flex items-center justify-center gap-4 transition-transform active:scale-95"><PlusCircle size={32} /> 確認並盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-8 border-b-2 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入關鍵字快速搜尋產品..." className="w-full px-10 py-5 text-3xl font-black bg-white rounded-2xl outline-none border-4 border-transparent focus:border-blue-500 shadow-inner" /></div>
                  <div className="flex-1 overflow-y-auto p-6 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-6 hover:bg-blue-600 hover:text-white rounded-2xl transition-all border-b border-slate-100 group flex justify-between items-center mb-3">
                        <div><div className="text-2xl font-black mb-1">{item.productCode}</div><div className="text-lg font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={28} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-8 text-center bg-slate-50 border-t"><button onClick={() => setShowMappingModal(false)} className="px-12 py-4 rounded-full bg-slate-300 text-slate-600 font-black text-xl hover:bg-slate-400 transition-colors">取消返回</button></div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-[250] bg-slate-950/98 flex items-center justify-center p-12 animate-in fade-in duration-300">
          <div className="w-full max-w-6xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-8"><h3 className="text-4xl font-black text-white flex items-center gap-4"><AlertCircle size={40} className="text-amber-500" /> ERP 待盤點清單</h3><button onClick={() => setShowUnscannedList(false)} className="text-white hover:rotate-90 transition-transform"><X size={56}/></button></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
              <table className="w-full text-left border-collapse">
                <thead className="sticky top-0 bg-slate-950 z-10 border-b-4 border-slate-800"><tr className="text-slate-500 text-xl font-black uppercase"><th className="pb-6 pl-4">產品代號</th><th className="pb-6">名稱</th><th className="pb-6 text-right pr-8">應有庫存</th></tr></thead>
                <tbody className="divide-y-4 divide-slate-900">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="bg-slate-900/30 hover:bg-slate-800 transition-colors"><td className="py-6 pl-6 text-2xl font-black text-blue-400 font-mono">{item.productCode}</td><td className="py-6 text-xl font-bold text-slate-300">{item.name}</td><td className="py-6 text-3xl font-black text-right pr-8 text-slate-500">{item.bookQty}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v8';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    audioService.playFeedback(!isPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8"><Play size={120} fill="currentColor" /></div>
          <h2 className="text-8xl font-black tracking-widest">盤點暫停中</h2>
          <p className="text-3xl font-bold text-amber-500 mt-6 animate-pulse uppercase tracking-[0.5em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航優化：說明文字改為 text-base，按鈕文字更大更清晰 */}
      <header className="flex justify-between items-end mb-6 px-2">
        <div className="flex gap-4 items-stretch">

          <div className="flex flex-col gap-2">
            <span className="text-base font-black text-blue-500 uppercase tracking-widest pl-1">Step 1. 數據匯入</span>
            <label className={`h-16 flex items-center gap-3 px-6 rounded-2xl cursor-pointer text-xl font-black transition-all shadow-lg border-2 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={24} /> {data.length === 0 ? "選擇檔案" : "重新匯入"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-base font-black text-slate-400 uppercase tracking-widest pl-1">Step 2. 登錄作業員</span>
            <div className="h-16 flex items-center bg-slate-900 border-2 border-slate-800 rounded-2xl focus-within:border-blue-500 transition-all px-5 gap-3">
              <User size={24} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入人員" className="bg-transparent text-xl font-black outline-none placeholder:text-slate-700 w-36" />
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-base font-black text-slate-400 uppercase tracking-widest pl-1">Step 3. 紀錄設定</span>
            <div className="h-16 flex items-center gap-2 bg-slate-900/50 p-1.5 rounded-2xl border-2 border-slate-800">
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-4 py-1 rounded-lg text-sm font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-5 py-1 rounded-lg text-sm font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={16} />計時</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-2 px-5 rounded-xl transition-all font-black text-sm border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={18} />{locationEnabled ? "儲位 ON" : "儲位 OFF"}</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-2 self-center h-12" />

          <div className="flex flex-col gap-2">
            <span className="text-base font-black text-amber-500 uppercase tracking-widest pl-1">Step 4. 作業控制</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-16 flex items-center gap-3 px-8 rounded-2xl text-xl font-black transition-all shadow-md border-2 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={24} /> : <Pause size={24} />}{isPaused ? "恢復" : "暫停"}</button>
          </div>

          <div className="flex flex-col gap-2">
            <span className="text-base font-black text-red-500 uppercase tracking-widest pl-1">Step 5. 完工結算</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-16 flex items-center gap-3 px-8 rounded-2xl text-xl font-black transition-all shadow-md border-2 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={24} /> 結束匯出</button>
          </div>
        </div>

        <div className="text-right pb-1">
            <h1 className="text-3xl font-black tracking-tighter text-white leading-none mb-1">大豐資訊盤點系統</h1>
            <span className="text-blue-500 font-bold text-xs tracking-[0.4em] uppercase">Enterprise Edition</span>
        </div>
      </header>

      {/* 掃描區域 */}
      <div className="flex gap-6 mb-4">
        <section className={`flex-1 flex p-1.5 rounded-[2rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_40px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[1.5rem] px-5 gap-2 ml-1 border border-slate-800">
            <Hash className="text-blue-500" size={20} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-3xl font-black text-blue-400 w-14 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-blue-500 w-8 h-8" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-16 pr-6 py-6 text-5xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-1.5 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2rem] flex flex-col justify-center px-8">
            <div className="flex items-center gap-2 mb-1 text-amber-500"><MapPin size={24} /><span className="text-lg font-black uppercase">儲位</span></div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="代號..." disabled={isPaused} className="bg-transparent text-4xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區：縮減高度與字級，騰出視覺空間 */}
      <main className="flex-1 grid grid-cols-12 gap-6 min-h-0 mb-4">
        <div className="col-span-8 bg-slate-900/40 border border-slate-800/50 rounded-[2.5rem] flex flex-col overflow-hidden relative shadow-xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="h-1/3 border-b border-slate-800/30 flex flex-col justify-center px-10 bg-slate-800/10">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-bold uppercase tracking-widest"><Package size={20} /> 品名名稱</div>
                <h2 className="text-4xl font-black text-white truncate">{lastScanned.name}</h2>
              </div>
              <div className="h-1/3 border-b border-slate-800/30 flex flex-col justify-center px-10">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-bold uppercase tracking-widest"><Info size={20} /> 產品代號</div>
                <p className="text-6xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
              <div className="h-1/3 flex flex-col justify-center px-10 bg-slate-800/5">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-bold uppercase tracking-widest"><ScanBarcode size={20} /> 最後掃描 / 時間</div>
                <p className="text-4xl font-black text-slate-300 font-mono flex items-center gap-5">
                  {lastScanned.barcode || '---'}
                  {lastScanned.scanTime && <span className="text-xl font-bold text-indigo-400 bg-indigo-500/10 px-4 py-1.5 rounded-xl border border-indigo-500/20">{lastScanned.scanTime}</span>}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={160} />
              <p className="text-3xl font-black mt-6 tracking-[0.5em]">系統盤點就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-6">
          <div className="flex-1 bg-blue-600 rounded-[2.5rem] flex flex-col items-center justify-center shadow-xl relative">
            <span className="text-blue-100 font-black text-xl mb-3 uppercase tracking-[0.2em]">當前累計</span>
            <div className="text-7xl font-black text-white">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-6 right-6 bg-white/20 hover:bg-white text-white hover:text-blue-600 p-3 rounded-full transition-all flex items-center gap-2 text-lg font-black backdrop-blur-sm"><Edit3 size={20} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[2.5rem] flex flex-col items-center justify-center shadow-xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-xl mb-3 uppercase tracking-[0.2em] opacity-80 text-white">庫存差異</span>
            <div className="text-7xl font-black text-white">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據：顯著放大字體，讓關鍵資訊清晰可見 */}
      <footer className="h-32 flex gap-6 items-stretch">
        <div className="flex-1 bg-slate-900 border border-slate-800 rounded-[1.5rem] flex items-center px-8 gap-6 shadow-2xl">
          <Package className="text-slate-500" size={40} />
          <div>
            <p className="text-sm font-black text-slate-500 uppercase mb-1">庫存總項數</p>
            <p className="text-5xl font-black text-white">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border border-slate-800 rounded-[1.5rem] flex items-center px-8 gap-6 shadow-2xl">
          <ClipboardCheck className="text-emerald-500" size={40} />
          <div>
            <p className="text-sm font-black text-emerald-600 uppercase mb-1">已盤清點項</p>
            <p className="text-5xl font-black text-white">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-2 border-slate-800 hover:border-amber-500 rounded-[1.5rem] flex items-center px-8 gap-6 transition-all group shadow-2xl">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={40} />
          <div className="text-left">
            <p className="text-sm font-black text-amber-600 uppercase mb-1">待盤項 (檢視)</p>
            <p className="text-5xl font-black text-white">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* Mapping Modal 等彈窗邏輯優化 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-5xl rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-8 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-3xl font-black">找不到條碼: {unknownBarcode}</h3><p className="text-lg opacity-80">請手動關聯現有產品或建立新項</p></div>
              <div className="flex gap-4">
                <button onClick={() => setIsCreatingNew(false)} className={`px-6 py-3 rounded-xl font-black ${!isCreatingNew ? 'bg-white text-red-600 shadow-lg' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-6 py-3 rounded-xl font-black ${isCreatingNew ? 'bg-white text-red-600 shadow-lg' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[450px]">
              {isCreatingNew ? (
                <div className="flex-1 p-16 bg-slate-50"><div className="max-w-xl mx-auto space-y-6">
                    <div className="grid grid-cols-2 gap-4">
                      <div className="bg-slate-200 p-4 rounded-xl"><label className="block text-xs font-black text-slate-500">條碼</label><p className="text-lg font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-50 p-4 rounded-xl"><label className="block text-xs font-black text-blue-600">數量</label><p className="text-lg font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-sm font-black mb-1 text-slate-500">產品代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="代號..." className="w-full px-6 py-4 text-2xl font-black bg-white border-4 border-slate-200 rounded-xl outline-none" /></div>
                    <div><label className="block text-sm font-black mb-1 text-slate-500">品名名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="品名..." className="w-full px-6 py-4 text-2xl font-black bg-white border-4 border-slate-200 rounded-xl outline-none" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-5 bg-blue-600 text-white rounded-xl text-2xl font-black shadow-lg active:scale-95 transition-transform"><PlusCircle className="inline mr-2" /> 確認建立並盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-6 border-b bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="搜尋關鍵字..." className="w-full px-8 py-4 text-2xl font-black bg-white rounded-xl border-4 border-transparent focus:border-blue-500 outline-none" /></div>
                  <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-5 hover:bg-blue-600 hover:text-white rounded-xl border-b border-slate-100 flex justify-between items-center transition-all mb-2">
                        <div><div className="text-xl font-black">{item.productCode}</div><div className="text-base opacity-60">{item.name}</div></div>
                        <Link size={24} />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-6 text-center border-t bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-10 py-3 rounded-full bg-slate-300 font-black">取消</button></div>
          </div>
        </div>
      )}

      {showUnscannedList && (
        <div className="fixed inset-0 z-[250] bg-slate-950/98 flex items-center justify-center p-12">
          <div className="w-full max-w-5xl h-full flex flex-col">
            <div className="flex justify-between items-center mb-6"><h3 className="text-4xl font-black text-white flex items-center gap-4"><AlertCircle size={40} className="text-amber-500" /> ERP 待盤點清單</h3><button onClick={() => setShowUnscannedList(false)} className="text-white hover:rotate-90 transition-transform"><X size={48}/></button></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar">
              <table className="w-full text-left">
                <thead className="sticky top-0 bg-slate-950 border-b-4 border-slate-800"><tr className="text-slate-500 text-lg font-black"><th className="pb-4 pl-4">產品代號</th><th className="pb-4">名稱</th><th className="pb-4 text-right pr-8">庫存</th></tr></thead>
                <tbody className="divide-y divide-slate-900">
                  {data.filter(i => i.actualQty === 0 && i.bookQty > 0).map((item, idx) => (
                    <tr key={idx} className="hover:bg-slate-900/50"><td className="py-5 pl-4 text-xl font-black text-blue-400 font-mono">{item.productCode}</td><td className="py-5 text-lg font-bold text-slate-300">{item.name}</td><td className="py-5 text-2xl font-black text-right pr-8 text-slate-500">{item.bookQty}</td></tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v9';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    audioService.playFeedback(!isPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8"><Play size={120} fill="currentColor" /></div>
          <h2 className="text-8xl font-black tracking-widest">盤點暫停中</h2>
          <p className="text-3xl font-bold text-amber-500 mt-6 animate-pulse uppercase tracking-[0.5em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區：顯著放大字體與標題 */}
      <header className="flex justify-between items-end mb-8 px-2">
        <div className="flex gap-6 items-stretch">

          <div className="flex flex-col gap-3">
            <span className="text-xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-20 flex items-center gap-4 px-8 rounded-3xl cursor-pointer text-2xl font-black transition-all shadow-lg border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={32} /> {data.length === 0 ? "選擇庫存清冊" : "重新匯入清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-3">
            <span className="text-xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業員</span>
            <div className="h-20 flex items-center bg-slate-900 border-4 border-slate-800 rounded-3xl focus-within:border-blue-500 transition-all px-6 gap-4">
              <User size={32} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="點擊輸入姓名" className="bg-transparent text-2xl font-black outline-none placeholder:text-slate-700 w-48" />
            </div>
          </div>

          <div className="flex flex-col gap-3">
            <span className="text-xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 紀錄設定</span>
            <div className="h-20 flex items-center gap-3 bg-slate-900/50 p-2 rounded-3xl border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-6 rounded-xl text-lg font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-6 rounded-xl text-lg font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600'}`}><Clock size={20} />計時模式</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-3 px-6 rounded-2xl transition-all font-black text-lg border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={24} />{locationEnabled ? "儲位 ON" : "儲位 OFF"}</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-2 self-center h-16" />

          <div className="flex flex-col gap-3">
            <span className="text-xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 休息</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-20 flex items-center gap-4 px-8 rounded-3xl text-2xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={32} /> : <Pause size={32} />}{isPaused ? "繼續" : "暫停"}</button>
          </div>

          <div className="flex flex-col gap-3">
            <span className="text-xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 完工</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-20 flex items-center gap-4 px-8 rounded-3xl text-2xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={32} /> 匯出結束</button>
          </div>
        </div>

        <div className="text-right pb-1">
            <h1 className="text-4xl font-black tracking-tighter text-white leading-none mb-1">大豐資訊盤點系統</h1>
            <span className="text-blue-500 font-bold text-sm tracking-[0.5em] uppercase">Enterprise Edition v9.0</span>
        </div>
      </header>

      {/* 掃描列：維持易讀，但縮減外部空間 */}
      <div className="flex gap-6 mb-6">
        <section className={`flex-1 flex p-2 rounded-[2.5rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_50px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2rem] px-6 gap-3 ml-2 border border-slate-800">
            <Hash className="text-blue-500" size={24} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-4xl font-black text-blue-400 w-16 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-2xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-blue-500 w-10 h-10" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-20 pr-8 py-8 text-6xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-2 bg-amber-900/10 border-4 border-amber-800/50 rounded-[2.5rem] flex flex-col justify-center px-10">
            <div className="flex items-center gap-3 mb-1 text-amber-500 font-black text-xl uppercase tracking-widest"><MapPin size={28} /> 儲位代碼</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="點擊輸入..." disabled={isPaused} className="bg-transparent text-5xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區：顯著降低高度，空間騰給上下導航與統計 */}
      <main className="flex-1 grid grid-cols-12 gap-8 min-h-0 mb-6">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[3.5rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="h-1/3 border-b-2 border-slate-800/50 flex flex-col justify-center px-12 bg-slate-800/10">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-black text-lg uppercase tracking-widest"><Package size={24} /> 品名名稱</div>
                <h2 className="text-4xl font-black text-white truncate drop-shadow-lg">{lastScanned.name}</h2>
              </div>
              <div className="h-1/3 border-b-2 border-slate-800/50 flex flex-col justify-center px-12">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-black text-lg uppercase tracking-widest"><Info size={24} /> 產品代號</div>
                <p className="text-6xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
              <div className="h-1/3 flex flex-col justify-center px-12 bg-slate-800/5">
                <div className="flex items-center gap-3 mb-1 text-slate-500 font-black text-lg uppercase tracking-widest"><ScanBarcode size={24} /> 最後掃描條碼</div>
                <p className="text-4xl font-black text-slate-300 font-mono flex items-center gap-6">
                  {lastScanned.barcode || '---'}
                  {lastScanned.scanTime && <span className="text-2xl font-black text-indigo-400 bg-indigo-500/10 px-6 py-2 rounded-2xl border border-indigo-500/20">{lastScanned.scanTime}</span>}
                </p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-4xl font-black mt-6 tracking-[0.5em]">系統盤點就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[3.5rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-2xl mb-2 uppercase tracking-[0.3em]">當前累計</span>
            <div className="text-8xl font-black drop-shadow-xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 p-4 rounded-full transition-all flex items-center gap-2 text-2xl font-black backdrop-blur-md shadow-2xl"><Edit3 size={28} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[3.5rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-2xl mb-2 uppercase tracking-[0.3em] opacity-80 text-white">庫存差異</span>
            <div className="text-8xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據：大幅度擴充高度，數字極大化，方便一眼查看總體進度 */}
      <footer className="h-44 flex gap-8 items-stretch mb-2">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-10 shadow-2xl">
          <Package className="text-slate-500" size={64} />
          <div>
            <p className="text-xl font-black text-slate-500 uppercase mb-2 tracking-widest">庫存總項數</p>
            <p className="text-7xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[2.5rem] flex items-center px-10 gap-10 shadow-2xl">
          <ClipboardCheck className="text-emerald-500" size={64} />
          <div>
            <p className="text-xl font-black text-emerald-600 uppercase mb-2 tracking-widest">已完成項數</p>
            <p className="text-7xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[2.5rem] flex items-center px-10 gap-10 transition-all group shadow-2xl">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={64} />
          <div className="text-left">
            <p className="text-xl font-black text-amber-600 uppercase mb-2 tracking-widest">待盤點項 (檢視)</p>
            <p className="text-7xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗：維持功能，視覺上與整體風格一致 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-6xl rounded-[4rem] overflow-hidden flex flex-col shadow-2xl border-8 border-slate-800">
            <div className="p-10 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-5xl font-black mb-2">條碼未登入: {unknownBarcode}</h3><p className="text-2xl font-bold opacity-80">請手動選擇對應產品或建立新項目</p></div>
              <div className="flex gap-6">
                <button onClick={() => setIsCreatingNew(false)} className={`px-10 py-5 rounded-2xl font-black text-2xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-10 py-5 rounded-2xl font-black text-2xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[500px]">
              {isCreatingNew ? (
                <div className="flex-1 p-20 bg-slate-50"><div className="max-w-2xl mx-auto space-y-8">
                    <div className="grid grid-cols-2 gap-6">
                      <div className="bg-slate-200 p-6 rounded-2xl shadow-inner"><label className="block text-sm font-black text-slate-500 mb-1">條碼編號</label><p className="text-2xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-50 p-6 rounded-2xl shadow-inner"><label className="block text-sm font-black text-blue-600 mb-1">本次數量</label><p className="text-2xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-xl font-black mb-2 text-slate-600">產品代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品代號..." className="w-full px-10 py-6 text-4xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 shadow-xl transition-all" /></div>
                    <div><label className="block text-xl font-black mb-2 text-slate-600">品名名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-10 py-6 text-4xl font-black bg-white border-4 border-slate-200 rounded-3xl outline-none focus:border-blue-600 shadow-xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-8 bg-blue-600 text-white rounded-3xl text-4xl font-black shadow-2xl active:scale-95 transition-transform flex items-center justify-center gap-4"><PlusCircle size={48} /> 確認建立並盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-10 border-b-4 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入產品代號或名稱進行快速搜尋..." className="w-full px-12 py-6 text-4xl font-black bg-white rounded-3xl border-4 border-transparent focus:border-blue-600 outline-none shadow-xl" /></div>
                  <div className="flex-1 overflow-y-auto p-8 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-8 hover:bg-blue-600 hover:text-white rounded-3xl border-b-2 border-slate-100 flex justify-between items-center transition-all mb-4 group shadow-sm hover:shadow-xl">
                        <div><div className="text-3xl font-black mb-1">{item.productCode}</div><div className="text-xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={40} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-10 text-center border-t-4 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-16 py-5 rounded-full bg-slate-400 text-white font-black text-2xl hover:bg-slate-500 transition-colors shadow-xl">取消作業</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v10';

type TimeFormat = 'off' | 'datetime' | 'date';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    setIsPaused(!isPaused);
    audioService.playFeedback(!isPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8"><Play size={120} fill="currentColor" /></div>
          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>
          <p className="text-3xl font-bold text-amber-500 mt-10 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區：大幅度增加高度與字體級別 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="點擊輸入品名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-8 rounded-xl text-xl font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-8 rounded-xl text-xl font-black transition-all flex items-center gap-3 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600'}`}><Clock size={24} />計時 ON</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">Enterprise Edition</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner">
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區：高度縮減，將垂直空間讓給頂部與底部 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">Ready for Scan</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據：顯著放大，高度擴張 (h-44)，數據極大化 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗部分保持不變，因為這就是您確認的功能核心 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="點擊輸入品名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-8 rounded-xl text-xl font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-8 rounded-xl text-xl font-black transition-all flex items-center gap-3 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600'}`}><Clock size={24} />計時 ON</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">Cloud Backup Ready</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner">
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">Ready for Scan</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="點擊輸入品名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-8 rounded-xl text-xl font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-8 rounded-xl text-xl font-black transition-all flex items-center gap-3 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600'}`}><Clock size={24} />計時 ON</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner">
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">條碼掃描就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('off');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat || 'off');
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入姓名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('off')} className={`px-8 rounded-xl text-xl font-black transition-all ${timeFormat === 'off' ? 'bg-slate-700 text-white' : 'text-slate-600'}`}>不計時</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-8 rounded-xl text-xl font-black transition-all flex items-center gap-3 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600'}`}><Clock size={24} />計時 ON</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner">
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">條碼掃描就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  // 預設改為 'date' (僅記日期)，避免預設不記錄任何時間
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('date');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          // 如果讀取到的設定是 'off'，強制轉為 'date'
          setTimeFormat(parsed.config.timeFormat === 'off' ? 'date' : (parsed.config.timeFormat || 'date'));
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入姓名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('date')} className={`px-6 rounded-xl text-xl font-black transition-all ${timeFormat === 'date' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-600 hover:text-slate-400'}`}>僅記日期</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-6 rounded-xl text-xl font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600 hover:text-slate-400'}`}><Clock size={24} />完整時間</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner">
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">條碼掃描就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  // 預設改為 'date' (僅記日期)，避免預設不記錄任何時間
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('date');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          // 如果讀取到的設定是 'off'，強制轉為 'date'
          setTimeFormat(parsed.config.timeFormat === 'off' ? 'date' : (parsed.config.timeFormat || 'date'));
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    // 關鍵修改：如果目前焦點在數量輸入框，就不要強制跳回條碼輸入框，允許使用者打字
    if (document.activeElement === qtyRef.current) return;

    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入姓名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('date')} className={`px-6 rounded-xl text-xl font-black transition-all ${timeFormat === 'date' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-600 hover:text-slate-400'}`}>僅記日期</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-6 rounded-xl text-xl font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600 hover:text-slate-400'}`}><Clock size={24} />完整時間</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div 
            className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner cursor-text"
            onClick={(e) => {
              e.stopPropagation(); // 阻止事件冒泡，避免觸發 window 的 click listener
              qtyRef.current?.focus();
            }}
          >
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              onFocus={(e) => e.target.select()} // 聚焦時全選
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  inputRef.current?.focus(); // Enter 跳回掃描
                }
              }}
              onClick={(e) => e.stopPropagation()}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input type="text" value={currentLocation} onChange={(e) => setCurrentLocation(e.target.value)} placeholder="輸入位置..." disabled={isPaused} className="bg-transparent text-6xl font-black text-amber-400 outline-none" autoComplete="off" />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">條碼掃描就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  // 預設改為 'date' (僅記日期)，避免預設不記錄任何時間
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('date');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);
  const locationRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          // 如果讀取到的設定是 'off'，強制轉為 'date'
          setTimeFormat(parsed.config.timeFormat === 'off' ? 'date' : (parsed.config.timeFormat || 'date'));
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    // 關鍵修改：如果目前焦點在 數量輸入框 或 儲位輸入框，就不要強制跳回條碼輸入框，允許使用者打字
    if (document.activeElement === qtyRef.current || document.activeElement === locationRef.current) return;

    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);

    // 當切換到暫停時，自動執行雲端備份
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }

    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    <div className="h-screen flex flex-col bg-slate-950 text-white overflow-hidden p-6 select-none relative">

      {isPaused && (
        <div onClick={togglePause} className="absolute inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-10 rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-8">
            <Play size={120} fill="currentColor" />
          </div>

          <h2 className="text-8xl font-black tracking-widest text-center">盤點暫停中<br/><span className="text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          {/* 雲端同步狀態顯示區 */}
          <div className="mt-12 flex items-center gap-6 bg-slate-900/50 px-10 py-6 rounded-full border-4 border-slate-800 shadow-2xl">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={48} className="text-blue-500 animate-spin" />
                <span className="text-3xl font-black text-blue-400 uppercase tracking-widest">雲端備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={48} className="text-emerald-500 animate-bounce" />
                <span className="text-3xl font-black text-emerald-400 uppercase tracking-widest">雲端備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={48} className="text-red-500" />
                <span className="text-3xl font-black text-red-500 uppercase tracking-widest">雲端連線失敗 (本地已儲存)</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待資料變更...</span>
            )}
          </div>

          <p className="text-3xl font-bold text-amber-500 mt-12 animate-pulse uppercase tracking-[0.4em]">點擊螢幕任何地方恢復作業</p>
        </div>
      )}

      {/* 頂部導航區 */}
      <header className="flex justify-between items-end mb-10 px-2 shrink-0">
        <div className="flex gap-8 items-stretch">

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 數據匯入</span>
            <label className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] cursor-pointer text-3xl font-black transition-all shadow-xl border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
               <FileSpreadsheet size={40} /> {data.length === 0 ? "匯入庫存清冊" : "重新讀取清冊"}
               <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                 const file = e.target.files?.[0]; if (!file) return;
                 const r = new FileReader();
                 r.onload = (ev) => {
                   const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                   const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                   setData((json as any[]).map(row => ({
                     barcode: String(row['條碼編號'] || '').trim(),
                     productCode: String(row['產品代號'] || '').trim(),
                     name: String(row['品名'] || row['名稱'] || '').trim(),
                     bookQty: parseFloat(row['期末數量'] || 0),
                     actualQty: 0,
                     diff: -parseFloat(row['期末數量'] || 0),
                     originalRow: row
                   })));
                 };
                 r.readAsArrayBuffer(file);
               }} className="hidden" />
            </label>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 作業人員</span>
            <div className="h-24 flex items-center bg-slate-900 border-4 border-slate-800 rounded-[2rem] focus-within:border-blue-500 transition-all px-8 gap-5">
              <User size={40} className="text-slate-500" />
              <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="輸入姓名" className="bg-transparent text-3xl font-black outline-none placeholder:text-slate-700 w-56" />
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
            <div className="h-24 flex items-center gap-4 bg-slate-900/50 p-3 rounded-[2rem] border-4 border-slate-800">
              <div className="flex bg-slate-950 p-1.5 rounded-2xl border border-slate-800 h-full">
                <button onClick={() => setTimeFormat('date')} className={`px-6 rounded-xl text-xl font-black transition-all ${timeFormat === 'date' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-600 hover:text-slate-400'}`}>僅記日期</button>
                <button onClick={() => setTimeFormat('datetime')} className={`px-6 rounded-xl text-xl font-black transition-all flex items-center gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600 hover:text-slate-400'}`}><Clock size={24} />完整時間</button>
              </div>
              <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-4 px-8 rounded-2xl transition-all font-black text-xl border-2 ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={32} />儲位紀錄</button>
            </div>
          </div>

          <div className="w-px bg-slate-800 mx-4 self-center h-20" />

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停備份</span>
            <button onClick={togglePause} disabled={data.length === 0} className={`h-24 flex items-center gap-4 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={40} /> : <Pause size={40} />}</button>
          </div>

          <div className="flex flex-col gap-4">
            <span className="text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 匯出</span>
            <button onClick={handleEndJob} disabled={data.length === 0} className={`h-24 flex items-center gap-5 px-10 rounded-[2rem] text-3xl font-black transition-all shadow-md border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={40} /> 結束盤點</button>
          </div>
        </div>

        <div className="text-right pb-1 flex flex-col items-end">
            <h1 className="text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
      </header>

      {/* 掃描列 */}
      <div className="flex gap-8 mb-8 shrink-0">
        <section className={`flex-1 flex p-3 rounded-[3rem] transition-all duration-300 border-4 ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_60px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div 
            className="flex items-center bg-slate-950 rounded-[2.5rem] px-8 gap-4 ml-2 border border-slate-800 shadow-inner cursor-text"
            onClick={(e) => {
              e.stopPropagation(); // 阻止事件冒泡，避免觸發 window 的 click listener
              qtyRef.current?.focus();
            }}
          >
            <Hash className="text-blue-500" size={32} />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              onFocus={(e) => e.target.select()} // 聚焦時全選
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  inputRef.current?.focus(); // Enter 跳回掃描
                }
              }}
              onClick={(e) => e.stopPropagation()}
              className="bg-transparent text-5xl font-black text-blue-400 w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative">
            <Search className="absolute left-10 top-1/2 -translate-y-1/2 text-blue-500 w-12 h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停中..." : data.length > 0 ? "掃描或輸入 [數量*條碼]..." : "請先匯入庫存清冊"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-24 pr-10 py-10 text-7xl font-black text-white outline-none placeholder:text-slate-800"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-1/4 p-3 bg-amber-900/10 border-4 border-amber-800/50 rounded-[3rem] flex flex-col justify-center px-12">
            <div className="flex items-center gap-4 mb-2 text-amber-500 font-black text-2xl uppercase tracking-widest"><MapPin size={36} /> 目前儲位</div>
            <input 
              ref={locationRef}
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)} 
              onClick={(e) => e.stopPropagation()} // 阻止冒泡，避免被 focusInput 搶走焦點
              placeholder="輸入位置..." 
              disabled={isPaused} 
              className="bg-transparent text-6xl font-black text-amber-400 outline-none" 
              autoComplete="off" 
            />
          </section>
        )}
      </div>

      {/* 中央主工作區 */}
      <main className="flex-[0.6] grid grid-cols-12 gap-8 min-h-0 mb-8 shrink-0">
        <div className="col-span-8 bg-slate-900/40 border-4 border-slate-800/50 rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16 bg-slate-800/10">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Package size={28} /> 品名名稱</div>
                <h2 className="text-5xl font-black text-white truncate drop-shadow-xl leading-tight">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-16">
                <div className="flex items-center gap-4 mb-2 text-slate-500 font-black text-xl uppercase tracking-widest"><Info size={28} /> 產品型號 / 代號</div>
                <p className="text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10">
              <ScanBarcode size={180} />
              <p className="text-5xl font-black mt-8 tracking-[0.5em] uppercase">條碼掃描就緒</p>
            </div>
          )}
        </div>

        <div className="col-span-4 flex flex-col gap-8">
          <div className="flex-1 bg-blue-600 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative">
            <span className="text-blue-100 font-black text-3xl mb-4 uppercase tracking-[0.4em]">累計數量</span>
            <div className="text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-10 right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-6 py-4 rounded-3xl transition-all flex items-center gap-3 text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={32} /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-3xl mb-4 uppercase tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據 */}
      <footer className="h-44 flex gap-8 items-stretch mb-4 shrink-0">
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <Package className="text-slate-500" size={80} />
          <div>
            <p className="text-2xl font-black text-slate-500 uppercase mb-3 tracking-widest">總項數</p>
            <p className="text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="flex-1 bg-slate-900 border-4 border-slate-800 rounded-[3rem] flex items-center px-12 gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <ClipboardCheck className="text-emerald-500" size={80} />
          <div>
            <p className="text-2xl font-black text-emerald-600 uppercase mb-3 tracking-widest">已完成項</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="flex-1 bg-slate-900 border-4 border-slate-800 hover:border-amber-500 rounded-[3rem] flex items-center px-12 gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)]">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform" size={80} />
          <div className="text-left">
            <p className="text-2xl font-black text-amber-600 uppercase mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容維持 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-[12px] border-slate-800">
            <div className="p-12 bg-red-600 text-white flex justify-between items-center">
              <div><h3 className="text-6xl font-black mb-3 italic">! 未知條碼: {unknownBarcode}</h3><p className="text-3xl font-bold opacity-80">請手動選擇關聯現有產品，或點擊「建立新項」手動輸入。</p></div>
              <div className="flex gap-8">
                <button onClick={() => setIsCreatingNew(false)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>搜尋關聯</button>
                <button onClick={() => setIsCreatingNew(true)} className={`px-12 py-6 rounded-3xl font-black text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-110' : 'bg-red-700 text-red-200'}`}>建立新項</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-24 bg-slate-50 flex flex-col justify-center"><div className="max-w-3xl mx-auto w-full space-y-10">
                    <div className="grid grid-cols-2 gap-8">
                      <div className="bg-slate-200 p-8 rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-xl font-black text-slate-500 mb-2 uppercase">未知條碼</label><p className="text-4xl font-black">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-8 rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-xl font-black text-blue-600 mb-2 uppercase">掃描數量</label><p className="text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品型號 / 代號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入 ERP 產品編號..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-2xl font-black mb-3 text-slate-700 uppercase">產品品名 / 名稱 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入產品品名..." className="w-full px-12 py-8 text-5xl font-black bg-white border-8 border-slate-200 rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-10 bg-blue-600 text-white rounded-[2.5rem] text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-6"><PlusCircle size={64} /> 儲存並加入盤點</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-12 border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="輸入型號或品名關鍵字搜尋..." className="w-full px-16 py-10 text-5xl font-black bg-white rounded-[3rem] border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-10 hover:bg-blue-600 hover:text-white rounded-[3rem] border-b-4 border-slate-100 flex justify-between items-center transition-all mb-6 group shadow-md hover:shadow-2xl">
                        <div><div className="text-4xl font-black mb-2">{item.productCode}</div><div className="text-2xl font-bold opacity-60 group-hover:opacity-100">{item.name}</div></div>
                        <Link size={64} className="text-blue-600 group-hover:text-white" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-12 text-center border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="px-24 py-6 rounded-full bg-slate-400 text-white font-black text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄本次掃描</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff, Menu
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('date');

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);
  const locationRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat === 'off' ? 'date' : (parsed.config.timeFormat || 'date'));
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  const focusInput = useCallback(() => {
    if (document.activeElement === qtyRef.current || document.activeElement === locationRef.current) return;
    // 在移動端，如果有點擊 mapping modal 或其他操作，暫時不強制 focus 以免鍵盤一直跳出
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused) {
      // 僅在非移動端或明確操作時強制 focus，這裡保留原邏輯但建議使用者在手機上點擊掃描框
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    if (isPaused) return;

    let targetCode = inputValue.trim();
    let currentAddQty = parseFloat(scanQty) || 1;

    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);
    } else {
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
    }
    setInputValue('');
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
  };

  const handleExport = () => {
    if (data.length === 0) return;
    const ws = XLSX.utils.json_to_sheet(data.map(i => ({
      ...i.originalRow,
      '實際盤點': i.actualQty,
      '差異': i.diff,
      '作業員': i.operator || '',
      '儲位': i.location || '',
      '盤點時間': i.scanTime || '',
      '手動關聯條碼': i.mappedBarcodes?.join(', ')
    })));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "盤點結果");
    XLSX.writeFile(wb, `大豐盤點_${new Date().toLocaleDateString()}.xlsx`);
  };

  const handleEndJob = () => {
    if (data.length === 0) return;
    if (window.confirm("確定要結束盤點工作嗎？系統將自動匯出最終報表。")) {
      handleExport();
      if (window.confirm("報表已匯出。是否要清空本次盤點數據以開始新的工作？")) {
        localStorage.removeItem(STORAGE_KEY);
        window.location.reload();
      }
    }
  };

  const togglePause = () => {
    const nextPaused = !isPaused;
    setIsPaused(nextPaused);
    if (nextPaused && data.length > 0) {
      backupToCloud(data);
    } else {
      setSyncStatus('idle');
    }
    audioService.playFeedback(nextPaused ? 'mapping' : 'success');
  };

  return (
    // Root: 手機版 min-h-screen 並允許捲動，電腦版 h-screen 並鎖定捲動
    <div className="flex flex-col bg-slate-950 text-white p-3 md:p-6 select-none relative min-h-screen md:h-screen overflow-y-auto md:overflow-hidden">

      {isPaused && (
        <div onClick={togglePause} className="fixed inset-0 z-[200] bg-slate-950/80 backdrop-blur-md flex flex-col items-center justify-center cursor-pointer group animate-in fade-in duration-300">
          <div className="bg-amber-600 p-6 md:p-10 rounded-full md:rounded-[3rem] shadow-[0_0_80px_rgba(217,119,6,0.3)] group-hover:scale-110 transition-transform mb-4 md:mb-8">
            <Play size={60} className="md:w-[120px] md:h-[120px]" fill="currentColor" />
          </div>

          <h2 className="text-5xl md:text-8xl font-black tracking-widest text-center">盤點暫停<br/><span className="text-2xl md:text-4xl text-amber-500/60 uppercase tracking-[0.5em]">Paused</span></h2>

          <div className="mt-8 md:mt-12 flex items-center gap-3 md:gap-6 bg-slate-900/50 px-6 py-4 md:px-10 md:py-6 rounded-full border-2 md:border-4 border-slate-800 shadow-2xl scale-90 md:scale-100">
            {syncStatus === 'syncing' && (
              <>
                <CloudSync size={32} className="md:w-[48px] md:h-[48px] text-blue-500 animate-spin" />
                <span className="text-xl md:text-3xl font-black text-blue-400 uppercase tracking-widest">備份同步中...</span>
              </>
            )}
            {syncStatus === 'success' && (
              <>
                <CheckCircle2 size={32} className="md:w-[48px] md:h-[48px] text-emerald-500 animate-bounce" />
                <span className="text-xl md:text-3xl font-black text-emerald-400 uppercase tracking-widest">備份已確認</span>
              </>
            )}
            {syncStatus === 'error' && (
              <>
                <CloudOff size={32} className="md:w-[48px] md:h-[48px] text-red-500" />
                <span className="text-xl md:text-3xl font-black text-red-500 uppercase tracking-widest">連線失敗</span>
              </>
            )}
            {syncStatus === 'idle' && (
              <span className="text-lg md:text-2xl font-bold text-slate-500 uppercase tracking-widest italic">等待變更...</span>
            )}
          </div>
          <p className="text-xl md:text-3xl font-bold text-amber-500 mt-8 md:mt-12 animate-pulse uppercase tracking-[0.2em] md:tracking-[0.4em]">點擊恢復作業</p>
        </div>
      )}

      {/* 頂部導航區：手機版改為橫向捲動容器 (overflow-x-auto) */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-end mb-4 md:mb-10 shrink-0 gap-4 md:gap-0">
        <div className="w-full md:w-auto overflow-x-auto custom-scrollbar pb-2 md:pb-0">
          <div className="flex gap-4 md:gap-8 items-stretch min-w-max">

            <div className="flex flex-col gap-1 md:gap-4">
              <span className="text-sm md:text-2xl font-black text-blue-500 uppercase tracking-widest pl-1">STEP 1. 匯入</span>
              <label className={`h-16 md:h-24 flex items-center gap-2 md:gap-4 px-6 md:px-10 rounded-2xl md:rounded-[2rem] cursor-pointer text-xl md:text-3xl font-black transition-all shadow-xl border-2 md:border-4 ${data.length === 0 ? 'bg-blue-600 border-blue-400 hover:bg-blue-700 animate-pulse' : 'bg-slate-900 border-slate-800 text-slate-400 hover:border-blue-500'}`}>
                 <FileSpreadsheet size={24} className="md:w-[40px] md:h-[40px]" /> 
                 {data.length === 0 ? "匯入" : "重讀"}
                 <input type="file" accept=".csv, .xlsx" onChange={(e) => {
                   const file = e.target.files?.[0]; if (!file) return;
                   const r = new FileReader();
                   r.onload = (ev) => {
                     const wb = XLSX.read(new Uint8Array(ev.target?.result as ArrayBuffer), { type: 'array' });
                     const json = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
                     setData((json as any[]).map(row => ({
                       barcode: String(row['條碼編號'] || '').trim(),
                       productCode: String(row['產品代號'] || '').trim(),
                       name: String(row['品名'] || row['名稱'] || '').trim(),
                       bookQty: parseFloat(row['期末數量'] || 0),
                       actualQty: 0,
                       diff: -parseFloat(row['期末數量'] || 0),
                       originalRow: row
                     })));
                   };
                   r.readAsArrayBuffer(file);
                 }} className="hidden" />
              </label>
            </div>

            <div className="flex flex-col gap-1 md:gap-4">
              <span className="text-sm md:text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 2. 人員</span>
              <div className="h-16 md:h-24 flex items-center bg-slate-900 border-2 md:border-4 border-slate-800 rounded-2xl md:rounded-[2rem] focus-within:border-blue-500 transition-all px-4 md:px-8 gap-2 md:gap-5">
                <User size={24} className="md:w-[40px] md:h-[40px] text-slate-500" />
                <input type="text" value={operatorName} onChange={(e) => setOperatorName(e.target.value)} placeholder="姓名" className="bg-transparent text-xl md:text-3xl font-black outline-none placeholder:text-slate-700 w-24 md:w-56" />
              </div>
            </div>

            <div className="flex flex-col gap-1 md:gap-4">
              <span className="text-sm md:text-2xl font-black text-slate-400 uppercase tracking-widest pl-1">STEP 3. 設定</span>
              <div className="h-16 md:h-24 flex items-center gap-2 md:gap-4 bg-slate-900/50 p-2 md:p-3 rounded-2xl md:rounded-[2rem] border-2 md:border-4 border-slate-800">
                <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800 h-full">
                  <button onClick={() => setTimeFormat('date')} className={`px-3 md:px-6 rounded-lg md:rounded-xl text-sm md:text-xl font-black transition-all ${timeFormat === 'date' ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-600 hover:text-slate-400'}`}>日期</button>
                  <button onClick={() => setTimeFormat('datetime')} className={`px-3 md:px-6 rounded-lg md:rounded-xl text-sm md:text-xl font-black transition-all flex items-center gap-1 md:gap-2 ${timeFormat === 'datetime' ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-600 hover:text-slate-400'}`}><Clock size={16} className="md:w-[24px] md:h-[24px]" />時間</button>
                </div>
                <button onClick={() => setLocationEnabled(!locationEnabled)} className={`h-full flex items-center gap-2 md:gap-4 px-4 md:px-8 rounded-xl md:rounded-2xl transition-all font-black text-sm md:text-xl border ${locationEnabled ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}><MapPin size={20} className="md:w-[32px] md:h-[32px]" />儲位</button>
              </div>
            </div>

            <div className="w-px bg-slate-800 mx-1 md:mx-4 self-center h-12 md:h-20" />

            <div className="flex flex-col gap-1 md:gap-4">
              <span className="text-sm md:text-2xl font-black text-amber-500 uppercase tracking-widest pl-1">STEP 4. 暫停</span>
              <button onClick={togglePause} disabled={data.length === 0} className={`h-16 md:h-24 flex items-center gap-2 md:gap-4 px-6 md:px-10 rounded-2xl md:rounded-[2rem] text-xl md:text-3xl font-black transition-all shadow-md border-2 md:border-4 ${isPaused ? 'bg-amber-600 border-amber-400 text-white' : 'bg-slate-900 border-slate-800 text-amber-500 hover:bg-slate-800 disabled:opacity-30'}`}>{isPaused ? <Play size={24} className="md:w-[40px] md:h-[40px]" /> : <Pause size={24} className="md:w-[40px] md:h-[40px]" />}</button>
            </div>

            <div className="flex flex-col gap-1 md:gap-4">
              <span className="text-sm md:text-2xl font-black text-red-500 uppercase tracking-widest pl-1">STEP 5. 結束</span>
              <button onClick={handleEndJob} disabled={data.length === 0} className={`h-16 md:h-24 flex items-center gap-2 md:gap-5 px-6 md:px-10 rounded-2xl md:rounded-[2rem] text-xl md:text-3xl font-black transition-all shadow-md border-2 md:border-4 ${data.length > 0 ? 'bg-red-600 border-red-400 hover:bg-red-700 text-white' : 'bg-slate-900 border-slate-800 text-slate-700 cursor-not-allowed'}`}><LogOut size={24} className="md:w-[40px] md:h-[40px]" /> 結束</button>
            </div>
          </div>
        </div>

        <div className="hidden md:flex flex-col items-end text-right pb-1">
            <h1 className="text-3xl lg:text-5xl font-black tracking-tighter text-white leading-none mb-2">大豐資訊盤點系統</h1>
            <div className="bg-blue-600/20 text-blue-500 font-bold px-4 py-1 rounded-full text-lg tracking-[0.4em] uppercase border border-blue-500/30">雲端備份就緒</div>
        </div>
        {/* 手機版標題簡化 */}
        <div className="md:hidden w-full flex justify-between items-center mt-2 px-1">
            <h1 className="text-xl font-black tracking-tight text-white">大豐資訊盤點系統</h1>
            <div className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_10px_#3b82f6]"></div>
        </div>
      </header>

      {/* 掃描列：手機版高度自動，內容垂直置中 */}
      <div className="flex flex-col md:flex-row gap-4 md:gap-8 mb-4 md:mb-8 shrink-0">
        <section className={`flex-1 flex p-2 md:p-3 rounded-3xl md:rounded-[3rem] transition-all duration-300 border-2 md:border-4 items-center ${isSuccess ? 'bg-emerald-500/20 border-emerald-500 shadow-[0_0_30px_rgba(16,185,129,0.2)]' : isPaused ? 'bg-slate-950 border-slate-900' : 'bg-slate-900 border-slate-800 focus-within:border-blue-500'}`}>
          <div 
            className="flex items-center bg-slate-950 rounded-2xl md:rounded-[2.5rem] px-4 md:px-8 gap-2 md:gap-4 ml-1 md:ml-2 border border-slate-800 shadow-inner cursor-text py-2 md:py-0"
            onClick={(e) => {
              e.stopPropagation(); 
              qtyRef.current?.focus();
            }}
          >
            <Hash className="text-blue-500 w-6 h-6 md:w-8 md:h-8" />
            <input 
              ref={qtyRef}
              type="number" 
              value={scanQty} 
              onChange={(e) => setScanQty(e.target.value)}
              onFocus={(e) => e.target.select()} 
              onKeyDown={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  inputRef.current?.focus(); 
                }
              }}
              onClick={(e) => e.stopPropagation()}
              className="bg-transparent text-3xl md:text-5xl font-black text-blue-400 w-16 md:w-24 outline-none text-center"
              placeholder="1"
            />
            <span className="text-slate-700 text-xl md:text-3xl font-black">X</span>
          </div>
          <form onSubmit={handleScan} className="flex-1 relative ml-2">
            <Search className="absolute left-2 md:left-4 top-1/2 -translate-y-1/2 text-blue-500 w-6 h-6 md:w-12 md:h-12" />
            <input 
              ref={inputRef}
              type="text" 
              value={inputValue} 
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={isPaused ? "暫停..." : data.length > 0 ? "掃描..." : "請先匯入"}
              disabled={data.length === 0 || isPaused}
              className="w-full bg-transparent pl-10 md:pl-20 pr-4 py-4 md:py-10 text-3xl md:text-7xl font-black text-white outline-none placeholder:text-slate-800 h-16 md:h-auto"
              autoComplete="off"
            />
          </form>
        </section>

        {locationEnabled && (
          <section className="w-full md:w-1/4 p-2 md:p-3 bg-amber-900/10 border-2 md:border-4 border-amber-800/50 rounded-3xl md:rounded-[3rem] flex flex-row md:flex-col items-center md:justify-center px-6 md:px-12 gap-4 md:gap-0">
            <div className="flex items-center gap-2 md:gap-4 md:mb-2 text-amber-500 font-black text-lg md:text-2xl uppercase tracking-widest shrink-0"><MapPin size={24} className="md:w-[36px] md:h-[36px]" /> <span className="hidden md:inline">目前</span>儲位</div>
            <input 
              ref={locationRef}
              type="text" 
              value={currentLocation} 
              onChange={(e) => setCurrentLocation(e.target.value)} 
              onClick={(e) => e.stopPropagation()}
              placeholder="位置..." 
              disabled={isPaused} 
              className="w-full bg-transparent text-4xl md:text-6xl font-black text-amber-400 outline-none" 
              autoComplete="off" 
            />
          </section>
        )}
      </div>

      {/* 中央主工作區：手機版垂直堆疊 (Grid 1 col)，電腦版左右分割 (Grid 12 cols) */}
      <main className="flex-1 grid grid-cols-1 lg:grid-cols-12 gap-4 md:gap-8 min-h-0 mb-4 md:mb-8 shrink-0">
        {/* 上方/左方：產品資訊 */}
        <div className="col-span-1 lg:col-span-8 bg-slate-900/40 border-2 md:border-4 border-slate-800/50 rounded-3xl md:rounded-[4rem] flex flex-col overflow-hidden relative shadow-2xl min-h-[300px] md:min-h-0">
          {lastScanned ? (
            <div className="h-full flex flex-col">
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-6 md:px-16 bg-slate-800/10 py-6 md:py-0">
                <div className="flex items-center gap-2 md:gap-4 mb-2 text-slate-500 font-black text-lg md:text-xl uppercase tracking-widest"><Package size={20} className="md:w-[28px] md:h-[28px]" /> 品名名稱</div>
                <h2 className="text-3xl md:text-5xl font-black text-white truncate drop-shadow-xl leading-tight whitespace-normal md:whitespace-nowrap">{lastScanned.name}</h2>
              </div>
              <div className="flex-1 border-b-2 border-slate-800/50 flex flex-col justify-center px-6 md:px-16 py-6 md:py-0">
                <div className="flex items-center gap-2 md:gap-4 mb-2 text-slate-500 font-black text-lg md:text-xl uppercase tracking-widest"><Info size={20} className="md:w-[28px] md:h-[28px]" /> 產品型號</div>
                <p className="text-5xl md:text-7xl font-black text-blue-400 font-mono tracking-tighter leading-none break-all">{lastScanned.productCode}</p>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center opacity-10 py-10 md:py-0">
              <ScanBarcode size={100} className="md:w-[180px] md:h-[180px]" />
              <p className="text-2xl md:text-5xl font-black mt-4 md:mt-8 tracking-[0.5em] uppercase text-center">掃描就緒</p>
            </div>
          )}
        </div>

        {/* 下方/右方：數量統計 */}
        <div className="col-span-1 lg:col-span-4 flex flex-row lg:flex-col gap-4 md:gap-8 h-40 lg:h-auto">
          <div className="flex-1 bg-blue-600 rounded-3xl md:rounded-[4rem] flex flex-col items-center justify-center shadow-2xl relative p-4">
            <span className="text-blue-100 font-black text-lg md:text-3xl mb-1 md:mb-4 uppercase tracking-[0.2em] md:tracking-[0.4em]">累計數量</span>
            <div className="text-6xl md:text-9xl font-black drop-shadow-2xl text-white leading-none">{lastScanned?.actualQty ?? '0'}</div>
            {lastScanned && (
              <button onClick={manualSetTotalQty} className="absolute bottom-2 right-2 md:bottom-10 md:right-10 bg-white/20 hover:bg-white text-white hover:text-blue-600 px-3 py-2 md:px-6 md:py-4 rounded-xl md:rounded-3xl transition-all flex items-center gap-1 md:gap-3 text-sm md:text-3xl font-black backdrop-blur-md shadow-2xl border-2 border-white/20"><Edit3 size={16} className="md:w-[32px] md:h-[32px]" /> 修正</button>
            )}
          </div>
          <div className={`flex-1 rounded-3xl md:rounded-[4rem] flex flex-col items-center justify-center shadow-2xl transition-all duration-500 p-4 ${!lastScanned ? 'bg-slate-800 text-slate-700' : lastScanned.diff === 0 ? 'bg-emerald-600' : 'bg-red-600'}`}>
            <span className="font-black text-lg md:text-3xl mb-1 md:mb-4 uppercase tracking-[0.2em] md:tracking-[0.4em] opacity-80 text-white">庫存差異</span>
            <div className="text-6xl md:text-9xl font-black text-white leading-none">{lastScanned ? (lastScanned.diff > 0 ? `+${lastScanned.diff}` : lastScanned.diff) : '0'}</div>
          </div>
        </div>
      </main>

      {/* 底部數據：手機版改為 Grid 2欄，電腦版 3欄 */}
      <footer className="grid grid-cols-2 lg:grid-cols-3 gap-2 md:gap-8 shrink-0 h-auto md:h-44 mb-20 md:mb-4">
        <div className="col-span-1 bg-slate-900 border-2 md:border-4 border-slate-800 rounded-3xl md:rounded-[3rem] flex items-center px-4 md:px-12 gap-4 md:gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)] py-4 md:py-0">
          <Package className="text-slate-500 w-10 h-10 md:w-20 md:h-20" />
          <div>
            <p className="text-sm md:text-2xl font-black text-slate-500 uppercase mb-1 md:mb-3 tracking-widest">總項數</p>
            <p className="text-4xl md:text-8xl font-black text-white leading-none">{data.length}</p>
          </div>
        </div>
        <div className="col-span-1 bg-slate-900 border-2 md:border-4 border-slate-800 rounded-3xl md:rounded-[3rem] flex items-center px-4 md:px-12 gap-4 md:gap-12 shadow-[0_0_60px_rgba(0,0,0,0.5)] py-4 md:py-0">
          <ClipboardCheck className="text-emerald-500 w-10 h-10 md:w-20 md:h-20" />
          <div>
            <p className="text-sm md:text-2xl font-black text-emerald-600 uppercase mb-1 md:mb-3 tracking-widest">已完成</p>
            <p className="text-4xl md:text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty > 0).length}</p>
          </div>
        </div>
        <button onClick={() => setShowUnscannedList(true)} className="col-span-2 lg:col-span-1 bg-slate-900 border-2 md:border-4 border-slate-800 hover:border-amber-500 rounded-3xl md:rounded-[3rem] flex items-center justify-center lg:justify-start px-4 md:px-12 gap-4 md:gap-12 transition-all group shadow-[0_0_60px_rgba(0,0,0,0.5)] py-4 md:py-0">
          <AlertCircle className="text-amber-500 group-hover:scale-110 transition-transform w-10 h-10 md:w-20 md:h-20" />
          <div className="text-left">
            <p className="text-sm md:text-2xl font-black text-amber-600 uppercase mb-1 md:mb-3 tracking-widest">未盤項 (檢視)</p>
            <p className="text-4xl md:text-8xl font-black text-white leading-none">{data.filter(i => i.actualQty === 0 && i.bookQty > 0).length}</p>
          </div>
        </button>
      </footer>

      {/* 彈窗內容：針對手機版做寬度與 Padding 調整 */}
      {showMappingModal && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4 md:p-10">
          <div className="bg-white text-slate-950 w-full max-w-7xl rounded-3xl md:rounded-[5rem] overflow-hidden flex flex-col shadow-2xl border-4 md:border-[12px] border-slate-800 max-h-[95vh]">
            <div className="p-6 md:p-12 bg-red-600 text-white flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div><h3 className="text-2xl md:text-6xl font-black mb-1 md:mb-3 italic break-all">! 未知: {unknownBarcode}</h3><p className="text-lg md:text-3xl font-bold opacity-80">請手動選擇或建立新項。</p></div>
              <div className="flex gap-2 md:gap-8 w-full md:w-auto">
                <button onClick={() => setIsCreatingNew(false)} className={`flex-1 md:flex-none px-4 md:px-12 py-3 md:py-6 rounded-xl md:rounded-3xl font-black text-lg md:text-3xl transition-all ${!isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-105 md:scale-110' : 'bg-red-700 text-red-200'}`}>搜尋</button>
                <button onClick={() => setIsCreatingNew(true)} className={`flex-1 md:flex-none px-4 md:px-12 py-3 md:py-6 rounded-xl md:rounded-3xl font-black text-lg md:text-3xl transition-all ${isCreatingNew ? 'bg-white text-red-600 shadow-2xl scale-105 md:scale-110' : 'bg-red-700 text-red-200'}`}>新建</button>
              </div>
            </div>
            <div className="flex-1 overflow-hidden flex min-h-[400px] md:min-h-[600px]">
              {isCreatingNew ? (
                <div className="flex-1 p-6 md:p-24 bg-slate-50 flex flex-col justify-center overflow-y-auto">
                  <div className="max-w-3xl mx-auto w-full space-y-4 md:space-y-10">
                    <div className="grid grid-cols-2 gap-4 md:gap-8">
                      <div className="bg-slate-200 p-4 md:p-8 rounded-2xl md:rounded-3xl shadow-inner border-2 border-slate-300"><label className="block text-sm md:text-xl font-black text-slate-500 mb-1 md:mb-2 uppercase">未知條碼</label><p className="text-xl md:text-4xl font-black break-all">{unknownBarcode}</p></div>
                      <div className="bg-blue-100 p-4 md:p-8 rounded-2xl md:rounded-3xl shadow-inner border-2 border-blue-200"><label className="block text-sm md:text-xl font-black text-blue-600 mb-1 md:mb-2 uppercase">掃描數量</label><p className="text-xl md:text-4xl font-black text-blue-700">{scanQty}</p></div>
                    </div>
                    <div><label className="block text-lg md:text-2xl font-black mb-1 md:mb-3 text-slate-700 uppercase">產品型號 (必填)</label><input autoFocus type="text" value={newProductCode} onChange={(e) => setNewProductCode(e.target.value)} placeholder="輸入型號..." className="w-full px-6 md:px-12 py-4 md:py-8 text-2xl md:text-5xl font-black bg-white border-4 md:border-8 border-slate-200 rounded-2xl md:rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <div><label className="block text-lg md:text-2xl font-black mb-1 md:mb-3 text-slate-700 uppercase">品名 (必填)</label><input type="text" value={newProductName} onChange={(e) => setNewProductName(e.target.value)} placeholder="輸入品名..." className="w-full px-6 md:px-12 py-4 md:py-8 text-2xl md:text-5xl font-black bg-white border-4 md:border-8 border-slate-200 rounded-2xl md:rounded-[2.5rem] outline-none focus:border-blue-600 shadow-2xl transition-all" /></div>
                    <button onClick={handleCreateNewItem} className="w-full py-6 md:py-10 bg-blue-600 text-white rounded-2xl md:rounded-[2.5rem] text-3xl md:text-5xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all flex items-center justify-center gap-4 md:gap-6"><PlusCircle size={32} className="md:w-[64px] md:h-[64px]" /> 儲存</button>
                </div></div>
              ) : (
                <div className="flex-1 flex flex-col">
                  <div className="p-4 md:p-12 border-b-4 md:border-b-8 border-slate-100 bg-slate-50"><input autoFocus type="text" value={mappingSearch} onChange={(e) => setMappingSearch(e.target.value)} placeholder="搜尋型號或品名..." className="w-full px-6 md:px-16 py-4 md:py-10 text-2xl md:text-5xl font-black bg-white rounded-2xl md:rounded-[3rem] border-4 md:border-8 border-transparent focus:border-blue-600 outline-none shadow-2xl" /></div>
                  <div className="flex-1 overflow-y-auto p-4 md:p-10 bg-white custom-scrollbar">
                    {data.filter(i => i.productCode.toLowerCase().includes(mappingSearch.toLowerCase()) || i.name.includes(mappingSearch)).slice(0, 15).map((item, idx) => (
                      <button key={idx} onClick={() => {
                        const dIdx = data.findIndex(d => d.productCode === item.productCode);
                        const updated = [...data];
                        updated[dIdx].mappedBarcodes = [...(updated[dIdx].mappedBarcodes || []), unknownBarcode];
                        updated[dIdx].actualQty += parseFloat(scanQty) || 1;
                        updated[dIdx].diff = updated[dIdx].actualQty - updated[dIdx].bookQty;
                        if (locationEnabled && currentLocation.trim()) updated[dIdx].location = currentLocation.trim();
                        if (operatorName.trim()) updated[dIdx].operator = operatorName.trim();
                        const t = getFormattedTime(); if (t) updated[dIdx].scanTime = t;
                        setData(updated); setLastScanned(updated[dIdx]); setShowMappingModal(false); audioService.speakMappingSuccess();
                      }} className="w-full text-left p-6 md:p-10 hover:bg-blue-600 hover:text-white rounded-2xl md:rounded-[3rem] border-b-2 md:border-b-4 border-slate-100 flex justify-between items-center transition-all mb-4 md:mb-6 group shadow-md hover:shadow-2xl">
                        <div className="overflow-hidden"><div className="text-xl md:text-4xl font-black mb-1 md:mb-2 truncate">{item.productCode}</div><div className="text-lg md:text-2xl font-bold opacity-60 group-hover:opacity-100 truncate">{item.name}</div></div>
                        <Link size={32} className="md:w-[64px] md:h-[64px] text-blue-600 group-hover:text-white shrink-0" />
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
            <div className="p-4 md:p-12 text-center border-t-4 md:border-t-8 border-slate-100 bg-slate-100"><button onClick={() => setShowMappingModal(false)} className="w-full md:w-auto px-12 md:px-24 py-4 md:py-6 rounded-full bg-slate-400 text-white font-black text-xl md:text-3xl hover:bg-slate-500 transition-colors shadow-2xl">放棄</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { 
  FileDown, CheckCircle2, Search,
  ScanBarcode, FileSpreadsheet, X,
  Link, Info, Package, ClipboardCheck, AlertCircle, PlusCircle, MapPin, Clock, User,
  Pause, Play, LogOut, Edit3, Hash, CloudSync, CloudCheck, CloudOff, Menu,
  Camera, CameraOff, RefreshCw, AlertTriangle
} from 'lucide-react';
import * as XLSX from 'xlsx';
import { Html5Qrcode, Html5QrcodeSupportedFormats } from 'html5-qrcode';
import { InventoryItem } from './types';
import { audioService } from './services/audioService';

const STORAGE_KEY = 'dafeng_inventory_local_v11';

type TimeFormat = 'off' | 'datetime' | 'date';
type SyncStatus = 'idle' | 'syncing' | 'success' | 'error';

const App: React.FC = () => {
  const [data, setData] = useState<InventoryItem[]>([]);
  const [lastScanned, setLastScanned] = useState<InventoryItem | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [scanQty, setScanQty] = useState('1');
  const [isSuccess, setIsSuccess] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const [showUnscannedList, setShowUnscannedList] = useState(false);
  const [showMappingModal, setShowMappingModal] = useState(false);
  const [unknownBarcode, setUnknownBarcode] = useState('');
  const [mappingSearch, setMappingSearch] = useState('');

  const [newProductName, setNewProductName] = useState('');
  const [newProductCode, setNewProductCode] = useState('');
  const [isCreatingNew, setIsCreatingNew] = useState(false);

  const [operatorName, setOperatorName] = useState('');
  const [locationEnabled, setLocationEnabled] = useState(false);
  const [currentLocation, setCurrentLocation] = useState('');
  const [timeFormat, setTimeFormat] = useState<TimeFormat>('date');

  // Camera Scanner State
  const [showScanner, setShowScanner] = useState(false);
  const [cameraError, setCameraError] = useState('');
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const scannerRegionId = "html5qr-code-full-region";

  const inputRef = useRef<HTMLInputElement>(null);
  const qtyRef = useRef<HTMLInputElement>(null);
  const locationRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.items?.length > 0) setData(parsed.items);
        if (parsed.config) {
          setLocationEnabled(!!parsed.config.locationEnabled);
          setCurrentLocation(parsed.config.currentLocation || '');
          setTimeFormat(parsed.config.timeFormat === 'off' ? 'date' : (parsed.config.timeFormat || 'date'));
          setOperatorName(parsed.config.operatorName || '');
          setIsPaused(!!parsed.config.isPaused);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    if (data.length > 0 || operatorName || locationEnabled || timeFormat !== 'off' || isPaused) {
      const config = { locationEnabled, currentLocation, timeFormat, operatorName, isPaused };
      localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: data, config }));
    }
  }, [data, locationEnabled, currentLocation, timeFormat, operatorName, isPaused]);

  // Focus Logic
  const focusInput = useCallback(() => {
    if (document.activeElement === qtyRef.current || document.activeElement === locationRef.current) return;
    if (inputRef.current && !showUnscannedList && !showMappingModal && !isPaused && !showScanner) {
      inputRef.current.focus();
    }
  }, [showUnscannedList, showMappingModal, isPaused, showScanner]);

  useEffect(() => {
    focusInput();
    const h = () => focusInput();
    window.addEventListener('click', h);
    return () => window.removeEventListener('click', h);
  }, [focusInput]);

  // Cloud Backup
  const backupToCloud = async (itemsToSync: InventoryItem[]) => {
    if (itemsToSync.length === 0) return;
    setSyncStatus('syncing');
    try {
      const response = await fetch('/api/backup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          operator: operatorName,
          items: itemsToSync.filter(i => i.actualQty > 0)
        })
      });
      if (response.ok) {
        setSyncStatus('success');
      } else {
        setSyncStatus('error');
      }
    } catch (e) {
      console.error("Backup failed", e);
      setSyncStatus('error');
    }
  };

  const getFormattedTime = () => {
    if (timeFormat === 'off') return undefined;
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    if (timeFormat === 'date') return `${y}/${m}/${d}`;
    const hh = String(now.getHours()).padStart(2, '0');
    const mm = String(now.getMinutes()).padStart(2, '0');
    return `${y}/${m}/${d} ${hh}:${mm}`;
  };

  // --- 核心邏輯重構：處理條碼 (共用於 USB 槍與鏡頭) ---
  const processBarcode = (code: string, qtyOverride?: number) => {
    if (isPaused) return;

    let targetCode = code.trim();
    let currentAddQty = qtyOverride !== undefined ? qtyOverride : (parseFloat(scanQty) || 1);

    // 處理 "數量*條碼" 格式
    if (targetCode.includes('*')) {
      const parts = targetCode.split('*');
      if (parts.length === 2) {
        const manualQty = parseFloat(parts[0]);
        if (!isNaN(manualQty)) {
          currentAddQty = manualQty;
          targetCode = parts[1].trim();
        }
      }
    }

    if (!targetCode || data.length === 0) return;

    const index = data.findIndex(item => 
      item.barcode === targetCode || item.productCode === targetCode || item.mappedBarcodes?.includes(targetCode)
    );

    if (index !== -1) {
      // 成功掃描
      const updatedData = [...data];
      updatedData[index].actualQty += currentAddQty;
      updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;

      if (locationEnabled && currentLocation.trim()) updatedData[index].location = currentLocation.trim();
      const t = getFormattedTime();
      if (t) updatedData[index].scanTime = t;
      if (operatorName.trim()) updatedData[index].operator = operatorName.trim();

      setData(updatedData);
      setLastScanned(updatedData[index]);
      setIsSuccess(true);
      audioService.speakSuccess('', 0);
      setTimeout(() => setIsSuccess(false), 300);

      // 如果是用相機掃的，掃完自動關閉
      if (showScanner) {
          stopScanner();
      }
    } else {
      // 未知條碼
      setUnknownBarcode(targetCode);
      setNewProductName('');
      setNewProductCode('');
      setIsCreatingNew(false);
      setShowMappingModal(true);
      audioService.speakError();
      if (showScanner) {
        stopScanner();
      }
    }
  };

  // 表單提交 (USB 槍)
  const handleScan = (e: React.FormEvent) => {
    e.preventDefault();
    processBarcode(inputValue);
    setInputValue('');
  };

  // --- 相機掃描邏輯 ---
  const startScanner = () => {
    setShowScanner(true);
    setCameraError('');

    // 稍微延遲以確保 DOM 已渲染
    setTimeout(() => {
        const html5QrCode = new Html5Qrcode(scannerRegionId);
        scannerRef.current = html5QrCode;

        const config = { fps: 10, qrbox: { width: 250, height: 250 } };

        // 優先使用後置鏡頭 environment
        html5QrCode.start(
            { facingMode: "environment" }, 
            config, 
            (decodedText) => {
                // Scan Success
                processBarcode(decodedText);
            },
            (errorMessage) => {
                // parse error, ignore
            }
        ).catch(err => {
            console.error("Camera Error", err);
            let msg = "無法啟動相機。";
            if (window.location.protocol === 'http:' && window.location.hostname !== 'localhost') {
                msg = "安全限制：瀏覽器禁止在 HTTP 網頁使用相機。請參閱說明開啟權限。";
            } else if (err?.name === 'NotAllowedError') {
                msg = "請允許瀏覽器存取相機權限。";
            }
            setCameraError(msg);
        });
    }, 100);
  };

  const stopScanner = () => {
      if (scannerRef.current) {
          scannerRef.current.stop().then(() => {
              scannerRef.current?.clear();
              setShowScanner(false);
          }).catch(err => console.error("Failed to stop scanner", err));
      } else {
          setShowScanner(false);
      }
  };

  const manualSetTotalQty = () => {
    if (!lastScanned) return;
    const newTotal = window.prompt(`[手動調整] 請輸入 "${lastScanned.name}" 的總盤點數量：`, lastScanned.actualQty.toString());
    if (newTotal !== null) {
      const parsed = parseFloat(newTotal);
      if (!isNaN(parsed)) {
        const index = data.findIndex(i => i.productCode === lastScanned.productCode);
        const updatedData = [...data];
        updatedData[index].actualQty = parsed;
        updatedData[index].diff = updatedData[index].actualQty - updatedData[index].bookQty;
        setData(updatedData);
        setLastScanned(updatedData[index]);
        audioService.speakMappingSuccess();
      }
    }
  };

  const handleCreateNewItem = () => {
    if (!newProductName.trim() || !newProductCode.trim()) {
      alert("品名與產品代號均為必填項目");
      return;
    }
    const newItem: InventoryItem = {
      barcode: unknownBarcode,
      productCode: newProductCode.trim(),
      name: newProductName.trim(),
      bookQty: 0,
      actualQty: parseFloat(scanQty) || 1,
      diff: parseFloat(scanQty) || 1,
      location: (locationEnabled && currentLocation.trim()) ? currentLocation.trim() : undefined,
      scanTime: getFormattedTime(),
      operator: operatorName.trim() || undefined,
      originalRow: { '條碼編號': unknownBarcode, '產品代號': newProductCode.trim(), '品名': newProductName.trim(), '期末數量': 0 }
    };
    setData([newItem, ...data]);
    setLastScanned(newItem);
    setShowMappingModal(false);
    audioService.speakMappingSuccess();
